// 1. Sweet Hero 3D Parallax & Radial Glow Mouse-Tracking















function initPacksHeroEffects() {















  const heroSection = document.getElementById('pack-hero-section');















  const logoWrapper = document.querySelector('.pack-logo-wrapper');















  const logoImg = document.querySelector('.pack-logo-img');















  const glowBehind = document.querySelector('.pack-logo-glow-behind');















  















  if (!heroSection || !logoWrapper || !logoImg) return;















  















  let targetMouseX = 0;















  let targetMouseY = 0;















  let curMouseX = 0;















  let curMouseY = 0;















  const LERP_FACTOR = 0.08;















  















  heroSection.addEventListener('mousemove', (e) => {















    const rect = heroSection.getBoundingClientRect();















    targetMouseX = ((e.clientX - rect.left) / rect.width) * 2 - 1; // -1 to 1















    targetMouseY = ((e.clientY - rect.top) / rect.height) * 2 - 1; // -1 to 1















  });















  















  heroSection.addEventListener('mouseleave', () => {















    targetMouseX = 0;















    targetMouseY = 0;















  });















  















  function animateHeroParallax() {















    curMouseX += (targetMouseX - curMouseX) * LERP_FACTOR;















    curMouseY += (targetMouseY - curMouseY) * LERP_FACTOR;















    















    const tiltX = -curMouseY * 22; // Aggressive tilt up to 22 degrees















    const tiltY = curMouseX * 22;















    















    logoImg.style.transform = `rotateX(${tiltX}deg) rotateY(${tiltY}deg) translateZ(40px)`;















    if (glowBehind) {















      glowBehind.style.transform = `translate(${curMouseX * 40}px, ${curMouseY * 30}px)`;















    }















    















    requestAnimationFrame(animateHeroParallax);















  }















  requestAnimationFrame(animateHeroParallax);















}































// 2. Cinematic Hero Scroll-Lock & Staggered Cards Reveal Animation















function initPacksHeroScroll() {















  const heroSection = document.getElementById('pack-hero-section');















  if (!heroSection) return;















  















  const statsContainer = document.getElementById('pack-hero-stats');















  const cards = statsContainer ? statsContainer.querySelectorAll('.pack-stat-card') : [];















  















  let isHeroLocked = true;















  let cardsRevealed = false;















  let isHeroAnimating = false;















  















  // Align page scroll to top on enter/reload















  if (window.scrollY < 20) {















    window.scrollTo(0, 0);















  }















  















  function handleHeroInput(e, direction) {















    if (!isHeroLocked) return;















    















    if (isHeroAnimating) {















      if (e.cancelable) e.preventDefault();















      return;















    }















    















    if (direction === 1) { // Scroll Down -> Reveal cards first, then scroll down















      if (!cardsRevealed) {















        if (e.cancelable) e.preventDefault();















        isHeroAnimating = true;















        















        cards.forEach((card, idx) => {















          setTimeout(() => {















            card.classList.add('stat-visible');















          }, idx * 250);















        });















        















        setTimeout(() => {















          cardsRevealed = true;















          isHeroAnimating = false;















        }, (cards.length - 1) * 250 + 800);















      } else {















        // Unlock and scroll down seamlessly to next section















        if (e.cancelable) e.preventDefault();















        isHeroLocked = false;















        















        const nextSection = heroSection.nextElementSibling;















        if (nextSection) {















          window.whiteboxSmoothScrolling = true;















          const targetY = window.scrollY + nextSection.getBoundingClientRect().top;















          slowScrollTo(targetY, 1000, () => {















            window.whiteboxSmoothScrolling = false;















          });















        }















      }















    } else if (direction === -1) { // Scroll Up -> Hide cards cleanly















      if (cardsRevealed && window.scrollY < 10) {















        if (e.cancelable) e.preventDefault();















        isHeroAnimating = true;















        















        Array.from(cards).reverse().forEach((card, idx) => {















          setTimeout(() => {















            card.classList.remove('stat-visible');















          }, idx * 150);















        });















        















        setTimeout(() => {















          cardsRevealed = false;















          isHeroAnimating = false;















        }, (cards.length - 1) * 150 + 800);















      }















    }















  }















  















  // Intercept standard wheel events















  window.addEventListener('wheel', (e) => {















    if (!isHeroLocked) return;















    const direction = e.deltaY > 0 ? 1 : -1;















    handleHeroInput(e, direction);















  }, { passive: false });















  















  // Intercept touch / mobile swipes















  let touchStartY = 0;















  window.addEventListener('touchstart', (e) => {















    if (!isHeroLocked) return;















    touchStartY = e.touches[0].clientY;















  }, { passive: true });















  















  window.addEventListener('touchmove', (e) => {















    if (!isHeroLocked) return;















    const touchY = e.touches[0].clientY;















    const diffY = touchStartY - touchY;















    















    if (Math.abs(diffY) > 30) {















      const direction = diffY > 0 ? 1 : -1;















      touchStartY = touchY;















      handleHeroInput(e, direction);















    } else {















      if (e.cancelable) e.preventDefault();















    }















  }, { passive: false });















  















  // Intercept key page shifts















  window.addEventListener('keydown', (e) => {















    if (!isHeroLocked) return;















    let direction = 0;















    if (e.key === 'ArrowDown' || e.key === 'PageDown' || (e.key === ' ' && !e.shiftKey)) {















      direction = 1;















    } else if (e.key === 'ArrowUp' || e.key === 'PageUp' || (e.key === ' ' && e.shiftKey)) {















      direction = -1;















    }















    















    if (direction !== 0) {















      handleHeroInput(e, direction);















    }















  }, { passive: false });















  















  // Relock when user scrolls back to absolute top















  window.addEventListener('scroll', () => {















    if (window.whiteboxSmoothScrolling) return;















    const scrollY = window.scrollY;















    















    if (scrollY < 15 && !isHeroLocked) {















      isHeroLocked = true;















      cardsRevealed = true;















    }















  }, { passive: true });















  















  // Prevent any default scroll shift when locked















  window.addEventListener('scroll', () => {















    if (isHeroLocked && !window.whiteboxSmoothScrolling && window.scrollY > 2) {















      window.scrollTo(0, 0);















    }















  }, { passive: true });















}































// 3. Section 2 methodology click triggers and drawers















function initPacksRRRInteractivity() {















  const panels = document.querySelectorAll('.rrr-card-panel');















  const drawers = document.querySelectorAll('.rrr-expandable-drawer');















  















  if (!panels.length) return;















  















  panels.forEach(panel => {















    panel.addEventListener('click', () => {















      const target = panel.getAttribute('data-target');















      const targetDrawer = document.getElementById(`drawer-${target}`);















      const isAlreadyActive = panel.classList.contains('panel-active');















      















      // Close all drawers smoothly















      drawers.forEach(drawer => {















        drawer.classList.remove('drawer-active');















        drawer.style.maxHeight = '';















      });















      















      // Remove active states from all cards















      panels.forEach(p => p.classList.remove('panel-active'));















      















      // If we clicked a new panel, expand its drawer















      if (!isAlreadyActive && targetDrawer) {















        panel.classList.add('panel-active');















        targetDrawer.classList.add('drawer-active');















        















        // Dynamically compute exact drawer height for sleek transition















        const inner = targetDrawer.querySelector('.rrr-drawer-content');















        if (inner) {















          const height = inner.scrollHeight + 32;















          targetDrawer.style.maxHeight = `${height}px`;















        }















      }















    });















  });















}































// 4. 3D Hover Tilt Physics for Glass Scorecards















function initPacksScorecardsParallax() {















  const cards = document.querySelectorAll('.glass-scorecard');















  if (!cards.length) return;















  















  cards.forEach(card => {















    card.addEventListener('mousemove', (e) => {















      const rect = card.getBoundingClientRect();















      const x = (e.clientX - rect.left) / rect.width - 0.5; // -0.5 to 0.5















      const y = (e.clientY - rect.top) / rect.height - 0.5; // -0.5 to 0.5















      















      const tiltY = x * 12; // Tilts up to 12 degrees















      const tiltX = -y * 12;















      















      card.style.transform = `translateY(-12px) scale(1.03) perspective(1000px) rotateX(${tiltX}deg) rotateY(${tiltY}deg)`;















    });















    















    card.style.transition = 'transform 0.1s ease-out, box-shadow 0.4s ease, border-color 0.4s ease';















    















    card.addEventListener('mouseleave', () => {















      card.style.transition = 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1), box-shadow 0.4s ease, border-color 0.4s ease';















      card.style.transform = '';















    });















  });















}































