function enrichRelationshipData() {















  const enrichItem = (item, type) => {















    // Contact Mapping















    if (!item.contact) {















      if (type === 'employee') {















        item.contact = item.name;















      } else if (item.name === "Apex Global Retail") {















        item.contact = "Diana Prince";















      } else if (item.name === "Chevron Solutions" || item.name === "Chevron Logistics") {















        item.contact = "Sarah Jenkins";















      } else if (item.name === "Vanguard Logistics" || item.name === "Vanguard Health") {















        item.contact = "Bruce Wayne";















      } else if (item.name === "OmniCorp Tech") {















        item.contact = "Peter Parker";















      } else if (item.name === "Summit Financial") {















        item.contact = "Clark Kent";















      } else if (item.name === "Nova Healthcare" || item.name === "Nova Financial") {















        item.contact = "Tony Stark";















      } else if (item.name === "Horizon Logistics") {















        item.contact = "Arthur Dent";















      } else if (item.name === "Pinnacle Brands") {















        item.contact = "Selina Kyle";















      } else if (item.name === "Starlight Ventures") {















        item.contact = "Bruce Banner";















      } else if (item.name === "Delta Aerospace") {















        item.contact = "Carol Danvers";















      } else if (item.name === "Orion Biotech") {















        item.contact = "Hank Pym";















      } else if (item.name === "Beacon Logistics") {















        item.contact = "Wanda Maximoff";















      } else if (item.name === "Eclipse Retail") {















        item.contact = "Natasha Romanoff";















      } else if (item.name === "Vortex Digital") {















        item.contact = "Steve Rogers";















      } else if (item.name === "Zenith Energy") {















        item.contact = "Hal Jordan";















      } else if (item.name === "Summit Media") {















        item.contact = "Barry Allen";















      } else {















        item.contact = item.rep || "Robert Vance";















      }















    }































    // Address splitting: "120 Broadway, New York NY"















    if (!item.city || !item.province || !item.postal) {















      const parts = item.address.split(',');















      if (parts.length >= 2) {















        item.streetAddress = parts[0].trim();















        const cityState = parts[1].trim().split(' ');















        if (cityState.length >= 2) {















          item.city = cityState[0].trim();















          item.province = cityState[1].trim();















        } else {















          item.city = parts[1].trim();















          item.province = "TX";















        }















      } else {















        item.streetAddress = item.address;















        item.city = "Houston";















        item.province = "TX";















      }















      















      // Map postals based on name or default















      if (item.name.includes("Apex") || item.name.includes("Vortex") || item.name.includes("Dupond") || item.name.includes("Smith")) item.postal = "10005";















      else if (item.name.includes("Chevron")) item.postal = "77002";















      else if (item.name.includes("Vanguard") || item.name.includes("Collins")) item.postal = "60609";















      else if (item.name.includes("OmniCorp") || item.name.includes("Starlight")) item.postal = "94103";















      else if (item.name.includes("Summit Financial") || item.name.includes("Paul")) item.postal = "02111";















      else if (item.name.includes("Nova Healthcare") || item.name.includes("Anna")) item.postal = "98104";















      else if (item.name.includes("Horizon") || item.name.includes("Jack")) item.postal = "75207";















      else if (item.name.includes("Pinnacle") || item.name.includes("Eclipse")) item.postal = "90015";















      else if (item.name.includes("Emily")) item.postal = "30303";















      else if (item.name.includes("Sarah Lansky")) item.postal = "M5H 2Y4";















      else if (item.name.includes("Stripe")) item.postal = "M4W 1A1";















      else if (item.name.includes("Acme")) item.postal = "78701";















      else item.postal = "77002";















    } else {















      item.streetAddress = item.address;















    }































    // Prospect/Customer flags (Mapped to system integration & conversion dates)















    const datesMap = {















      "Apex Global Retail": { prospect: "2026-02-10", customer: "2026-04-14" },















      "Chevron Solutions": { prospect: "2026-01-18", customer: "2026-03-22" },















      "Chevron Logistics": { prospect: "2026-01-18", customer: "2026-03-22" },















      "Vanguard Logistics": { prospect: "2025-11-12", customer: "2026-01-15" },















      "Vanguard Health": { prospect: "2025-11-15", customer: "2026-01-08" },















      "OmniCorp Tech": { prospect: "2025-12-05", customer: "2026-02-18" },















      "Summit Financial": { prospect: "2026-01-10", customer: "2026-03-05" },















      "Nova Healthcare": { prospect: "2025-10-15", customer: "2026-01-20" },















      "Horizon Logistics": { prospect: "2026-02-14", customer: "2026-04-05" },















      "Pinnacle Brands": { prospect: "2025-08-20", customer: "2025-11-10" },















      "Stripe Canada": { prospect: "2026-03-12", customer: "2026-05-13" },















      "Acme Corporation": { prospect: "2026-03-22", customer: "N/A" },















      "Starlight Ventures": { prospect: "2026-05-12", customer: "N/A" },















      "Delta Aerospace": { prospect: "2026-05-02", customer: "N/A" },















      "Orion Biotech": { prospect: "2026-03-15", customer: "N/A" },















      "Beacon Logistics": { prospect: "2026-04-01", customer: "N/A" },















      "Eclipse Retail": { prospect: "2026-05-10", customer: "N/A" },















      "Vortex Digital": { prospect: "2026-04-18", customer: "N/A" },















      "Zenith Energy": { prospect: "2026-05-15", customer: "N/A" },















      "Summit Media": { prospect: "2026-03-20", customer: "N/A" }















    };















    















    const mapped = datesMap[item.name];















    if (mapped) {















      item.prospect = mapped.prospect;















      item.customer = mapped.customer;















    } else {
      if (type === 'prospect') {
        if (!item.prospect) item.prospect = "2026-05-01";
        if (!item.customer) item.customer = "N/A";
      } else if (type === 'customer') {
        if (!item.prospect) item.prospect = "2026-01-10";
        if (!item.customer) item.customer = "2026-05-01";
      } else {
        if (!item.prospect) item.prospect = "N/A";
        if (!item.customer) item.customer = "N/A";
      }















    }















  };































  employeesData.forEach(item => enrichItem(item, 'employee'));















  customersData.forEach(item => enrichItem(item, 'customer'));















  prospectsData.forEach(item => enrichItem(item, 'prospect'));















}































// RELATIONSHIP MANAGEMENT OPERATING SYSTEM (RMOS) DASHBOARD















// ============================================================































window.triggerB2BGiftingBuilder = function(targetName, milestoneName = '', dateStr = '') {















  // 1. Reset Send a Box Form first















  if (window.resetSendBoxForm) {















    window.resetSendBoxForm();















  }































  // 2. Pre-fill Recipient Name















  const recipientInput = document.getElementById('recipient_name');















  if (recipientInput) {















    recipientInput.value = targetName;















    recipientInput.dispatchEvent(new Event('input', { bubbles: true }));















  }































  // Pre-fill Sender Name to Gregory Sterling (CEO)















  const senderInput = document.getElementById('sender_name');
  if (senderInput) {
    const role = window.currentRole || localStorage.getItem('whitebox_role') || 'owner';
    const username = window.currentUsername || localStorage.getItem('whitebox_username') || 'Tom Collins';
    if (role === 'rep') {
      senderInput.value = username;
    } else {
      senderInput.value = "Gregory Sterling (CEO)";
    }
    senderInput.dispatchEvent(new Event('input', { bubbles: true }));










  }































  // 3. Pre-fill Dispatch Date















  const dateInput = document.getElementById('dispatch_date');















  if (dateInput) {















    if (dateStr) {















      try {















        const d = new Date(dateStr);















        if (!isNaN(d.getTime())) {















          dateInput.value = d.toISOString().split('T')[0];















          dateInput.dispatchEvent(new Event('change', { bubbles: true }));















        }















      } catch(err) {















        console.warn("Milestone date parsing failed:", err);















      }















    } else {















      // Default to today + 7 days















      const d = new Date();















      d.setDate(d.getDate() + 7);















      dateInput.value = d.toISOString().split('T')[0];















      dateInput.dispatchEvent(new Event('change', { bubbles: true }));















    }















  }































  // 4. Pre-fill Appreciation Reason & Category based on Milestone context















  const reasonSelect = document.getElementById('send_reason');















  let occasionVal = 'custom';















  let categoryVal = 'reach';















  















  if (milestoneName) {















    const lowerMilestone = milestoneName.toLowerCase();















    if (lowerMilestone.includes('birthday')) {















      occasionVal = 'birthday';















      categoryVal = 'remember';















    } else if (lowerMilestone.includes('anniversary')) {















      occasionVal = 'anniversary';















      categoryVal = 'retain';















    } else if (lowerMilestone.includes('renewal')) {















      occasionVal = 'contract_renewal';















      categoryVal = 'retain';















    } else if (lowerMilestone.includes('recognition')) {















      occasionVal = 'employee_recognition';















      categoryVal = 'reward';















    }















  }































  if (reasonSelect) {















    reasonSelect.value = occasionVal;















    reasonSelect.dispatchEvent(new Event('change', { bubbles: true }));















  }































  // Select category radio button programmatically















  const categoryRadio = document.querySelector(`input[name="gifting_category"][value="${categoryVal}"]`);















  if (categoryRadio) {















    document.querySelectorAll('input[name="gifting_category"]').forEach(r => {















      r.checked = false;















      const option = r.closest('.selector-option');















      if (option) option.classList.remove('active');















    });















    categoryRadio.checked = true;















    const option = categoryRadio.closest('.selector-option');















    if (option) option.classList.add('active');















  }































  // 5. Select recipient scale: if individual employee, set to executive (1 box)















  const isIndividual = ['Tom Collins', 'Sarah Lansky', 'Emily Davis', 'Marcus Dupond', 'Jane Smith', 'Gregory Sterling'].includes(targetName) || 















                       (typeof employeesData !== 'undefined' && employeesData.some(emp => emp.name === targetName));















  const scaleVal = isIndividual ? 'executive' : 'custom';















  const scaleRadio = document.querySelector(`input[name="recipient_scale"][value="${scaleVal}"]`);















  if (scaleRadio) {















    document.querySelectorAll('input[name="recipient_scale"]').forEach(r => {















      r.checked = false;















      const option = r.closest('.selector-option');















      if (option) option.classList.remove('active');















    });















    scaleRadio.checked = true;















    const option = scaleRadio.closest('.selector-option');















    if (option) option.classList.add('active');















  }































  // Make sure Recipient Count subform displays appropriately if scale is not executive















  const recipientCountSubform = document.getElementById('recipient-count-subform');















  if (recipientCountSubform) {















    recipientCountSubform.style.display = scaleVal !== 'executive' ? 'block' : 'none';















  }































  // Set default box type sweet and activate its visual selector















  const boxTypeSweet = document.querySelector('input[name="box_type"][value="sweet"]');















  if (boxTypeSweet) {















    document.querySelectorAll('input[name="box_type"]').forEach(r => {















      r.checked = false;















      const option = r.closest('.selector-option');















      if (option) option.classList.remove('active');















    });















    boxTypeSweet.checked = true;















    const option = boxTypeSweet.closest('.selector-option');















    if (option) option.classList.add('active');















  }































  // Hide dynamic pack/premium subforms on reset default to sweet box















  const packBoxSubform = document.getElementById('pack-box-subform');















  const premiumBoxSubform = document.getElementById('premium-box-subform');















  if (packBoxSubform) packBoxSubform.style.display = 'none';















  if (premiumBoxSubform) premiumBoxSubform.style.display = 'none';































  // 6. Open the Modal overlay directly















  const modalOverlay = document.getElementById('send-box-modal-overlay');















  const formWrapper = document.getElementById('send-box-form-wrapper');















  const successWrapper = document.getElementById('send-box-success-wrapper');















  















  if (modalOverlay) {















    formWrapper.style.display = 'block';















    successWrapper.style.display = 'none';















    modalOverlay.style.display = 'flex';















    















    if (window.calculateStartsAtPrice) {















      window.calculateStartsAtPrice();















    }















    















    const modalContent = modalOverlay.querySelector('.send-box-modal-content');















    if (modalContent) {















      modalContent.style.transform = 'scale(0.95)';















      modalContent.style.opacity = '0';















      setTimeout(() => {















        modalContent.style.transition = 'all 0.4s cubic-bezier(0.16, 1, 0.3, 1)';















        modalContent.style.transform = 'scale(1)';















        modalContent.style.opacity = '1';















      }, 30);















    }















  }















};































  // Global Event Delegation for Action Buttons















  document.addEventListener('click', (e) => {















    // Send Gift















    const sendGiftBtn = e.target.closest('.send-gift-btn');















    if (sendGiftBtn) {















      e.preventDefault();















      e.stopPropagation();















      const name = sendGiftBtn.getAttribute('data-name') || 'Client';















      















      sendGiftBtn.style.transform = 'scale(0.9)';















      setTimeout(() => { sendGiftBtn.style.transform = ''; }, 150);















      















      window.triggerB2BGiftingBuilder(name);















      return;















    }














    // Nudge Rep














    const nudgeRepBtn = e.target.closest('.nudge-rep-btn');














    if (nudgeRepBtn) {














      e.preventDefault();














      e.stopPropagation();














      const repName = nudgeRepBtn.getAttribute('data-rep') || 'Tom Collins';














      const clientName = nudgeRepBtn.getAttribute('data-client');














      nudgeRepBtn.style.transform = 'scale(0.95)';














      setTimeout(() => { nudgeRepBtn.style.transform = ''; }, 150);














      const nudgeMessage = clientName 














        ? `Nudge sent successfully! ${repName} alerted about ${clientName}.`














        : `Nudge sent successfully! ${repName} has been alerted.`;














      showDashboardToast(nudgeMessage, '📬');














      return;














    }















    















    // Contact















    const contactBtn = e.target.closest('.contact-btn');















    if (contactBtn) {















      e.preventDefault();















      e.stopPropagation();















      const name = contactBtn.getAttribute('data-name') || 'Client';















      showDashboardToast(`✓ Direct communication channel initiated with ${name}!`, '✓');















      















      // Programmatically click the corresponding node name link to open profile details view!















      const nodes = Array.from(document.querySelectorAll('.node-name'));















      const matchingNode = nodes.find(n => n.textContent.trim() === name || n.getAttribute('data-name') === name);















      if (matchingNode) {















        matchingNode.click();















      }















      return;















    }















    















    // Send to Board















    const sendToBoardBtn = e.target.closest('.send-to-board-btn');















    if (sendToBoardBtn) {















      e.preventDefault();















      e.stopPropagation();















      const client = sendToBoardBtn.getAttribute('data-client') || 'Client';















      















      if (window.sendRelationshipToRecoveryBoard) {
        window.sendRelationshipToRecoveryBoard(client);
      }
      showDashboardToast(`✓ ${client} transferred to Board successfully!`, '✓');
      if (typeof renderOverviewRegistry === 'function') renderOverviewRegistry();
      if (typeof renderCustomersList === 'function') renderCustomersList();
      if (typeof renderProspectsList === 'function') renderProspectsList();
    }
  });

function updateTabPillBadges() {
  const empBadge = document.getElementById('employees-total-count');
  const custBadge = document.getElementById('customers-total-count');
  const prospBadge = document.getElementById('prospects-total-count');

  const role = window.currentRole || localStorage.getItem('whitebox_role') || 'owner';
  const username = window.currentUsername || localStorage.getItem('whitebox_username') || 'Paul K.';

  let scopedCust = customersData || [];
  let scopedProsp = prospectsData || [];

  if (role === 'rep') {
    scopedCust = scopedCust.filter(c => c.rep === username);
    scopedProsp = scopedProsp.filter(p => p.rep === username);
  } else if (role === 'manager') {
    const team = getTeamRoster(username);
    scopedCust = scopedCust.filter(c => team.includes(c.rep));
    scopedProsp = scopedProsp.filter(p => team.includes(p.rep));
  }

  if (typeof renderEmployeesList === 'function') {
    renderEmployeesList();
  } else {
    const liveEmpCount = window.supabaseLeaderboardLive ? getLiveEmployeesList().length : employeesData.length;
    if (empBadge) empBadge.textContent = liveEmpCount;
  }

  if (custBadge) custBadge.textContent = scopedCust.length;
  if (prospBadge) prospBadge.textContent = scopedProsp.length;














}































