window.bindRepTimeFilterPills = function() {
  const pills = document.querySelectorAll('.rep-time-filter-pills .filter-pill');
  pills.forEach(pill => {
    if (pill.dataset.clickBound) return;
    pill.dataset.clickBound = 'true';
    pill.addEventListener('click', (e) => {
      e.stopPropagation();
      const dataRange = pill.getAttribute('data-range');
      window.currentAnalyticsRange = dataRange;
      
      const allRepPills = document.querySelectorAll('.rep-time-filter-pills .filter-pill');
      allRepPills.forEach(p => {
        if (p.getAttribute('data-range') === dataRange) {
          p.classList.add('active');
        } else {
          p.classList.remove('active');
        }
      });
      
      if (typeof window.renderRepACFChart === 'function') window.renderRepACFChart();
      if (typeof window.renderRepTPVolumeChart === 'function') window.renderRepTPVolumeChart();
      if (typeof window.renderRepConversionHUD === 'function') window.renderRepConversionHUD();
    });
  });
};

function generateRepExpandedACFTrendSVG(labels) {
  const width = 800;
  const height = 240;
  const paddingLeft = 55;
  const paddingRight = 20;
  const paddingTop = 25;
  const paddingBottom = 30;

  const activeLabels = labels || ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'];
  const graphWidth = width - paddingLeft - paddingRight;
  const graphHeight = height - paddingTop - paddingBottom;
  const range = window.currentAnalyticsRange || '30d';

  if (!window.activeRepACFSeries) {
    window.activeRepACFSeries = { prospects: true, customers: true };
  }

  const getPoints = (dataArr) => {
    return dataArr.map((val, idx) => {
      const x = paddingLeft + (idx / (dataArr.length - 1)) * graphWidth;
      const y = paddingTop + graphHeight * (1 - val / 100);
      return { x, y, val };
    });
  };

  const getPathD = (points) => {
    if (points.length === 0) return '';
    let pathD = `M ${points[0].x} ${points[0].y}`;
    for (let i = 0; i < points.length - 1; i++) {
      const p0 = points[i];
      const p1 = points[i + 1];
      const cp1x = p0.x + (p1.x - p0.x) / 3;
      const cp1y = p0.y;
      const cp2x = p0.x + 2 * (p1.x - p0.x) / 3;
      const cp2y = p1.y;
      pathD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;
    }
    return pathD;
  };

  const getFillD = (points) => {
    if (points.length === 0) return '';
    let fillD = `M ${points[0].x} ${height - paddingBottom} L ${points[0].x} ${points[0].y}`;
    for (let i = 0; i < points.length - 1; i++) {
      const p0 = points[i];
      const p1 = points[i + 1];
      const cp1x = p0.x + (p1.x - p0.x) / 3;
      const cp1y = p0.y;
      const cp2x = p0.x + 2 * (p1.x - p0.x) / 3;
      const cp2y = p1.y;
      fillD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;
    }
    fillD += ` L ${points[points.length - 1].x} ${height - paddingBottom} Z`;
    return fillD;
  };

  let curvesHtml = '';
  const series = [
    { key: 'prospects', color: '#3b82f6', grad: 'acf-prospects-fill-modal' },
    { key: 'customers', color: '#10b981', grad: 'acf-customers-fill-modal' }
  ];

  series.forEach(s => {
    if (window.activeRepACFSeries[s.key]) {
      const rawData = getRepACFData(s.key, range);
      const pts = getPoints(rawData);
      const path = getPathD(pts);
      const fill = getFillD(pts);
      curvesHtml += `
        <!-- ${s.key} curve -->
        <path d="${fill}" fill="url(#${s.grad})" />
        <path d="${path}" fill="none" stroke="${s.color}" stroke-width="3" stroke-linecap="round" filter="drop-shadow(0 2px 4px rgba(0,0,0,0.3))" />
        ${pts.map((p, idx) => `
          <circle cx="${p.x}" cy="${p.y}" r="4" fill="${s.color}" stroke="#0a0b18" stroke-width="1.5" />
          <text x="${p.x}" y="${p.y - 10}" fill="#fff" font-family="'Outfit', sans-serif" font-size="8" font-weight="900" text-anchor="middle" style="text-shadow: 0 1px 3px rgba(0,0,0,0.9);">${p.val}%</text>
        `).join('')}
      `;
    }
  });

  const labelsHtml = activeLabels.map((l, idx) => {
    const x = paddingLeft + (idx / (activeLabels.length - 1)) * graphWidth;
    return `<text x="${x}" y="${height - 12}" fill="#94a3b8" font-family="'Outfit', sans-serif" font-size="9" font-weight="700" text-anchor="middle">${l}</text>`;
  }).join('');

  return `
    <svg viewBox="0 0 ${width} ${height}" style="width: 100%; height: auto; background: rgba(10, 11, 24, 0.6); border: 1px solid rgba(255,255,255,0.05); border-radius: 16px; overflow: visible;">
      <defs>
        <linearGradient id="acf-prospects-fill-modal" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="rgba(59, 130, 246, 0.12)"/>
          <stop offset="100%" stop-color="rgba(59, 130, 246, 0)"/>
        </linearGradient>
        <linearGradient id="acf-customers-fill-modal" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="rgba(16, 185, 129, 0.12)"/>
          <stop offset="100%" stop-color="rgba(16, 185, 129, 0)"/>
        </linearGradient>
      </defs>

      <!-- Y Grid Lines & Labels -->
      <line x1="${paddingLeft}" y1="${paddingTop}" x2="${width - paddingRight}" y2="${paddingTop}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${paddingTop + graphHeight / 2}" x2="${width - paddingRight}" y2="${paddingTop + graphHeight / 2}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${height - paddingBottom}" x2="${width - paddingRight}" y2="${height - paddingBottom}" stroke="rgba(255,255,255,0.08)" stroke-width="1.5"/>

      <text x="${paddingLeft - 10}" y="${paddingTop + 4}" fill="#94a3b8" font-family="'Outfit', sans-serif" font-size="9" font-weight="800" text-anchor="end">100% (A)</text>
      <text x="${paddingLeft - 10}" y="${paddingTop + graphHeight / 2 + 4}" fill="#475569" font-family="'Outfit', sans-serif" font-size="9" font-weight="800" text-anchor="end">50% (C)</text>
      <text x="${paddingLeft - 10}" y="${height - paddingBottom + 3}" fill="#ef4444" font-family="'Outfit', sans-serif" font-size="9" font-weight="900" text-anchor="end">0% (F)</text>

      ${curvesHtml}
      ${labelsHtml}
    </svg>
  `;
}

function generateRepExpandedTPVolumeSVG(labels) {
  const width = 800;
  const height = 240;
  const paddingLeft = 45;
  const paddingRight = 20;
  const paddingTop = 25;
  const paddingBottom = 30;

  const activeLabels = labels || ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'];
  const graphWidth = width - paddingLeft - paddingRight;
  const graphHeight = height - paddingTop - paddingBottom;
  const range = window.currentAnalyticsRange || '30d';

  if (!window.activeRepTPVolumeSeries) {
    window.activeRepRepTPVolumeSeries = { prospects: true, customers: true };
  }

  const dataP = getRepTPVolumeData('prospects', range);
  const dataC = getRepTPVolumeData('customers', range);

  const len = activeLabels.length;
  let maxTotal = 1;
  for (let i = 0; i < len; i++) {
    const valP = window.activeRepTPVolumeSeries.prospects ? dataP[i] : 0;
    const valC = window.activeRepTPVolumeSeries.customers ? dataC[i] : 0;
    const itemMax = Math.max(valP, valC);
    if (itemMax > maxTotal) maxTotal = itemMax;
  }

  const barWidth = 24;
  const barGap = 6;
  const groupWidth = 2 * barWidth + barGap;
  const colGap = (graphWidth - (len * groupWidth)) / (len - 1 || 1);

  const columnsHtml = activeLabels.map((l, idx) => {
    const groupX = paddingLeft + idx * (groupWidth + colGap);
    
    let prospectsBar = '';
    if (window.activeRepTPVolumeSeries.prospects) {
      const val = dataP[idx];
      const h = (val / maxTotal) * graphHeight;
      const y = height - paddingBottom - h;
      prospectsBar = `
        <g class="tp-volume-bar-group" data-index="${idx}" data-category="prospects" data-value="${val}" style="cursor: pointer; pointer-events: all;">
          <rect class="tp-volume-bar-highlight" x="${groupX - 2}" y="${y - 2}" width="${barWidth + 4}" height="${h + 4}" rx="4" ry="4" fill="none" stroke="#3b82f6" stroke-width="1.5" style="opacity: 0; transition: opacity 0.2s ease; filter: drop-shadow(0 0 4px rgba(59,130,246,0.5));" />
          <rect class="tp-volume-bar" x="${groupX}" y="${y}" width="${barWidth}" height="${h}" rx="3" ry="3" fill="url(#tp-prospects-grad-modal)" style="opacity: 0.85; transition: opacity 0.2s ease;" />
          ${val > 0 ? `<text class="tp-volume-bar-val" x="${groupX + barWidth / 2}" y="${y - 5}" fill="#3b82f6" font-family="'Outfit', sans-serif" font-size="7.5" font-weight="800" text-anchor="middle" style="transition: opacity 0.2s ease;">${val}</text>` : ''}
          <rect x="${groupX - 1}" y="${paddingTop}" width="${barWidth + 2}" height="${graphHeight}" fill="#fff" fill-opacity="0" pointer-events="all" />
        </g>
      `;
    }

    let customersBar = '';
    if (window.activeRepTPVolumeSeries.customers) {
      const val = dataC[idx];
      const h = (val / maxTotal) * graphHeight;
      const y = height - paddingBottom - h;
      const xOffset = groupX + barWidth + barGap;
      customersBar = `
        <g class="tp-volume-bar-group" data-index="${idx}" data-category="customers" data-value="${val}" style="cursor: pointer; pointer-events: all;">
          <rect class="tp-volume-bar-highlight" x="${xOffset - 2}" y="${y - 2}" width="${barWidth + 4}" height="${h + 4}" rx="4" ry="4" fill="none" stroke="#10b981" stroke-width="1.5" style="opacity: 0; transition: opacity 0.2s ease; filter: drop-shadow(0 0 4px rgba(16,185,129,0.5));" />
          <rect class="tp-volume-bar" x="${xOffset}" y="${y}" width="${barWidth}" height="${h}" rx="3" ry="3" fill="url(#tp-customers-grad-modal)" style="opacity: 0.85; transition: opacity 0.2s ease;" />
          ${val > 0 ? `<text class="tp-volume-bar-val" x="${xOffset + barWidth / 2}" y="${y - 5}" fill="#10b981" font-family="'Outfit', sans-serif" font-size="7.5" font-weight="800" text-anchor="middle" style="transition: opacity 0.2s ease;">${val}</text>` : ''}
          <rect x="${xOffset - 1}" y="${paddingTop}" width="${barWidth + 2}" height="${graphHeight}" fill="#fff" fill-opacity="0" pointer-events="all" />
        </g>
      `;
    }

    return `
      <g>
        ${prospectsBar}
        ${customersBar}
      </g>
    `;
  }).join('');

  const labelsHtml = activeLabels.map((l, idx) => {
    const x = paddingLeft + idx * (groupWidth + colGap) + groupWidth / 2;
    return `<text x="${x}" y="${height - 12}" fill="#94a3b8" font-family="'Outfit', sans-serif" font-size="9" font-weight="700" text-anchor="middle">${l}</text>`;
  }).join('');

  return `
    <svg viewBox="0 0 ${width} ${height}" style="width: 100%; height: auto; background: rgba(10, 11, 24, 0.6); border: 1px solid rgba(255,255,255,0.05); border-radius: 16px; overflow: visible;">
      <style>
        .tp-volume-bar {
          transition: transform 0.2s ease, opacity 0.2s ease, filter 0.2s ease;
        }
        .tp-volume-bar-group:hover .tp-volume-bar {
          filter: brightness(1.2);
          transform: translateY(-2px);
          opacity: 1 !important;
        }
      </style>
      <defs>
        <linearGradient id="tp-prospects-grad-modal" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="#3b82f6"/>
          <stop offset="100%" stop-color="#1d4ed8"/>
        </linearGradient>
        <linearGradient id="tp-customers-grad-modal" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="#10b981"/>
          <stop offset="100%" stop-color="#047857"/>
        </linearGradient>
      </defs>

      <!-- Y Grid Lines -->
      <line x1="${paddingLeft}" y1="${paddingTop}" x2="${width - paddingRight}" y2="${paddingTop}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${paddingTop + graphHeight / 2}" x2="${width - paddingRight}" y2="${paddingTop + graphHeight / 2}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${height - paddingBottom}" x2="${width - paddingRight}" y2="${height - paddingBottom}" stroke="rgba(255,255,255,0.08)" stroke-width="1.5"/>

      <!-- Y-Axis Labels -->
      <text x="${paddingLeft - 10}" y="${paddingTop + 4}" fill="#94a3b8" font-family="'Outfit', sans-serif" font-size="9" font-weight="800" text-anchor="end">${maxTotal}</text>
      <text x="${paddingLeft - 10}" y="${paddingTop + graphHeight / 2 + 4}" fill="#475569" font-family="'Outfit', sans-serif" font-size="9" font-weight="800" text-anchor="end">${Math.round(maxTotal / 2)}</text>
      <text x="${paddingLeft - 10}" y="${height - paddingBottom + 3}" fill="#94a3b8" font-family="'Outfit', sans-serif" font-size="9" font-weight="800" text-anchor="end">0</text>

      ${columnsHtml}
      ${labelsHtml}
    </svg>
  `;
}

function getRepHealthLabels(range) {
  const map = {
    'live': ['8am', '10am', '12pm', '2pm', '4pm', '6pm'],
    'yesterday': ['8am', '10am', '12pm', '2pm', '4pm', '6pm'],
    '7d': ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'],
    '30d': ['Wk 1', 'Wk 2', 'Wk 3', 'Wk 4', 'Wk 5', 'Active'],
    '90d': ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
    'ytd': ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
    'all': ['Q1-25', 'Q2-25', 'Q3-25', 'Q4-25', 'Q1-26', 'Q2-26']
  };
  return map[range] || map['30d'];
}

function getRepACFData(tab, range) {
  const len = 6;
  const data = [];
  const seed = tab === 'customers' ? 0.8 : 0.2;
  for (let i = 0; i < len; i++) {
    let wave = Math.sin(i * 1.5 + seed) * 3;
    if (tab === 'customers') {
      data.push(Math.round(75 + wave));
    } else {
      data.push(Math.round(55 + wave));
    }
  }
  return data;
}

function getRepTouchpointsScale(range) {
  const map = {
    'live': 2,
    'yesterday': 1,
    '7d': 8,
    '30d': 36,
    '90d': 110,
    'ytd': 280,
    'all': 450
  };
  return map[range] || 36;
}

function getRepTPVolumeData(tab, range) {
  const len = 6;
  const data = [];
  const seed = (range.charCodeAt(0) || 5) + (tab === 'customers' ? 3 : 1);
  const scale = getRepTouchpointsScale(range);
  const factor = tab === 'customers' ? 0.55 : 0.45;
  for (let i = 0; i < len; i++) {
    const base = scale * factor;
    const wave = 0.5 + Math.abs(Math.sin(seed + i * 1.1)) * 0.5;
    const val = Math.round(base * wave);
    data.push(val || 1);
  }
  return data;
}

window.renderRepACFChart = function() {
  const svgs = document.querySelectorAll('#rep-svg-acf-trend');
  if (svgs.length === 0) return;

  const width = 600;
  const height = 160;
  const paddingLeft = 48;
  const paddingRight = 15;
  const paddingTop = 20;
  const paddingBottom = 25;

  const range = window.currentAnalyticsRange || '30d';
  const activeLabels = getRepHealthLabels(range);

  const graphWidth = width - paddingLeft - paddingRight;
  const graphHeight = height - paddingTop - paddingBottom;

  if (!window.activeRepACFSeries) {
    window.activeRepACFSeries = { prospects: true, customers: true };
  }

  const repSections = document.querySelectorAll('#rep-profile-analytics-section');
  repSections.forEach(section => {
    const acfCard = section.querySelector('#rep-card-acf-trend-hud');
    if (!acfCard) return;
    const tags = acfCard.querySelectorAll('.analytics-legend-row .panel-tag');
    if (tags.length >= 2) {
      const keys = ['prospects', 'customers'];
      keys.forEach((key, idx) => {
        const tag = tags[idx];
        tag.style.cursor = 'pointer';
        if (!tag.dataset.listenerAttached) {
          tag.dataset.listenerAttached = 'true';
          tag.addEventListener('click', (e) => {
            e.stopPropagation();
            window.activeRepACFSeries[key] = !window.activeRepACFSeries[key];
            window.renderRepACFChart();
          });
        }
        if (window.activeRepACFSeries[key]) {
          tag.style.opacity = '1';
          if (key === 'prospects') {
            tag.style.background = 'rgba(59, 130, 246, 0.15)';
            tag.style.borderColor = 'rgba(59, 130, 246, 0.4)';
            tag.style.color = '#3b82f6';
          } else {
            tag.style.background = 'rgba(16, 185, 129, 0.15)';
            tag.style.borderColor = 'rgba(16, 185, 129, 0.4)';
            tag.style.color = '#10b981';
          }
        } else {
          tag.style.opacity = '0.3';
          tag.style.background = 'rgba(255, 255, 255, 0.02)';
          tag.style.borderColor = 'rgba(255, 255, 255, 0.05)';
          tag.style.color = '#64748b';
        }
      });
    }
  });

  const getPoints = (dataArr) => {
    return dataArr.map((val, idx) => {
      const x = paddingLeft + (idx / (dataArr.length - 1)) * graphWidth;
      const y = paddingTop + graphHeight * (1 - val / 100);
      return { x, y, val };
    });
  };

  const getPathD = (points) => {
    if (points.length === 0) return '';
    let pathD = `M ${points[0].x} ${points[0].y}`;
    for (let i = 0; i < points.length - 1; i++) {
      const p0 = points[i];
      const p1 = points[i + 1];
      const cp1x = p0.x + (p1.x - p0.x) / 3;
      const cp1y = p0.y;
      const cp2x = p0.x + 2 * (p1.x - p0.x) / 3;
      const cp2y = p1.y;
      pathD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;
    }
    return pathD;
  };

  const getFillD = (points) => {
    if (points.length === 0) return '';
    let fillD = `M ${points[0].x} ${height - paddingBottom} L ${points[0].x} ${points[0].y}`;
    for (let i = 0; i < points.length - 1; i++) {
      const p0 = points[i];
      const p1 = points[i + 1];
      const cp1x = p0.x + (p1.x - p0.x) / 3;
      const cp1y = p0.y;
      const cp2x = p0.x + 2 * (p1.x - p0.x) / 3;
      const cp2y = p1.y;
      fillD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;
    }
    fillD += ` L ${points[points.length - 1].x} ${height - paddingBottom} Z`;
    return fillD;
  };

  let prospectsCurve = '';
  if (window.activeRepACFSeries.prospects) {
    const pts = getPoints(getRepACFData('prospects', range));
    const path = getPathD(pts);
    const fill = getFillD(pts);
    prospectsCurve = `
      <path d="${fill}" fill="url(#rep-acf-prospects-fill)" />
      <path d="${path}" fill="none" stroke="#3b82f6" stroke-width="2.5" stroke-linecap="round" />
      ${pts.map(p => `
        <circle cx="${p.x}" cy="${p.y}" r="3.2" fill="#3b82f6" stroke="#0a0b18" stroke-width="1.2" />
        <text x="${p.x}" y="${p.y - 8}" fill="#fff" font-size="7.5" font-family="'Outfit', sans-serif" font-weight="900" text-anchor="middle" style="text-shadow: 0 1px 2px rgba(0,0,0,0.9);">${p.val}%</text>
      `).join('')}
    `;
  }

  let customersCurve = '';
  if (window.activeRepACFSeries.customers) {
    const pts = getPoints(getRepACFData('customers', range));
    const path = getPathD(pts);
    const fill = getFillD(pts);
    customersCurve = `
      <path d="${fill}" fill="url(#rep-acf-customers-fill)" />
      <path d="${path}" fill="none" stroke="#10b981" stroke-width="2.5" stroke-linecap="round" />
      ${pts.map(p => `
        <circle cx="${p.x}" cy="${p.y}" r="3.2" fill="#10b981" stroke="#0a0b18" stroke-width="1.2" />
        <text x="${p.x}" y="${p.y - 8}" fill="#fff" font-size="7.5" font-family="'Outfit', sans-serif" font-weight="900" text-anchor="middle" style="text-shadow: 0 1px 2px rgba(0,0,0,0.9);">${p.val}%</text>
      `).join('')}
    `;
  }

  const labelsHtml = activeLabels.map((l, idx) => {
    const x = paddingLeft + (idx / (activeLabels.length - 1)) * graphWidth;
    return `<text x="${x}" y="${height - 10}" fill="#64748b" font-size="8.5" font-weight="700" text-anchor="middle">${l}</text>`;
  }).join('');

  svgs.forEach(svg => {
    svg.innerHTML = `
      <defs>
        <linearGradient id="rep-acf-prospects-fill" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="rgba(59, 130, 246, 0.08)"/>
          <stop offset="100%" stop-color="rgba(59, 130, 246, 0)"/>
        </linearGradient>
        <linearGradient id="rep-acf-customers-fill" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="rgba(16, 185, 129, 0.08)"/>
          <stop offset="100%" stop-color="rgba(16, 185, 129, 0)"/>
        </linearGradient>
      </defs>

      <line x1="${paddingLeft}" y1="${paddingTop}" x2="${width - paddingRight}" y2="${paddingTop}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${paddingTop + graphHeight / 2}" x2="${width - paddingRight}" y2="${paddingTop + graphHeight / 2}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${height - paddingBottom}" x2="${width - paddingRight}" y2="${height - paddingBottom}" stroke="rgba(255,255,255,0.06)" stroke-width="1.5"/>

      <text x="40" y="${paddingTop + 4}" fill="#64748b" font-size="8.5" font-weight="700" text-anchor="end">100% (A)</text>
      <text x="40" y="${paddingTop + graphHeight / 2 + 4}" fill="#475569" font-size="8.5" font-weight="700" text-anchor="end">50% (C)</text>
      <text x="40" y="${height - paddingBottom + 3}" fill="#ef4444" font-size="8.5" font-weight="800" text-anchor="end">0% (F)</text>

      ${labelsHtml}
      ${prospectsCurve}
      ${customersCurve}
    `;
  });
};

