function getTimelineGradeHtml(grade = 'C') {















  const labels = { 'A': 'A - Very Good', 'C': 'C - Okay', 'F': 'F - Very Bad' };















  const classes = { 'A': 'grade-badge-a', 'C': 'grade-badge-c', 'F': 'grade-badge-f' };















  















  return `















    <div class="timeline-card-grade-container" data-grade="${grade}">















      <span class="timeline-grade-badge ${classes[grade] || 'grade-badge-c'}" title="Click to change grade">${labels[grade] || 'C - Okay'}</span>















      <div class="timeline-grade-selector-popup">















        <button class="mini-grade-opt opt-a ${grade === 'A' ? 'active' : ''}" data-val="A">A</button>















        <button class="mini-grade-opt opt-c ${grade === 'C' ? 'active' : ''}" data-val="C">C</button>















        <button class="mini-grade-opt opt-f ${grade === 'F' ? 'active' : ''}" data-val="F">F</button>















      </div>















    </div>















  `;















}































function bindTimelineGradeInteractions(parent = document) {















  const containers = parent.querySelectorAll('.timeline-card-grade-container');















  containers.forEach(container => {















    const badge = container.querySelector('.timeline-grade-badge');















    const popup = container.querySelector('.timeline-grade-selector-popup');















    const opts = container.querySelectorAll('.mini-grade-opt');















    















    if (!badge || !popup) return;















    















    badge.addEventListener('click', (e) => {















      e.preventDefault();















      e.stopPropagation();















      















      document.querySelectorAll('.timeline-grade-selector-popup.show').forEach(p => {















        if (p !== popup) p.classList.remove('show');















      });















      















      popup.classList.toggle('show');















    });















    















    document.addEventListener('click', () => {















      popup.classList.remove('show');















    });















    















    opts.forEach(opt => {















      opt.addEventListener('click', (e) => {















        e.preventDefault();















        e.stopPropagation();















        















        const newVal = opt.getAttribute('data-val');















        const oldVal = container.getAttribute('data-grade');















        if (newVal === oldVal) {















          popup.classList.remove('show');















          return;















        }















        















        container.setAttribute('data-grade', newVal);















        















        opts.forEach(o => o.classList.remove('active'));















        opt.classList.add('active');















        















        const labels = { 'A': 'A - Very Good', 'C': 'C - Okay', 'F': 'F - Very Bad' };















        const classes = { 'A': 'grade-badge-a', 'C': 'grade-badge-c', 'F': 'grade-badge-f' };















        















        badge.className = `timeline-grade-badge ${classes[newVal]}`;















        badge.textContent = labels[newVal];















        















        popup.classList.remove('show');















        















        const gradeLabelsMap = {















          'A': 'A (Very Good Interaction) 🟢',















          'C': 'C (Okay / Neutral Interaction) 🟡',















          'F': 'F (Very Bad Interaction) 🔴'















        };















        showDashboardToast(`Interaction grade updated to ${gradeLabelsMap[newVal]}!`, '✓');















        















        const detailHealthScore = document.getElementById('detail-health-score-val');















        const detailHealthFill = document.getElementById('detail-health-fill');















        const detailNameEl = document.getElementById('detail-name');















        const activeName = detailNameEl ? detailNameEl.textContent.trim() : '';















        















        if (newVal === 'A') {















          if (detailHealthScore) detailHealthScore.textContent = '98%';















          if (detailHealthFill) {















            detailHealthFill.style.strokeDashoffset = '5.0';















            detailHealthFill.style.stroke = '#10b981';















          }















          if (activeName) resetClientDecayToGreen(activeName);















        } else if (newVal === 'F') {















          if (detailHealthScore) detailHealthScore.textContent = '38%';















          if (detailHealthFill) {















            detailHealthFill.style.strokeDashoffset = '155.7';















            detailHealthFill.style.stroke = '#ef4444';















          }















          if (activeName) triggerClientDecayToRed(activeName);















          showDashboardToast(`Warning: Client in high-risk category due to friction!`, '⚠');















        } else {















          if (detailHealthScore) detailHealthScore.textContent = '74%';















          if (detailHealthFill) {















            detailHealthFill.style.strokeDashoffset = '65.3';















            detailHealthFill.style.stroke = '#f59e0b';















          }















          if (activeName) resetClientDecayToOrange(activeName);















        }















        















        sortAllRegistryTables();















        















        // Update database history and redraw graph















        const detailTimelineList = document.getElementById('detail-timeline-list');















        const cardItem = container.closest('.timeline-card-item');















        if (cardItem && detailTimelineList && activeName) {















          const cards = Array.from(detailTimelineList.querySelectorAll('.timeline-card-item'));















          const idx = cards.indexOf(cardItem);















          if (idx !== -1) {















            const history = getClientHistory(activeName);















            const historyIndex = history.length - 1 - idx;















            if (historyIndex >= 0 && historyIndex < history.length) {















              history[historyIndex].grade = newVal;















              renderDashboardGraph(activeName);















            }















          }















        }















      });















    });















  });















}































