function getClientGraphHistory(clientName, timeframe) {















  const history = getClientHistory(clientName);















  if (timeframe === 'last5') return history;















  















  const timeLabels = {















    "7d": ["May 21", "May 22", "May 24", "May 25", "May 27"],















    "30d": ["May 02", "May 08", "May 15", "May 20", "May 27"],















    "90d": ["Mar 10", "Mar 28", "Apr 15", "May 05", "May 27"],















    "ytd": ["Jan 15", "Feb 28", "Mar 30", "Apr 30", "May 27"]















  };















  















  const labels = timeLabels[timeframe] || timeLabels["30d"];















  const basePoints = history.map(item => ({...item}));















  















  return basePoints.map((item, idx) => {















    item.date = labels[idx];















    return item;















  });















}































function initGraphFilters() {















  const sectorToggle = document.getElementById('graph-sector-toggle');















  if (sectorToggle) {















    sectorToggle.querySelectorAll('.sector-toggle-btn').forEach(btn => {















      btn.onclick = (e) => {















        e.preventDefault();















        sectorToggle.querySelectorAll('.sector-toggle-btn').forEach(b => b.classList.remove('active'));















        btn.classList.add('active');















        window.activeGraphSector = btn.getAttribute('data-sector') || 'prospects';















        if (window.activeProfileName) {















          renderDashboardGraph(window.activeProfileName);















        }















      };















    });















  }















  















  const timeToggle = document.getElementById('graph-time-toggle');















  if (timeToggle) {















    timeToggle.querySelectorAll('.time-toggle-btn').forEach(btn => {















      btn.onclick = (e) => {















        e.preventDefault();















        timeToggle.querySelectorAll('.time-toggle-btn').forEach(b => b.classList.remove('active'));















        btn.classList.add('active');















        window.activeGraphTimeframe = btn.getAttribute('data-time') || 'last5';















        if (window.activeProfileName) {















          renderDashboardGraph(window.activeProfileName);















        }















      };















    });















  }















}































function renderDashboardGraph(clientName) {















  const pathEl = document.getElementById('trend-chart-path');















  const fillEl = document.getElementById('trend-chart-fill');















  const nodesGroup = document.getElementById('trend-chart-nodes');















  const labelsGroup = document.getElementById('trend-chart-labels');















  















  if (!pathEl || !fillEl || !nodesGroup || !labelsGroup) return;















  















  let history = [];















  const profileType = window.activeProfileType || 'customer';















  















  if (profileType === 'employee') {















    const activeSector = window.activeGraphSector || 'prospects';















    const activeTimeframe = window.activeGraphTimeframe || 'last5';















    history = getEmployeeGraphHistory(clientName, activeSector, activeTimeframe);















  } else {















    const activeTimeframe = window.activeGraphTimeframe || 'last5';















    history = getClientGraphHistory(clientName, activeTimeframe);















  }















  















  const xCoords = [65, 285, 505, 725, 945];















  const yCoords = { "A": 35, "C": 110, "F": 185 };















  const colors = { "A": "#10b981", "C": "#f59e0b", "F": "#ef4444" };















  















  const points = [];















  for (let i = 0; i < 5; i++) {















    const item = history[i] || { type: "Touchpoint", date: "N/A", grade: "C" };















    const x = xCoords[i];















    const y = yCoords[item.grade] !== undefined ? yCoords[item.grade] : 110;















    const count = item.count !== undefined ? item.count : 1;















    points.push({ x, y, grade: item.grade, type: item.type, date: item.date, count, notes: item.notes, rep: item.rep });















  }















  















  // Smooth cubic Bezier spline















  let pathD = `M ${points[0].x} ${points[0].y}`;















  for (let i = 0; i < points.length - 1; i++) {















    const p0 = points[i];















    const p1 = points[i + 1];















    const cp1x = p0.x + 100;















    const cp1y = p0.y;















    const cp2x = p1.x - 100;















    const cp2y = p1.y;















    pathD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;















  }















  















  let fillD = `M ${points[0].x} 210 L ${points[0].x} ${points[0].y}`;















  for (let i = 0; i < points.length - 1; i++) {















    const p0 = points[i];















    const p1 = points[i + 1];















    const cp1x = p0.x + 100;















    const cp1y = p0.y;















    const cp2x = p1.x - 100;















    const cp2y = p1.y;















    fillD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;















  }















  fillD += ` L ${points[points.length - 1].x} 210 Z`;















  















  pathEl.setAttribute('d', pathD);















  fillEl.setAttribute('d', fillD);















  















  // Draw subtle blue bar chart behind the line graph















  const barsGroup = document.getElementById('trend-chart-bars');















  if (barsGroup) {















    let barsHtml = '';















    points.forEach((pt, index) => {















      const count = pt.count || 1;















      let y = 210;















      let height = 0;















      if (count > 0) {















        y = 222.5 - 37.5 * count;















        height = 210 - y;















      }















      // Width is 40px, rx=6 for rounding, centered on pt.x (offset by -20)















      barsHtml += `<rect class="trend-bar" data-index="${index}" x="${pt.x - 20}" y="${y}" width="40" height="${height}" rx="6" ry="6" />`;















    });















    barsGroup.innerHTML = barsHtml;















    















    // Bind click events on the bars















    const svgChart = document.getElementById('trend-svg-chart');















    const bars = barsGroup.querySelectorAll('.trend-bar');















    bars.forEach(bar => {















      bar.addEventListener('click', (e) => {















        e.preventDefault();















        e.stopPropagation();















        















        const isCurrentlyFocused = svgChart.classList.contains('focus-bars');















        const clickedIndex = bar.getAttribute('data-index');















        const isActive = bar.classList.contains('active-highlight');















        















        // Clear all highlights















        bars.forEach(b => b.classList.remove('active-highlight'));















        















        if (isCurrentlyFocused && isActive) {















          // Toggle back to Line forefront mode















          svgChart.classList.remove('focus-bars');















          showDashboardToast("Line graph brought to forefront.", "ℹ");















        } else {















          // Bring Bar chart to forefront















          svgChart.classList.add('focus-bars');















          bar.classList.add('active-highlight');















          const count = points[clickedIndex].count || 1;















          showDashboardToast(`Momentum Focus: ${count} touchpoints on ${points[clickedIndex].date} 📊`, "✓");















        }















      });















    });















    















    // Background click resets focus to Line graph forefront















    if (svgChart && !svgChart.dataset.clickBound) {















      svgChart.dataset.clickBound = "true";















      svgChart.addEventListener('click', (e) => {















        if (e.target.tagName === 'svg' || e.target.tagName === 'line' || e.target.id === 'trend-svg-chart') {















          svgChart.classList.remove('focus-bars');















          const barsList = svgChart.querySelectorAll('.trend-bar');















          barsList.forEach(b => b.classList.remove('active-highlight'));















        }















      });















    }















  }















  















  // Draw circles (Radius expanded to 10, stroke to 3, and glow shadow to 6px)















  let nodesHtml = '';















  points.forEach(pt => {















    const color = colors[pt.grade] || "#f59e0b";















    nodesHtml += `<circle cx="${pt.x}" cy="${pt.y}" r="10" fill="${color}" stroke="#0a0b12" stroke-width="3" style="transition: all 0.4s ease; filter: drop-shadow(0 0 6px ${color});" />`;















  });















  nodesGroup.innerHTML = nodesHtml;















  















  // Draw labels (Aligned bottom at Y=228 to avoid Y-axis overlap, using responsive text anchors to prevent clipping)















  let labelsHtml = '';















  points.forEach((pt, index) => {















    let anchor = 'middle';















    let labelX = pt.x;















    















    if (index === 0) {















      anchor = 'start';















      labelX = 60; // Shifted right slightly from X=65 node center to ensure zero collision with Y-labels















    } else if (index === 4) {















      anchor = 'end';















      labelX = 950; // Shifted left slightly from X=945 node center















    }















    















    labelsHtml += `















      <text class="trend-label-text" data-index="${index}" x="${labelX}" y="228" fill="rgba(255,255,255,0.65)" font-size="16" font-weight="700" font-family="'Outfit', sans-serif" text-anchor="${anchor}" style="transition: all 0.4s ease; cursor: pointer;">















        ${pt.date}















      </text>















    `;















  });















  labelsGroup.innerHTML = labelsHtml;















  















  // Premium Interactive Sliding Tooltip binding















  const tooltip = document.getElementById('graph-tooltip');















  const svgChart = document.getElementById('trend-svg-chart');















  if (tooltip && svgChart) {















    const triggerShow = (pt, index) => {















      let gradeColor = '#f59e0b';















      if (pt.grade === 'A') gradeColor = '#10b981';















      else if (pt.grade === 'F') gradeColor = '#ef4444';















      















      let badgeBg = 'rgba(245, 158, 11, 0.15)';















      if (pt.grade === 'A') badgeBg = 'rgba(16, 185, 129, 0.15)';















      else if (pt.grade === 'F') badgeBg = 'rgba(239, 68, 68, 0.15)';















      















      tooltip.innerHTML = `















        <div class="tooltip-header">















          <span class="tooltip-type" style="color: ${gradeColor}; background: ${badgeBg}; font-size: 10px; font-weight: 800; text-transform: uppercase; letter-spacing: 0.06em; padding: 2px 6px; border-radius: 4px;">${pt.type}</span>















          <span class="tooltip-date" style="font-size: 11px; font-weight: 500; color: rgba(255, 255, 255, 0.4);">${pt.date}</span>















        </div>















        <div class="tooltip-body" style="font-size: 12px; line-height: 1.4; color: rgba(255, 255, 255, 0.85); font-weight: 400; max-height: 70px; overflow-y: auto;">${pt.notes || 'No description logged.'}</div>















        <div class="tooltip-rep" style="display: flex; align-items: center; gap: 4px; margin-top: 6px; font-size: 10px; color: rgba(255, 255, 255, 0.45);">















          <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><circle cx="12" cy="12" r="10"/><path d="M12 8v4l3 3"/></svg>















          <span>Logged by: ${pt.rep || 'Owner'}</span>















        </div>















      `;















      















      // Calculate precise absolute pixel offset inside graph-chart-wrap container















      const svgRect = svgChart.getBoundingClientRect();















      const posX = (pt.x / 1000) * svgRect.width;















      















      // Dynamic Apple-like sliding alignment using fixed percentage transitions:















      // Index 0 (first bar) is locked exactly at left: 12px with zero transform.















      // Index 4 (last bar) is locked exactly at 100% minus the card width (calc) with zero transform.















      // Middle bars are centered exactly at X = posX (50%).















      let transformStr = 'translateX(-50%)';















      let leftVal = `${posX}px`;















      















      if (index === 0) {















        transformStr = 'translateX(0)';















        leftVal = '12px';















      } else if (index === 4) {















        transformStr = 'translateX(0)';















        leftVal = 'calc(100% - 312px)';















      }















      















      tooltip.style.transform = transformStr;















      tooltip.style.left = leftVal;















      tooltip.style.opacity = '1';















    };















    















    const triggerHide = () => {















      tooltip.style.opacity = '0';















    };















    















    // Attach trigger events to circles (nodes)















    const circles = nodesGroup.querySelectorAll('circle');















    circles.forEach((c, idx) => {















      c.style.cursor = 'pointer';















      c.addEventListener('mouseenter', () => triggerShow(points[idx], idx));















      c.addEventListener('mouseleave', triggerHide);















    });















    















    // Attach trigger events to subtle bar rects















    const barRects = barsGroup ? barsGroup.querySelectorAll('.trend-bar') : [];















    barRects.forEach((b, idx) => {















      b.addEventListener('mouseenter', () => triggerShow(points[idx], idx));















      b.addEventListener('mouseleave', triggerHide);















    });















    















    // Attach trigger events to text labels















    const textLabels = labelsGroup.querySelectorAll('.trend-label-text');















    textLabels.forEach((t, idx) => {















      t.addEventListener('mouseenter', () => triggerShow(points[idx], idx));















      t.addEventListener('mouseleave', triggerHide);















    });















  }















  if (typeof window.hydrateProfileGiftingAnalytics === 'function') {







    window.hydrateProfileGiftingAnalytics(clientName);







  }







  if (typeof window.hydrateProfileTeamDirectory === 'function') {







    window.hydrateProfileTeamDirectory(clientName);







  }















}































function updateDataDecayState(name, days, health) {















  let item = prospectsData.find(p => p.name === name);















  if (item) {















    item.inactiveDays = days;















    if (health !== undefined) item.health = health;















  } else {















    item = customersData.find(c => c.name === name);















    if (item) {















      item.inactiveDays = days;















      if (health !== undefined) item.health = health;















    }















  }















  // Refresh directory views if they exist to keep everything globally synchronized















  if (typeof renderProspectsList === 'function') renderProspectsList();















  if (typeof renderCustomersList === 'function') renderCustomersList();















  // Also refresh our Overview Repository!















  if (typeof renderOverviewRegistry === 'function') renderOverviewRegistry();















}































function resetClientDecayToGreen(name) {















  const rows = document.querySelectorAll('.registry-table tbody .registry-row');















  rows.forEach(row => {















    const nameEl = row.querySelector('.client-name');















    if (nameEl && nameEl.textContent.trim() === name) {















      row.setAttribute('data-status', 'green');















      row.className = 'registry-row green-row';















      const dot = row.querySelector('.aging-glow-dot');















      if (dot) dot.className = 'aging-glow-dot dot-green';















      const statusDaysText = row.querySelector('.status-days');















      if (statusDaysText) {















        statusDaysText.className = 'status-days green-text';















        statusDaysText.textContent = '0 days ago';















      }















      const actionCell = row.querySelector('.row-actions');















      if (actionCell) {















        actionCell.innerHTML = '<span class="action-tag positive">Healthy</span>';















      }















    }















  });















  updateDataDecayState(name, 0, 98);















}































function triggerClientDecayToRed(name) {















  const rows = document.querySelectorAll('.registry-table tbody .registry-row');















  rows.forEach(row => {















    const nameEl = row.querySelector('.client-name');















    if (nameEl && nameEl.textContent.trim() === name) {















      row.setAttribute('data-status', 'red');















      row.className = 'registry-row red-row';















      const dot = row.querySelector('.aging-glow-dot');















      if (dot) dot.className = 'aging-glow-dot dot-red';















      const statusDaysText = row.querySelector('.status-days');















      if (statusDaysText) {















        statusDaysText.className = 'status-days red-text';















        statusDaysText.textContent = '62 days ago';















      }















      const actionCell = row.querySelector('.row-actions');















      if (actionCell) {















        actionCell.innerHTML = `















          <div class="row-actions">















              <button class="row-btn action-gift send-gift-btn" data-name="${name}">Send Gift</button>















              <button class="row-btn action-nudge nudge-rep-btn" data-rep="Tom Collins" data-client="${name}">Nudge Rep</button>















          </div>















        `;















      }















    }















  });















  updateDataDecayState(name, 62, 48);















}































function resetClientDecayToOrange(name) {















  const rows = document.querySelectorAll('.registry-table tbody .registry-row');















  rows.forEach(row => {















    const nameEl = row.querySelector('.client-name');















    if (nameEl && nameEl.textContent.trim() === name) {















      row.setAttribute('data-status', 'orange');















      row.className = 'registry-row orange-row';















      const dot = row.querySelector('.aging-glow-dot');















      if (dot) dot.className = 'aging-glow-dot dot-orange';















      const statusDaysText = row.querySelector('.status-days');















      if (statusDaysText) {















        statusDaysText.className = 'status-days orange-text';















        statusDaysText.textContent = '35 days ago';















      }















      const actionCell = row.querySelector('.row-actions');















      if (actionCell) {















        actionCell.innerHTML = `















          <div class="row-actions">















              <button class="row-btn action-gift send-gift-btn" data-name="${name}">Send Gift</button>















              <button class="row-btn action-nudge nudge-rep-btn" data-rep="Tom Collins" data-client="${name}">Nudge Rep</button>















          </div>















        `;















      }















    }















  });















  updateDataDecayState(name, 35, 78);















}































// 4. Modal Triggers & Validation Logic















function initDashboardLoggingModal() {















  const btnOpen = document.getElementById('btn-quick-log');















  const modal = document.getElementById('quick-log-modal');















  const btnClose = document.getElementById('btn-close-log-modal');















  const btnCancel = document.getElementById('btn-cancel-log-modal');















  const btnSubmit = document.getElementById('btn-submit-activity');















  const selectType = document.getElementById('select-activity-type');















  const feedbackBox = document.getElementById('timer-feedback-indicator');















  















  if (!modal) return;















  















  // Modal Grade Selection Logic















  const modalGradeSelector = document.getElementById('modal-grade-selector');















  const modalSelectedGradeInput = document.getElementById('modal-selected-grade');















  const modalGradeFeedbackDesc = document.getElementById('modal-grade-feedback-desc');















  















  if (modalGradeSelector && modalSelectedGradeInput) {















    const btns = modalGradeSelector.querySelectorAll('.grade-btn');















    const descMap = {















      'A': 'Grade A: Very Good (Receptive, understanding, positive interaction)',















      'C': 'Grade C: Okay / Neutral Interaction (Friction or neutral outcome)',















      'F': 'Grade F: Very Bad Interaction (Hostile, complaint, "don\'t talk")'















    };















    const colorClasses = {















      'A': 'text-green',















      'C': 'text-orange',















      'F': 'text-red'















    };















    btns.forEach(btn => {















      btn.addEventListener('click', (e) => {















        e.preventDefault();















        e.stopPropagation();















        btns.forEach(b => b.classList.remove('active'));















        btn.classList.add('active');















        const val = btn.getAttribute('data-grade');















        modalSelectedGradeInput.value = val;















        















        if (modalGradeFeedbackDesc) {















          modalGradeFeedbackDesc.textContent = descMap[val] || '';















          modalGradeFeedbackDesc.className = 'grade-feedback-desc ' + (colorClasses[val] || '');















        }















      });















    });















  }















  















  // Open modal click















  if (btnOpen) {















    btnOpen.addEventListener('click', () => {















      // Bulletproof viewport centering: force modal element directly onto document.documentElement to bypass relative grids, transforms, and body zoom scaling!















      if (modal.parentElement !== document.documentElement) {















        document.documentElement.appendChild(modal);















      }















      modal.classList.add('show');















      document.body.style.overflow = 'hidden'; // Lock background scrolling















    });















  }















  















  // Close triggers















  const closeModal = () => {















    modal.classList.remove('show');















    document.body.style.overflow = '';















  };















  















  if (btnClose) btnClose.addEventListener('click', closeModal);















  if (btnCancel) btnCancel.addEventListener('click', closeModal);















  















  // Close on overlay backing click















  modal.addEventListener('click', (e) => {















    if (e.target === modal) {















      closeModal();















    }















  });















  















  // Choices validation: High-Value vs. Low-Value















  if (selectType && feedbackBox) {















    selectType.addEventListener('change', () => {















      const type = selectType.value;















      const isHighValue = ['call', 'meeting', 'personal-email', 'gift'].includes(type);















      















      const iconEl = feedbackBox.querySelector('.feedback-icon');















      const titleEl = feedbackBox.querySelector('.feedback-title');















      const descEl = feedbackBox.querySelector('.feedback-desc');















      















      if (isHighValue) {















        feedbackBox.classList.remove('low-value');















        if (iconEl) {















          iconEl.textContent = '✓';















          iconEl.style.background = '#10b981';















        }















        if (titleEl) titleEl.textContent = 'High-Value Engagement Validated';















        if (descEl) descEl.textContent = "Resets the client's inactivity decay timer to Green (Active).";















      } else {















        feedbackBox.classList.add('low-value');















        if (iconEl) {















          iconEl.textContent = '!';















          iconEl.style.background = '#64748b';















        }















        if (titleEl) titleEl.textContent = 'System Template / Low-Value Touchpoint';















        if (descEl) descEl.textContent = "Logs in history, but does NOT reset relationship decay timers.";















      }















    });















  }















  















  // Form submission lifecycle















  if (btnSubmit) {
    btnSubmit.addEventListener('click', (e) => {
      e.preventDefault();

      const clientSelect = document.getElementById('select-client');
      const clientName = clientSelect ? clientSelect.value : 'Client';
      const notesVal = document.getElementById('input-notes') ? document.getElementById('input-notes').value : '';
      const activityVal = selectType ? selectType.value : 'call';
      const selectedGrade = modalSelectedGradeInput ? modalSelectedGradeInput.value : 'C';

      if (!notesVal.trim()) {
        showDashboardToast('Please write some interaction notes first.', '⚠️');
        return;
      }

      // Map frontend clientName to contact ID from customersData or prospectsData
      const cleanName = clientName.toLowerCase().trim();
      const dbItem = [...customersData, ...prospectsData].find(c => c.name.toLowerCase().trim() === cleanName);
      const contactId = dbItem ? dbItem.id : null;

      if (!contactId) {
        showDashboardToast(`Could not resolve contact ID for ${clientName}`, '❌');
        return;
      }

      // Map activity types to capitalized DB types
      let dbType = 'Call';
      if (activityVal === 'meeting') dbType = 'Meeting';
      else if (activityVal === 'personal-email' || activityVal === 'email') dbType = 'Email';
      else if (activityVal === 'lunch') dbType = 'Lunch';
      else if (activityVal === 'proposal') dbType = 'Proposal';
      else if (activityVal === 'gift') dbType = 'Gift';

      // Disable submit button
      const submitBtn = document.getElementById('btn-submit-activity');
      if (submitBtn) {
        submitBtn.disabled = true;
        submitBtn.textContent = 'Logging...';
      }

      (async () => {
        try {
          const { error: actErr } = await supabase
            .from('activities')
            .insert({
              contact_id: contactId,
              rep_id: window.activeUserId || '8b1933c0-0f0e-4361-b472-3c8cfa2b9801', // Fallback to Paul K
              type: dbType,
              grade: selectedGrade,
              notes: notesVal.trim(),
              workspace_id: window.activeWorkspaceId || 'd9b0a1a0-0000-0000-0000-000000000001'
            });

          if (actErr) {
            console.error("[SUPABASE LOG ACTIVITY] Database insert failed:", actErr);
            showDashboardToast(`Database Error: ${actErr.message || actErr.details || 'Check permission details.'}`, '❌');
            return;
          }

          showDashboardToast(`🎉 Activity logged successfully!`, '✓');

          // Close modal and reset form inputs
          closeModal();

          if (document.getElementById('input-notes')) {
            document.getElementById('input-notes').value = '';
          }
          if (modalSelectedGradeInput) {
            modalSelectedGradeInput.value = 'C';
            const btns = modalGradeSelector.querySelectorAll('.grade-btn');
            btns.forEach(b => {
              if (b.getAttribute('data-grade') === 'C') b.classList.add('active');
              else b.classList.remove('active');
            });
            if (modalGradeFeedbackDesc) {
              modalGradeFeedbackDesc.textContent = 'Grade C: Okay / Neutral Interaction';
              modalGradeFeedbackDesc.className = 'grade-feedback-desc text-orange';
            }
          }

          // Reload data
          await fetchDashboardData();

        } catch (ex) {
          console.error("[SUPABASE LOG ACTIVITY] Exception during log:", ex);
          showDashboardToast(`Error: ${ex.message || ex}`, '❌');
        } finally {
          if (submitBtn) {
            submitBtn.disabled = false;
            submitBtn.textContent = 'Log Activity';
          }
        }
      })();
    });
  }


}


