  // Draw Gifting Calendar















  function renderGiftingCalendar(year, month) {















    const displayEl = document.getElementById('gift-cal-display-month');















    const gridEl = document.getElementById('gift-calendar-days-grid');















    if (!gridEl || !displayEl) return;































    const monthNames = [















      "January", "February", "March", "April", "May", "June",















      "July", "August", "September", "October", "November", "December"















    ];















    displayEl.textContent = `${monthNames[month]} ${year}`;































    const firstDay = new Date(year, month, 1).getDay();















    const totalDays = new Date(year, month + 1, 0).getDate();































    gridEl.innerHTML = '';































    // Empty blank cells















    for (let i = 0; i < firstDay; i++) {















      const blank = document.createElement('span');















      blank.className = 'calendar-day-empty';















      blank.style.cssText = 'opacity: 0.05; padding: 12px 0;';















      gridEl.appendChild(blank);















    }































    // Grid days















    for (let day = 1; day <= totalDays; day++) {















      const dayStr = `${year}-${String(month + 1).padStart(2, '0')}-${String(day).padStart(2, '0')}`;















      const cell = document.createElement('div');















      cell.className = 'gift-cal-cell';















      if (dayStr === selectedGiftCalDate) {















        cell.classList.add('selected');















      }















      if (dayStr === '2026-05-27') {















        cell.classList.add('today');















      }































      cell.innerHTML = `<span>${day}</span>`;































      // Get dispatches for day















      let dayDispatches = giftingDispatchSchedule.filter(ev => ev.date === dayStr);
      if (window.currentRole === 'rep') {
        dayDispatches = dayDispatches.filter(ev => recordBelongsToRep({
          sender: ev.sender,
          senderName: ev.sender,
          recipientName: ev.client,
          client: ev.client
        }, window.currentUsername || 'Tom Collins'));
      }















      















      // Check if any dispatch on this day is pending approval or building















      const hasPending = dayDispatches.some(ev => ev.finalized === false);















      if (hasPending) {















        cell.classList.add('has-pending');















      }































      if (dayDispatches.length > 0) {















        const dotWrap = document.createElement('div');















        dotWrap.className = 'gift-cal-dot-wrap';















        















        // Add colorful category indicators (Reach, Retain, Reward, Remember)















        dayDispatches.forEach(disp => {















          // If pending, we don't draw a solid node for it yet (unless finalized)















          if (disp.finalized !== false) {















            const dot = document.createElement('span');















            // User requestedApproved Node colors: Reach = blue, Retain = green, Reward = red, Remember = purple















            const dotColorClass = disp.category === 'reach' ? 'blue' : disp.category === 'retain' ? 'green' : disp.category === 'reward' ? 'red' : 'purple';















            dot.className = `gift-cal-dot ${dotColorClass}`;















            dotWrap.appendChild(dot);















          }















        });















        if (dotWrap.childElementCount > 0) {















          cell.appendChild(dotWrap);















        }















      }































      cell.onclick = () => {















        selectedGiftCalDate = dayStr;















        renderGiftingCalendar(year, month);















        renderGiftingDayDetail(dayStr);















      };































      gridEl.appendChild(cell);















    }















  }































  // Display details when cell clicked















  function renderGiftingDayDetail(dateStr) {















    const labelEl = document.getElementById('gift-detail-day-label');















    const descEl = document.getElementById('gift-detail-day-desc');















    const listEl = document.getElementById('gift-detail-dispatches-list');















    if (!labelEl || !descEl || !listEl) return;































    const dParsed = new Date(dateStr + 'T00:00:00');















    labelEl.textContent = dParsed.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });































    let dayDispatches = giftingDispatchSchedule.filter(ev => ev.date === dateStr);
    if (window.currentRole === 'rep') {
      dayDispatches = dayDispatches.filter(ev => recordBelongsToRep({
        sender: ev.sender,
        senderName: ev.sender,
        recipientName: ev.client,
        client: ev.client
      }, window.currentUsername || 'Tom Collins'));
    }















    















    if (dayDispatches.length === 0) {















      descEl.textContent = '0 appreciation dispatches scheduled for this date.';















      listEl.innerHTML = `















        <div style="text-align: center; padding: 24px; color: #64748b; font-size: 13px;">















          No active boxes queued for delivery on this day.















        </div>















      `;















      return;















    }































    descEl.textContent = `${dayDispatches.length} dispatch${dayDispatches.length > 1 ? 'es' : ''} registered.`;















    listEl.innerHTML = '';































    dayDispatches.forEach(disp => {















      const el = document.createElement('div');















      















      const themeTag = disp.category === 'reach' ? 'bg-blue' : disp.category === 'retain' ? 'bg-emerald' : disp.category === 'reward' ? 'bg-amber' : 'bg-violet';















      const categoryDisplay = disp.category.charAt(0).toUpperCase() + disp.category.slice(1);















      















      // Determine value display















      let valueDisplay = 'Pending Quote';















      if (disp.finalized !== false) {















        valueDisplay = typeof disp.price === 'number' ? `$${disp.price.toFixed(2)}` : disp.price;















      }































      // Distinct styling for pending vs approved dispatches















      let statusBadgeHTML = '';















      let valueColor = '#10b981'; // Green/emerald for approved finalized dispatches















      















      if (disp.finalized === false) {















        el.className = 'dispatch-detail-item dispatch-pending';















        statusBadgeHTML = `<span class="dispatch-status-badge status-pending-badge">Pending Approval</span>`;















        valueColor = '#fbbf24'; // Amber for pending Quote















      } else {















        el.className = 'dispatch-detail-item dispatch-approved';















        statusBadgeHTML = `<span class="dispatch-status-badge status-approved-badge">Dispatched</span>`;















        valueColor = '#10b981'; // Green for approved















      }































      el.innerHTML = `















        <div class="dispatch-detail-row" style="display: flex; align-items: center; flex-wrap: wrap; gap: 6px;">















          <span class="dispatch-detail-cat ${themeTag}">${categoryDisplay}</span>















          <span style="font-weight: 700; color: #fff;">${disp.client}</span>















          ${statusBadgeHTML}















        </div>















        <div class="dispatch-detail-body" style="font-size: 12.5px; color: #94a3b8; margin-top: 6px; line-height: 1.4;">















          <div><strong>Box Type:</strong> ${disp.box}</div>















          <div><strong>Sender:</strong> ${disp.sender}</div>















          <div><strong>Reason:</strong> ${disp.reason}</div>















          <div><strong>Value:</strong> <span style="color: ${valueColor}; font-weight: 600;">${valueDisplay}</span></div>















        </div>















      `;































      // Make it clickable and route to details modal















      el.addEventListener('click', () => {















        const orderId = disp.orderId;















        if (orderId && activeB2BOrders[orderId]) {















          showAppreciationDetails(orderId);















        } else {















          // Dynamically synthesize a B2B order to support viewing details for pre-populated static finalized items!















          const tempId = `order-static-${disp.client.replace(/\s+/g, '-').toLowerCase()}`;















          if (!activeB2BOrders[tempId]) {















            activeB2BOrders[tempId] = {















              orderId: tempId,















              recipientName: disp.client,















              recipientScale: 'executive',















              recipientCount: 1,















              boxType: disp.box.includes('Premium') ? 'premium' : disp.box.includes('Pack') ? 'pack' : 'sweet',















              boxTypeDisplay: disp.box,















              dispatchDate: disp.date,















              sendReason: disp.reason.includes('Outreach') ? 'prospect_outreach' : disp.reason.includes('Renewal') || disp.reason.includes('retention') ? 'customer_retention' : 'custom',















              senderName: disp.sender,















              outerLogoName: '',















              innerLogoName: '',















              outerQuote: '',















              importantNotes: disp.reason,















              minPrice: typeof disp.price === 'number' ? disp.price : 90.00,















              finalPrice: typeof disp.price === 'number' ? disp.price : 90.00,















              state: disp.finalized ? 'Finalize' : (disp.status === 'Awaiting Owner Approval' ? 'Awaiting Owner Approval' : (disp.status === 'Awaiting Design & Quote' ? 'Building' : 'Finalize')),















              category: disp.category















            };















          }















          showAppreciationDetails(tempId);















        }















      });































      listEl.appendChild(el);















    });















  }































  // Dynamic Gifting Queue Rendering System















  function recordBelongsToRep(item, activeRepName = 'Tom Collins') {
    if (!item) return false;
    
    const isManager = (window.currentRole === 'manager');
    if (isManager && activeRepName === 'Marcus Dupond') {
      const roster = ['marcus dupond', 'marcus dupont', 'dwight schrute', 'jane smith'];
      if (item.sender && roster.includes(item.sender.toLowerCase().trim())) return true;
      if (item.senderName && roster.includes(item.senderName.toLowerCase().trim())) return true;
      if (item.rep && roster.includes(item.rep.toLowerCase().trim())) return true;
      
      const clientName = item.client || item.recipientName;
      if (clientName) {
        const cleanName = clientName.toLowerCase().trim();
        const customer = (typeof customersData !== 'undefined') ? customersData.find(c => c.name.toLowerCase().trim() === cleanName) : null;
        if (customer && customer.rep && roster.includes(customer.rep.toLowerCase().trim())) return true;
        const prospect = (typeof prospectsData !== 'undefined') ? prospectsData.find(p => p.name.toLowerCase().trim() === cleanName) : null;
        if (prospect && prospect.rep && roster.includes(prospect.rep.toLowerCase().trim())) return true;
        if (cleanName.includes('scranton') || cleanName.includes('zenith') || cleanName.includes('dunder') || cleanName.includes('apex') || cleanName.includes('chevron') || cleanName.includes('stripe') || cleanName.includes('nova')) return true;
      }
      return false;
    }

    if (item.sender && item.sender.includes(activeRepName)) return true;
    if (item.senderName && item.senderName.includes(activeRepName)) return true;
    const clientName = item.client || item.recipientName;
    if (clientName) {
      const cleanName = clientName.toLowerCase().trim();
      const customer = (typeof customersData !== 'undefined') ? customersData.find(c => c.name.toLowerCase().trim() === cleanName) : null;
      if (customer && customer.rep && customer.rep.includes(activeRepName)) return true;
      const prospect = (typeof prospectsData !== 'undefined') ? prospectsData.find(p => p.name.toLowerCase().trim() === cleanName) : null;
      if (prospect && prospect.rep && prospect.rep.includes(activeRepName)) return true;
    }
    return false;
  }






  function renderGiftingQueue() {
    const role = window.currentRole || localStorage.getItem('whitebox_role') || 'owner';
    const username = window.currentUsername || localStorage.getItem('whitebox_username') || 'Tom Collins';
    const queueList1 = document.getElementById('gifting-approval-list');















    const queueList2 = document.getElementById('alerts-gifting-approval-list');















    















    const renderList = (queueList) => {















      if (!queueList) return;















      queueList.innerHTML = '';















      















      let orders = Object.values(activeB2BOrders);
      if (window.currentRole === 'rep') {
        orders = orders.filter(o => recordBelongsToRep(o, window.currentUsername || localStorage.getItem('whitebox_username') || 'Tom Collins'));
      }















      if (orders.length === 0) {















        queueList.innerHTML = `















          <div style="text-align: center; padding: 32px; color: #64748b; font-size: 13.5px;">















            ✓ All pending automated CRM touchpoints have been finalized. Excellent work.















          </div>















        `;















        return;















      }















      















      // Sort: newest first















      const sortedOrders = orders.sort((a, b) => {















        return b.orderId.localeCompare(a.orderId);















      });















      















      sortedOrders.forEach(order => {















        const cat = order.category;















        let borderLeftColor = '#3b82f6';















        let catLabel = 'Reach';















        let tagClass = 'outreach-tag';















        let bgClass = 'bg-blue';















        















        if (cat === 'retain') {















          borderLeftColor = '#10b981';















          catLabel = 'Retain';















          tagClass = 'retention-tag';















          bgClass = 'bg-emerald';















        } else if (cat === 'reward') {















          borderLeftColor = '#f59e0b';















          catLabel = 'Reward';















          tagClass = 'reward-tag';















          bgClass = 'bg-amber';















        } else if (cat === 'remember') {















          borderLeftColor = '#8b5cf6';















          catLabel = 'Remember';















          tagClass = 'remember-tag';















          bgClass = 'bg-violet';















        }































        const card = document.createElement('div');















        card.id = `card-${order.orderId}-${queueList.id}`; // Keep DOM element IDs unique across lists















        card.setAttribute('data-order-id', order.orderId);















        















        let stateClass = 'state-pending';















        if (order.state === 'Finalize') {















          stateClass = 'state-finalize';















        }















        card.className = `gifting-queue-card ${stateClass}`;















        card.style.cssText = `border-left: 4px solid ${borderLeftColor}; cursor: pointer; transition: all 0.4s ease;`;















        















        let priceLabelVal = order.recipientScale === 'executive' ? `Starts at $${order.minPrice.toFixed(2)}` : 'Custom pricing';















        if (order.state === 'Finalize') {















          priceLabelVal = `Quote Ready: $${order.finalPrice.toFixed(2)}`;















        } else if (order.state === 'Building') {















          priceLabelVal = 'Awaiting Design & Quote';















        }































        let buttonHTML = '';















        const btnId = `btn-action-${order.orderId}-${queueList.id}`;















        if (window.currentRole === 'rep') {
          buttonHTML = `<button class="btn-gift-approve view-gift-btn-queue" id="${btnId}">View</button>`;
        } else if (order.state === 'Awaiting Owner Approval') {















          buttonHTML = `<button class="btn-gift-approve approve-gift-btn-queue pulse-amber-btn" id="${btnId}">Approve</button>`;















        } else if (order.state === 'Building') {















          buttonHTML = `<button class="btn-gift-approve btn-building-disabled" id="${btnId}" disabled>Building</button>`;















        } else if (order.state === 'Finalize') {















          buttonHTML = `<button class="btn-gift-approve btn-finalize-green" id="${btnId}">Finalize</button>`;















        }































        card.innerHTML = `















          <div class="gift-card-main" style="pointer-events: none;">















            <div class="gift-avatar ${bgClass}">${catLabel}</div>















            <div class="gift-info">















              <div class="gift-title-row">















                <h4 class="gift-client">${order.recipientName}</h4>















                <span class="gift-tag ${tagClass}">${priceLabelVal}</span>















              </div>















              <span class="gift-type">${order.boxTypeDisplay}</span>















              <span class="gift-reason" style="color: #64748b;">Reason: ${order.importantNotes || order.sendReason.replace('_', ' ').toUpperCase()} | Date: ${order.dispatchDate}</span>















            </div>















          </div>















          <div class="gift-card-actions" style="pointer-events: auto;">















            ${buttonHTML}















          </div>















        `;































        // Click card body anywhere (except action button) to open details modal















        card.onclick = (e) => {















          if (e.target.tagName !== 'BUTTON') {















            showAppreciationDetails(order.orderId);















          }















        };































        // Bind button click event















        const actionBtn = card.querySelector(`#${btnId}`);















        if (actionBtn) {















          actionBtn.onclick = (e) => {















            e.stopPropagation();















            if (window.currentRole === 'rep') {
              showAppreciationDetails(order.orderId);
            } else if (order.state === 'Awaiting Owner Approval') {















              approveB2BOrderConcept(order.orderId);















            } else if (order.state === 'Finalize') {















              showAppreciationDetails(order.orderId);















            }















          };















        }































        queueList.appendChild(card);















      });















    };































    // Calculate pending count















    let pendingCount = 0;















    let ordersToCount = Object.values(activeB2BOrders);
    if (window.currentRole === 'rep') {
      ordersToCount = ordersToCount.filter(o => recordBelongsToRep(o, window.currentUsername || localStorage.getItem('whitebox_username') || 'Tom Collins'));
    }
    ordersToCount.forEach(o => {















      if (o.state === 'Awaiting Owner Approval') {















        pendingCount++;















      }















    });































    renderList(queueList1);















    renderList(queueList2);































    // Update count badges















    const countBadges = document.querySelectorAll('.automated-queue-panel .active-badge');















    countBadges.forEach(badge => {















      if (window.currentRole === 'rep') {
        badge.textContent = `${pendingCount} Pending Touchpoint${pendingCount !== 1 ? 's' : ''}`;
      } else {
        badge.textContent = `${pendingCount} CEO Approval${pendingCount !== 1 ? 's' : ''} Pending`;
      }















    });































    // Update sidebar Gifting Queue nav badge count















    const giftingBadge = document.querySelector('.sidebar-nav-item[data-tab="gifting"] .nav-badge-info');















    if (giftingBadge) {















      let badgeOrders = Object.values(activeB2BOrders);
      if (window.currentRole === 'rep') {
        badgeOrders = badgeOrders.filter(o => recordBelongsToRep(o, window.currentUsername || localStorage.getItem('whitebox_username') || 'Tom Collins'));
      }
      giftingBadge.textContent = badgeOrders.length;















    }















  }































