  function calculateStartsAtPrice() {















    if (!pricePreviewDisplay) return 90.00;































    const recipientScale = document.querySelector('input[name="recipient_scale"]:checked').value;















    const boxType = document.querySelector('input[name="box_type"]:checked').value;















    















    let packClass = 'essential';















    const packClassInput = document.querySelector('input[name="pack_class"]:checked');















    if (packClassInput) packClass = packClassInput.value;































    let premiumTier = 'premium';















    const premiumTierInput = document.querySelector('input[name="premium_tier"]:checked');















    if (premiumTierInput) premiumTier = premiumTierInput.value;































    if (recipientScale === 'team' || recipientScale === 'office') {















      pricePreviewDisplay.textContent = 'Custom pricing';















      if (pricePreviewSubtext) {















        pricePreviewSubtext.textContent = 'Given this order is for a team/enterprise, the B2B pricing is custom and will be negotiated separately.';















      }















      return 'Custom pricing';















    }































    // Executive single person pricing















    let basePrice = 90.00;















    let description = 'Sweet Box base starting price for single executive dispatches.';















    















    if (boxType === 'sweet') {















      basePrice = 90.00;















      description = 'Sweet Box minimum starting price for single executive dispatches.';















    } else if (boxType === 'pack') {















      if (packClass === 'hero') {















        basePrice = 125.00;















        description = 'Pack Box with Hero Gadget minimum starting price for executive dispatches.';















      } else {















        basePrice = 80.00;















        description = 'Pack Box (Essential Class) minimum starting price for executive dispatches.';















      }















    } else if (boxType === 'premium') {















      if (premiumTier === 'platinum') {















        basePrice = 500.00;















        description = 'Platinum Tier custom box minimum starting price for executive dispatches.';















      } else {















        basePrice = 300.00;















        description = 'Premium Tier custom box minimum starting price for executive dispatches.';















      }















    }































    pricePreviewDisplay.textContent = `Starts at $${basePrice.toFixed(2)}`;















    if (pricePreviewSubtext) {















      pricePreviewSubtext.textContent = description;















    }















    return basePrice;















  }















  window.calculateStartsAtPrice = calculateStartsAtPrice;































  // Bind change listeners to Send a Box form fields for live pricing updates















