  // Recipient autocomplete suggestions logic
  const recipientInput = document.getElementById('recipient_name');
  if (recipientInput) {
    const parentGroup = recipientInput.closest('.form-input-group');
    if (parentGroup) {
      parentGroup.style.position = 'relative';
      const suggestionsContainer = document.createElement('div');
      suggestionsContainer.className = 'autocomplete-suggestions';
      suggestionsContainer.style.display = 'none';
      parentGroup.appendChild(suggestionsContainer);

      recipientInput.addEventListener('input', () => {
        const query = recipientInput.value.toLowerCase().trim();
        suggestionsContainer.innerHTML = '';
        if (!query) {
          suggestionsContainer.style.display = 'none';
          return;
        }

        const businessNames = new Set();
        const categoryMap = {}; // Maps business name to reach/retain

        if (typeof customersData !== 'undefined') {
          customersData.forEach(c => {
            businessNames.add(c.name);
            categoryMap[c.name] = 'retain';
          });
        }
        if (typeof prospectsData !== 'undefined') {
          prospectsData.forEach(p => {
            businessNames.add(p.name);
            categoryMap[p.name] = 'reach';
          });
        }

        const matches = Array.from(businessNames).filter(name => name.toLowerCase().includes(query));
        if (matches.length === 0) {
          suggestionsContainer.style.display = 'none';
          return;
        }

        matches.forEach(name => {
          const suggestionEl = document.createElement('div');
          suggestionEl.className = 'autocomplete-suggestion';
          suggestionEl.textContent = name;
          suggestionEl.addEventListener('click', () => {
            recipientInput.value = name;
            suggestionsContainer.style.display = 'none';
            recipientInput.dispatchEvent(new Event('input', { bubbles: true }));

            // Auto-select category matching the business type
            const matchedCategory = categoryMap[name];
            if (matchedCategory) {
              const categoryRadio = document.querySelector(`input[name="gifting_category"][value="${matchedCategory}"]`);
              if (categoryRadio) {
                document.querySelectorAll('input[name="gifting_category"]').forEach(r => {
                  r.checked = false;
                  const opt = r.closest('.selector-option');
                  if (opt) opt.classList.remove('active');
                });
                categoryRadio.checked = true;
                const opt = categoryRadio.closest('.selector-option');
                if (opt) opt.classList.add('active');
                categoryRadio.dispatchEvent(new Event('change', { bubbles: true }));
              }
            }
          });
          suggestionsContainer.appendChild(suggestionEl);
        });

        suggestionsContainer.style.display = 'block';
      });

      document.addEventListener('click', (e) => {
        if (e.target !== recipientInput && e.target !== suggestionsContainer && !suggestionsContainer.contains(e.target)) {
          suggestionsContainer.style.display = 'none';
        }
      });
    }
  }

