// 10. Directive Tasks (To-Do List) Checkbox Interactive Response















function initTodoDirectives() {















  const checkboxes = document.querySelectorAll('.todo-checkbox');















  checkboxes.forEach(box => {















    box.addEventListener('change', () => {















      const isChecked = box.checked;















      const textEl = box.closest('.todo-item').querySelector('.todo-text');















      const text = textEl ? textEl.textContent.trim() : 'Directive';















      if (isChecked) {















        showDashboardToast(`Directive marked as complete: ${text.substring(0, 30)}...`, '✓');















      }















    });















  });















}































// 11. Registry Tables Inactivity Auto-Sorting















function sortAllRegistryTables() {















  const tableBodies = document.querySelectorAll('.registry-table tbody');















  tableBodies.forEach(tableBody => {















    const rows = Array.from(tableBody.querySelectorAll('.registry-row'));















    if (!rows.length) return;















    















    rows.sort((a, b) => {















      const aText = a.querySelector('.status-days')?.textContent || '';















      const bText = b.querySelector('.status-days')?.textContent || '';















      















      const aDays = parseInt(aText) || 0;















      const bDays = parseInt(bText) || 0;















      















      return bDays - aDays; // Descending sort















    });















    















    rows.forEach(row => {















      tableBody.appendChild(row);















    });















  });















}































