            <span class="todo-custom-box" style="width: 18px; height: 18px; border: 1px solid rgba(59, 130, 246, 0.4); border-radius: 5px; background: rgba(59, 130, 246, 0.15); display: flex; align-items: center; justify-content: center; flex-shrink: 0; margin-top: 2px;"></span>
