function getInactivityStatus(days) {















  if (days >= 60) return 'red';















  if (days >= 30) return 'orange';















  return 'green';















}































function getPerformanceStatus(health) {















  if (health >= 90) return 'high-performer';















  if (health >= 75) return 'moderate-performer';















  return 'underperformer';















}































function updateEmployeesScorecards(dataset) {
  const giftsSentVal = document.getElementById('emp-card-gifts-sent-val');
  const giftsReceivedVal = document.getElementById('emp-card-gifts-received-val');
  const healthVal = document.getElementById('emp-card-health-val');
  const companyHealthVal = document.getElementById('emp-card-company-health-val');

  const card1 = document.querySelector('.kpi-employee-gifts-sent');
  const card2 = document.querySelector('.kpi-employee-gifts-received');
  const card3 = document.querySelector('.kpi-employee-relationship-health');
  const card4 = document.querySelector('.kpi-employee-company-health');

  const role = window.currentRole || 'owner';

  if (role === 'rep' || role === 'manager') {
    const username = window.currentUsername || 'Tom Collins';
    const selfEmp = (typeof employeesData !== 'undefined' ? employeesData : []).find(e => e.name === username);
    const managerName = (role === 'manager') ? username : (selfEmp ? selfEmp.manager : 'Jane Smith');
    const metrics = window.compileTeamConstellationMetrics ? window.compileTeamConstellationMetrics(managerName) : {
      totalProspects: 50,
      totalCustomers: 47,
      conversionRate: 48,
      compiledScore: 85
    };

    // Update Card 1: Total Team Prospects
    if (card1) {
      const label = card1.querySelector('.kpi-label');
      if (label) label.textContent = 'Total Team Prospects';
      const trendCapsule = card1.querySelector('.trend-capsule');
      if (trendCapsule) {
        trendCapsule.innerHTML = `+10% ▲ <span class="basis-text">vs last month</span>`;
        trendCapsule.className = 'trend-capsule positive';
      }
      const indicator = card1.querySelector('.kpi-indicator');
      if (indicator) {
        indicator.setAttribute('data-tooltip', 'Total active prospects across the team.');
        indicator.innerHTML = `Active team prospects. <span class="info-icon">ⓘ</span>`;
        indicator.className = 'kpi-indicator positive tooltip-trigger';
      }
    }
    if (giftsSentVal) {
      giftsSentVal.textContent = metrics.totalProspects;
      giftsSentVal.className = 'kpi-value';
    }

    // Update Card 2: Total Team Customers
    if (card2) {
      const label = card2.querySelector('.kpi-label');
      if (label) label.textContent = 'Total Team Customers';
      const trendCapsule = card2.querySelector('.trend-capsule');
      if (trendCapsule) {
        trendCapsule.innerHTML = `+12% ▲ <span class="basis-text">vs last month</span>`;
        trendCapsule.className = 'trend-capsule positive';
      }
      const indicator = card2.querySelector('.kpi-indicator');
      if (indicator) {
        indicator.setAttribute('data-tooltip', 'Total active B2B customers across the team.');
        indicator.innerHTML = `Active team customers. <span class="info-icon">ⓘ</span>`;
        indicator.className = 'kpi-indicator positive tooltip-trigger';
      }
    }
    if (giftsReceivedVal) {
      giftsReceivedVal.textContent = metrics.totalCustomers;
      giftsReceivedVal.className = 'kpi-value';
    }

    // Update Card 3: Prospect to customer Converted
    if (card3) {
      const label = card3.querySelector('.kpi-label');
      if (label) label.textContent = 'Prospect to customer Converted';
      const trendCapsule = card3.querySelector('.trend-capsule');
      if (trendCapsule) {
        trendCapsule.innerHTML = `+5% ▲ <span class="basis-text">vs last month</span>`;
        trendCapsule.className = 'trend-capsule positive';
      }
      const indicator = card3.querySelector('.kpi-indicator');
      if (indicator) {
        indicator.setAttribute('data-tooltip', 'Percentage of prospects converted to customers across the team.');
        indicator.innerHTML = `Team conversion rate. <span class="info-icon">ⓘ</span>`;
        indicator.className = 'kpi-indicator positive tooltip-trigger';
      }
    }
    if (healthVal) {
      healthVal.textContent = `${metrics.conversionRate}%`;
      healthVal.className = `kpi-value ${metrics.conversionRate >= 45 ? 'text-green' : (metrics.conversionRate >= 35 ? 'text-orange' : 'text-red')}`;
    }

    // Update Card 4: Team Health
    if (card4) {
      const label = card4.querySelector('.kpi-label');
      if (label) label.textContent = 'Team Health';
      const trendCapsule = card4.querySelector('.trend-capsule');
      if (trendCapsule) {
        trendCapsule.innerHTML = `85% Score <span class="basis-text">vs last quarter</span>`;
        trendCapsule.className = 'trend-capsule positive';
      }
      const indicator = card4.querySelector('.kpi-indicator');
      if (indicator) {
        indicator.setAttribute('data-tooltip', 'Average compiled team health score.');
        indicator.innerHTML = `Compiled team score. <span class="info-icon">ⓘ</span>`;
        indicator.className = 'kpi-indicator positive tooltip-trigger';
      }
    }
    if (companyHealthVal) {
      companyHealthVal.textContent = `${metrics.compiledScore}%`;
      companyHealthVal.className = `kpi-value ${metrics.compiledScore >= 80 ? 'text-green' : (metrics.compiledScore >= 70 ? 'text-orange' : 'text-red')}`;
    }
    return;
  }

  if (!dataset.length) {
    if (giftsSentVal) giftsSentVal.textContent = '0';
    if (giftsReceivedVal) giftsReceivedVal.textContent = '0';
    if (healthVal) healthVal.textContent = '0%';
    if (companyHealthVal) companyHealthVal.textContent = '0%';
    return;
  }

  const total = dataset.length;
  const avgHealth = Math.round(dataset.reduce((acc, emp) => acc + emp.health, 0) / total);
  const giftsSent = dataset.reduce((acc, emp) => acc + (emp.gifts || 0), 0);
  const giftsReceived = dataset.reduce((acc, emp) => acc + (emp.giftsReceived || 0), 0);
  const companyHealth = Math.min(99, Math.round(avgHealth * 1.02 || 94));

  // Restore defaults
  if (card1) {
    const label = card1.querySelector('.kpi-label');
    if (label) label.textContent = 'Gifts Sent';
    const trendCapsule = card1.querySelector('.trend-capsule');
    if (trendCapsule) {
      trendCapsule.innerHTML = `+12% ▲ <span class="basis-text">vs last month</span>`;
      trendCapsule.className = 'trend-capsule positive';
    }
    const indicator = card1.querySelector('.kpi-indicator');
    if (indicator) {
      indicator.setAttribute('data-tooltip', 'Total appreciation gifts sent by your employees.');
      indicator.innerHTML = `Gifts successfully sent. <span class="info-icon">ⓘ</span>`;
      indicator.className = 'kpi-indicator positive tooltip-trigger';
    }
  }
  if (giftsSentVal) {
    giftsSentVal.textContent = giftsSent;
    giftsSentVal.className = 'kpi-value';
  }

  if (card2) {
    const label = card2.querySelector('.kpi-label');
    if (label) label.textContent = 'Gifts Received';
    const trendCapsule = card2.querySelector('.trend-capsule');
    if (trendCapsule) {
      trendCapsule.innerHTML = `+8% ▲ <span class="basis-text">vs last month</span>`;
      trendCapsule.className = 'trend-capsule positive';
    }
    const indicator = card2.querySelector('.kpi-indicator');
    if (indicator) {
      indicator.setAttribute('data-tooltip', 'Total employee appreciation gifts received by team members.');
      indicator.innerHTML = `Gifts successfully received. <span class="info-icon">ⓘ</span>`;
      indicator.className = 'kpi-indicator positive tooltip-trigger';
    }
  }
  if (giftsReceivedVal) {
    giftsReceivedVal.textContent = giftsReceived;
    giftsReceivedVal.className = 'kpi-value';
  }

  if (card3) {
    const label = card3.querySelector('.kpi-label');
    if (label) label.textContent = 'Relationship Health';
    const trendCapsule = card3.querySelector('.trend-capsule');
    if (trendCapsule) {
      trendCapsule.innerHTML = `+6% ▲ <span class="basis-text">vs last week</span>`;
      trendCapsule.className = 'trend-capsule positive';
    }
    const indicator = card3.querySelector('.kpi-indicator');
    if (indicator) {
      indicator.setAttribute('data-tooltip', 'Graded based on how consistently your team is in contact with prospects, customers, and each other.');
      indicator.innerHTML = `Combined team touchpoint health average. <span class="info-icon">ⓘ</span>`;
      indicator.className = 'kpi-indicator positive tooltip-trigger';
    }
  }
  if (healthVal) {
    healthVal.textContent = `${avgHealth}%`;
    healthVal.className = `kpi-value ${avgHealth >= 90 ? 'text-green' : (avgHealth >= 75 ? 'text-orange' : 'text-red')}`;
  }

  if (card4) {
    const label = card4.querySelector('.kpi-label');
    if (label) label.textContent = 'Company Health';
    const trendCapsule = card4.querySelector('.trend-capsule');
    if (trendCapsule) {
      trendCapsule.innerHTML = `Excellent ▲ <span class="basis-text">vs last quarter</span>`;
      trendCapsule.className = 'trend-capsule positive';
    }
    const indicator = card4.querySelector('.kpi-indicator');
    if (indicator) {
      indicator.setAttribute('data-tooltip', 'Overall operational and corporate relationship performance index.');
      indicator.innerHTML = `Overall operational status index. <span class="info-icon">ⓘ</span>`;
      indicator.className = 'kpi-indicator positive tooltip-trigger';
    }
  }
  if (companyHealthVal) {
    companyHealthVal.textContent = `${companyHealth}%`;
    companyHealthVal.className = `kpi-value ${companyHealth >= 90 ? 'text-green' : (companyHealth >= 75 ? 'text-orange' : 'text-red')}`;
  }
};































function populateMilestones(name, type) {















  const container = document.getElementById('detail-employee-dates-list');















  const cardTitle = document.querySelector('#detail-employee-dates-card .milestones-card-title');















  if (!container) return;































  // Determine database and default milestones based on type















  let db = employeeMilestonesDB;















  let title = "Key Employee Milestones & Celebrations";















  let defaultMilestones = [















    { type: "birthday", name: "Employee Birthday", date: "June 25, 2026", countdown: "In 29 Days", countdownClass: "normal" },















    { type: "renewal", name: "Contract Renewal Review", date: "July 31, 2026", countdown: "In 65 Days", countdownClass: "normal" }















  ];































  if (type === 'customer') {















    db = customerMilestonesDB;















    title = "Key Customer Milestones & Celebrations";















    defaultMilestones = [















      { type: "anniversary", name: "Partnership Anniversary", date: "June 15, 2026", countdown: "In 19 Days", countdownClass: "soon" },















      { type: "birthday", name: "CEO's Birthday", date: "June 28, 2026", countdown: "In 32 Days", countdownClass: "normal" }















    ];















  } else if (type === 'prospect') {















    db = prospectMilestonesDB;















    title = "Key Prospect Milestones & Celebrations";















    defaultMilestones = [















      { type: "renewal", name: "Proposal Presentation Review", date: "June 10, 2026", countdown: "In 14 Days", countdownClass: "urgent" },















      { type: "anniversary", name: "Discovery Meeting Anniversary", date: "June 22, 2026", countdown: "In 26 Days", countdownClass: "soon" }















    ];















  }































  // Update card title















  if (cardTitle) cardTitle.textContent = title;































  const milestones = db[name] || defaultMilestones;































  container.innerHTML = milestones.map(m => {















    let icon = "🎂";















    if (m.type === "renewal") icon = "📄";















    else if (m.type === "anniversary") icon = "🎖️";































    return `















      <div class="milestone-row" style="animation: dropdownFadeIn 0.3s ease;">















        <div class="milestone-left">















          <div class="milestone-icon-badge ${m.type}">${icon}</div>















          <div class="milestone-info">















            <div class="milestone-name-row">















              <span class="milestone-name">${m.name}</span>















              <span class="milestone-countdown ${m.countdownClass}">${m.countdown}</span>















            </div>















            <span class="milestone-date">${m.date}</span>















          </div>















        </div>















        <button class="milestone-gift-btn" data-milestone="${m.name}" data-target-name="${name}" data-date="${m.date}">















          🎁 Send Gift















        </button>















      </div>















    `;















  }).join('');















}































function populateEmployeeMilestones(name) {















  populateMilestones(name, 'employee');















}































































function renderCalendarEvents(name, type, scheduleType = 'send') {















  console.log("renderCalendarEvents called", { name, type, scheduleType });















  const calendarCard = document.getElementById('detail-gifting-calendar-card');















  if (!calendarCard) {















    console.log("renderCalendarEvents aborted: detail-gifting-calendar-card not found");















    return;















  }















  















  if (window.currentCalendarMonth === undefined) {















    window.currentCalendarMonth = 5; // Default June















  }















  if (window.currentCalendarYear === undefined) {















    window.currentCalendarYear = 2026; // Default 2026















  }































  const toggleContainer = document.getElementById('calendar-schedule-toggle');















  const contextTag = document.getElementById('calendar-context-tag');















  const eventsList = document.getElementById('calendar-events-list');















  const daysGrid = document.getElementById('calendar-days-grid');















  const monthDisplay = document.getElementById('calendar-month-year-display');















  console.log("renderCalendarEvents DOM elements:", { toggleContainer, contextTag, eventsList, daysGrid, monthDisplay });















  















  if (type === 'employee') {















    if (toggleContainer) toggleContainer.style.display = 'flex';















    if (contextTag) contextTag.textContent = scheduleType === 'send' ? 'Sending Schedule' : 'Receiving Schedule';















    















    // Style toggle buttons color-coded















    const sendBtn = toggleContainer ? toggleContainer.querySelector('[data-schedule="send"]') : null;















    const receiveBtn = toggleContainer ? toggleContainer.querySelector('[data-schedule="receive"]') : null;















    if (sendBtn && receiveBtn) {















      sendBtn.className = 'cal-toggle-btn' + (scheduleType === 'send' ? ' active' : '');















      receiveBtn.className = 'cal-toggle-btn' + (scheduleType === 'receive' ? ' receive-active' : '');















    }















  } else {















    if (toggleContainer) toggleContainer.style.display = 'none';















    if (contextTag) contextTag.textContent = 'Sending Schedule';















    scheduleType = 'send'; // Force clients to send schedule only















  }















  















  // Re-bind Month toggles Previous / Next click listeners once















  const prevBtn = document.querySelector('.prev-month-btn');















  const nextBtn = document.querySelector('.next-month-btn');















  if (prevBtn && nextBtn) {















    const newPrevBtn = prevBtn.cloneNode(true);















    const newNextBtn = nextBtn.cloneNode(true);















    prevBtn.parentNode.replaceChild(newPrevBtn, prevBtn);















    nextBtn.parentNode.replaceChild(newNextBtn, nextBtn);















    















    newPrevBtn.addEventListener('click', (e) => {















      e.preventDefault();















      e.stopPropagation();















      window.currentCalendarMonth--;















      if (window.currentCalendarMonth < 0) {















        window.currentCalendarMonth = 11;















        window.currentCalendarYear--;















      }















      renderCalendarEvents(name, type, scheduleType);















    });















    















    newNextBtn.addEventListener('click', (e) => {















      e.preventDefault();















      e.stopPropagation();















      window.currentCalendarMonth++;















      if (window.currentCalendarMonth > 11) {















        window.currentCalendarMonth = 0;















        window.currentCalendarYear++;















      }















      renderCalendarEvents(name, type, scheduleType);















    });















  }































  // Update Month Header text















  const monthNames = ["January", "February", "March", "April", "May", "June", "July", "August", "September", "October", "November", "December"];















  if (monthDisplay) {















    monthDisplay.textContent = `${monthNames[window.currentCalendarMonth]} ${window.currentCalendarYear}`;















  }































  // Retrieve events from database if it's the target month (June 2026)















  // To keep it clean, all predefined events are for June 2026.















  const isTargetMonth = (window.currentCalendarMonth === 5 && window.currentCalendarYear === 2026);















  const clientEvents = calendarEventsDB[name] || {};















  const sendEvents = isTargetMonth ? (clientEvents.send || []) : [];















  const receiveEvents = isTargetMonth ? (clientEvents.receive || []) : [];















  















  // Dynamic day cell grid generation















  if (daysGrid) {















    daysGrid.innerHTML = `















      <span class="day-label">M</span>















      <span class="day-label">T</span>















      <span class="day-label">W</span>















      <span class="day-label">T</span>















      <span class="day-label">F</span>















      <span class="day-label">S</span>















      <span class="day-label">S</span>















    `;















    















    const firstDayDate = new Date(window.currentCalendarYear, window.currentCalendarMonth, 1);















    const startDay = firstDayDate.getDay();















    const startingIndex = startDay === 0 ? 6 : startDay - 1; // Monday start















    const daysInMonth = new Date(window.currentCalendarYear, window.currentCalendarMonth + 1, 0).getDate();















    















    // Add spacer empty days















    for (let i = 0; i < startingIndex; i++) {















      const emptyCell = document.createElement('div');















      emptyCell.className = 'cal-day empty-day';















      daysGrid.appendChild(emptyCell);















    }















    















    // Add real days with events scanner















    for (let d = 1; d <= daysInMonth; d++) {















      const dayCell = document.createElement('div');















      dayCell.className = 'cal-day';















      dayCell.setAttribute('data-day', d);















      dayCell.textContent = d;















      















      const daySend = sendEvents.filter(e => e.day === d);















      const dayReceive = receiveEvents.filter(e => e.day === d);















      















      let hasSend = daySend.length > 0;















      let hasReceive = dayReceive.length > 0;















      















      if (type === 'employee') {















        if (hasSend && hasReceive) {















          dayCell.classList.add('has-event-both');















        } else if (hasSend) {















          dayCell.classList.add('has-event');















        } else if (hasReceive) {















          dayCell.classList.add('has-event-receive');















        }















        















        if (hasSend || hasReceive) {















          const dotsContainer = document.createElement('div');















          dotsContainer.className = 'day-dots-container';















          if (hasSend) {















            const dot = document.createElement('span');















            dot.className = 'dot-send';















            dotsContainer.appendChild(dot);















          }















          if (hasReceive) {















            const hasRecGift = dayReceive.some(e => e.box && e.box.toLowerCase().includes('box'));















            const hasRecMeeting = dayReceive.some(e => !e.box || !e.box.toLowerCase().includes('box'));































            if (hasRecGift) {















              const dot = document.createElement('span');















              dot.className = 'dot-receive';















              dotsContainer.appendChild(dot);















            }















            if (hasRecMeeting) {















              const dot = document.createElement('span');















              dot.className = 'dot-orange';















              dotsContainer.appendChild(dot);















            }















          }















          dayCell.appendChild(dotsContainer);















        }















      } else {















        if (hasSend) {















          dayCell.classList.add('has-event');















          const dotsContainer = document.createElement('div');















          dotsContainer.className = 'day-dots-container';















          const dot = document.createElement('span');















          dot.className = 'dot-send';















          dotsContainer.appendChild(dot);















          dayCell.appendChild(dotsContainer);















        }















      }















      















      daysGrid.appendChild(dayCell);















    }















  }































  // Inner function to list events below the calendar















  function renderList(filteredDay = null) {















    let listEvents = [];















    if (type === 'employee') {















      if (filteredDay) {















        // If a specific day is clicked, show both sending and receiving events together















        const daySend = sendEvents.filter(e => e.day === filteredDay).map(e => ({ ...e, isSend: true }));















        const dayReceive = receiveEvents.filter(e => e.day === filteredDay).map(e => ({ ...e, isSend: false }));















        listEvents = [...daySend, ...dayReceive];















      } else {















        // Otherwise, filter based on active toggle tab















        listEvents = scheduleType === 'send'















          ? sendEvents.map(e => ({ ...e, isSend: true }))















          : receiveEvents.map(e => ({ ...e, isSend: false }));















      }















    } else {















      listEvents = filteredDay















        ? sendEvents.filter(e => e.day === filteredDay).map(e => ({ ...e, isSend: true }))















        : sendEvents.map(e => ({ ...e, isSend: true }));















    }















      















    if (!listEvents.length) {















      const monthText = monthNames[window.currentCalendarMonth];















      const labelText = type === 'employee' ? 'gifts or B2B meetings' : 'gifts';















      eventsList.innerHTML = `















        <div style="text-align: center; color: #64748b; font-size: 11px; padding: 20px 0; font-family: 'Inter', sans-serif;">















          No scheduled ${labelText} ${filteredDay ? `on ${monthText} ${filteredDay}` : `for ${monthText} ${window.currentCalendarYear}`}.















        </div>















      `;















      return;















    }















    















    eventsList.innerHTML = listEvents.map(ev => {















      const statusText = ev.status || 'scheduled';















      const isSendEvent = ev.isSend;















      const relationText = isSendEvent















        ? `To: <strong>${ev.recipient}</strong>`















        : `From: <strong>${ev.sender}</strong>`;















        















      let boxClass = 'cal-event-box';















      let badgeClass = 'cal-event-status';















      let displayStatus = statusText;































      const isGiftBox = ev.box && ev.box.toLowerCase().includes('box');































      if (isGiftBox) {















        if (isSendEvent) {















          // Sent gifts: Green title & Green status pill















          boxClass = 'cal-event-box green-text-plain';















          badgeClass = 'cal-event-status green-badge';















          displayStatus = 'scheduled';















        } else {















          // Received gifts: Purple title & Purple status pill















          boxClass = 'cal-event-box purple-text-plain';















          badgeClass = 'cal-event-status purple-badge';















          displayStatus = 'received';















        }















      } else {















        // Scheduled B2B Meetings / Performance Reviews: Orange title & Orange status pill















        boxClass = 'cal-event-box orange-text-plain';















        badgeClass = 'cal-event-status orange-badge';















        displayStatus = 'scheduled';















      }















        















      return `















        <div class="cal-event-item" style="animation: dropdownFadeIn 0.3s ease;">















          <div class="cal-event-meta">















            <span class="cal-event-date">${ev.date}</span>















            <span class="${badgeClass}">${displayStatus}</span>















          </div>















          <div class="${boxClass}">${ev.box}</div>















          <div class="cal-event-reason">















            ${relationText}<br>















            Why: ${ev.reason}















          </div>















        </div>















      `;















    }).join('');















  }















  















  // Render list initially















  renderList();















  















  // Re-bind click event handlers for active day cell elements















  const dayElements = document.querySelectorAll('#calendar-days-grid .cal-day');















  dayElements.forEach(dayEl => {















    dayEl.addEventListener('click', (e) => {















      const dayNum = parseInt(dayEl.getAttribute('data-day'));















      if (!dayNum) return;















      















      if (dayEl.classList.contains('active-day')) {















        dayEl.classList.remove('active-day');















        renderList();















      } else {















        document.querySelectorAll('#calendar-days-grid .cal-day').forEach(d => d.classList.remove('active-day'));















        dayEl.classList.add('active-day');















        renderList(dayNum);















      }















    });















  });















}































function bindDynamicNodeClicks(selector) {















  const nodes = document.querySelectorAll(selector);















  const detailWrapper = document.getElementById('view-relationship-detail');















  const backBtn = document.getElementById('btn-back-to-workspace');















  const wrappers = document.querySelectorAll('.dashboard-canvas .dashboard-view-wrapper');















  















  const detailName = document.getElementById('detail-name');















  const detailCategory = document.getElementById('detail-category-tag');















  const detailSector = document.getElementById('detail-sector-tag');















  const detailAddress = document.getElementById('detail-address');















  const detailPhone = document.getElementById('detail-phone');















  const detailEmail = document.getElementById('detail-email');















  const detailRep = document.getElementById('detail-rep-name');















  const detailGlowDot = document.getElementById('detail-glow-dot');















  const detailStatusText = document.getElementById('detail-status-text');















  const detailHealthScore = document.getElementById('detail-health-score');















  const detailHealthFill = document.getElementById('detail-health-fill');















  const detailCalls = document.getElementById('detail-calls-count');















  const detailGifts = document.getElementById('detail-gifts-count');















  const detailAiRec = document.getElementById('detail-ai-recommendation');















  const detailTimelineList = document.getElementById('detail-timeline-list');































  nodes.forEach(node => {















    node.style.cursor = 'pointer';















    node.style.textDecoration = 'underline';















    node.style.textDecorationStyle = 'dotted';















    















    node.addEventListener('click', (e) => {
      if (typeof window.cancelContactEdit === 'function') {
        window.cancelContactEdit();
      }















      e.preventDefault();















      e.stopPropagation();















      















      const name = (node.getAttribute('data-name') || (node.getAttribute('data-type') === 'employee' ? node.getAttribute('data-contact') : null) || node.textContent.trim()).trim();
      if (name && name.endsWith("'s Team")) {
        if (typeof window.showTeamProfileDetail === 'function') {
          window.showTeamProfileDetail(name);
          return;
        }
      }















      const type = node.getAttribute('data-type') || 'customer';
      const editContactBtn = document.getElementById('btn-edit-contact');
      if (editContactBtn) {
        const lowerType = type.toLowerCase();
        if (lowerType === 'customer' || lowerType === 'prospect') {
          editContactBtn.style.display = 'inline-block';
        } else {
          editContactBtn.style.display = 'none';
        }
      }















      















      window.activeProfileName = name;















      window.activeProfileType = type;
      if (typeof window.checkProfileRestriction === 'function') { window.checkProfileRestriction(name, type); }















      try { hydrateRelationshipAuditBanner(name); } catch(err) {}















      















      const sectorToggle = document.getElementById('graph-sector-toggle');















      const timeToggle = document.getElementById('graph-time-toggle');















      















      const datesCard = document.getElementById('detail-employee-dates-card');















      if (datesCard) {















        datesCard.style.display = 'block';















        populateMilestones(name, type);















      }































      if (type === 'employee') {















        if (sectorToggle) sectorToggle.style.display = 'flex';















        window.activeGraphSector = 'prospects';















        window.activeGraphTimeframe = 'last5';















        















        if (sectorToggle) {















          sectorToggle.querySelectorAll('.sector-toggle-btn').forEach(btn => {















            if (btn.getAttribute('data-sector') === 'prospects') btn.classList.add('active');















            else btn.classList.remove('active');















          });















        }















      } else {















        if (sectorToggle) sectorToggle.style.display = 'none';















        window.activeGraphSector = (type === 'prospect') ? 'prospects' : 'customers';















        window.activeGraphTimeframe = 'last5';















      }















      















      if (timeToggle) {















        timeToggle.querySelectorAll('.time-toggle-btn').forEach(btn => {















          if (btn.getAttribute('data-time') === 'last5') btn.classList.add('active');















          else btn.classList.remove('active');















        });















      }















      















      let address = node.getAttribute('data-address');
      let phone = node.getAttribute('data-phone');
      let email = node.getAttribute('data-email');
      let rep = node.getAttribute('data-rep');

      if (type === 'prospect') {
        const item = (typeof prospectsData !== 'undefined' ? prospectsData : []).find(p => p.name === name);
        if (item) {
          if (!address || address === 'undefined') address = item.streetAddress;
          if (!phone || phone === 'undefined') phone = item.phone;
          if (!email || email === 'undefined') email = item.email;
          if (!rep || rep === 'undefined') rep = item.rep;
        }
      } else if (type === 'customer') {
        const item = (typeof customersData !== 'undefined' ? customersData : []).find(c => c.name === name);
        if (item) {
          if (!address || address === 'undefined') address = item.streetAddress;
          if (!phone || phone === 'undefined') phone = item.phone;
          if (!email || email === 'undefined') email = item.email;
          if (!rep || rep === 'undefined') rep = item.rep;
        }
      } else if (type === 'employee') {
        const item = (typeof employeesData !== 'undefined' ? employeesData : []).find(e => e.name === name);
        if (item) {
          if (!address || address === 'undefined') address = item.streetAddress;
          if (!phone || phone === 'undefined') phone = item.phone;
          if (!email || email === 'undefined') email = item.email;
          if (!rep || rep === 'undefined') rep = item.manager;
        }
      }

      if (!address || address === 'undefined') address = '500 Logistics Way';
      if (!phone || phone === 'undefined') phone = '(800) 555-0199';
      if (!email || email === 'undefined') email = 'contact@whitebox.com';
      if (!rep || rep === 'undefined') rep = 'Tom Collins';

      const daysAsCustomerWrapper = document.getElementById('metadata-item-days-as-customer');
      if (daysAsCustomerWrapper) {
        if (type === 'employee') {
          daysAsCustomerWrapper.style.display = 'none';
        } else {
          daysAsCustomerWrapper.style.display = 'flex';
        }
      }















      const health = node.getAttribute('data-health') || '84%';















      const calls = node.getAttribute('data-calls') || '3 logged calls';















      const gifts = node.getAttribute('data-gifts') || '1 dispatched';















      const ai = node.getAttribute('data-ai') || 'Trigger Appreciations Box';















      















      const contact = node.getAttribute('data-contact') || 'Sarah Jenkins';















      const city = node.getAttribute('data-city') || 'Houston';















      const province = node.getAttribute('data-province') || 'TX';















      const postal = node.getAttribute('data-postal') || '77002';















      let prospect = node.getAttribute('data-prospect');
      let customer = node.getAttribute('data-customer');

      if (type.toLowerCase() === 'employee') {
        const item = (typeof employeesData !== 'undefined' ? employeesData : []).find(e => e.name === name);
        const pCount = (typeof prospectsData !== 'undefined' ? prospectsData : []).filter(p => p.rep === name).length;
        const cCount = (typeof customersData !== 'undefined' ? customersData : []).filter(c => c.rep === name).length;
        prospect = pCount || (item ? (item.prospects || 0) : 0);
        customer = cCount || (item ? (item.customers || 0) : 0);
      }

      if (!prospect || prospect === 'undefined') prospect = 'No';
      if (!customer || customer === 'undefined') customer = 'Yes';















      















      const row = node.closest('.registry-row');















      const sectorEl = row ? row.querySelector('.client-sector') : null;















      let sector = sectorEl ? sectorEl.textContent.trim() : 'B2B Sector';















      // Clean sector string if it contains extra category indicators















      sector = sector.replace(/\s*\(Customer\)/i, '').replace(/\s*\(Prospect\)/i, '').replace(/\s*\(Employee\)/i, '');















      















      if (detailName) detailName.textContent = name;

      const daysInSystemEl = document.getElementById('detail-days-in-system');
      const daysAsCustomerEl = document.getElementById('detail-days-as-customer');

      if (daysInSystemEl) {
        let startDateStr = null;
        if (type === 'prospect') {
          const prospItem = (typeof prospectsData !== 'undefined' ? prospectsData : []).find(p => p.name === name);
          startDateStr = (prospItem && prospItem.prospect && prospItem.prospect !== 'N/A') ? prospItem.prospect : node.getAttribute('data-prospect');
        } else if (type === 'customer') {
          const custItem = (typeof customersData !== 'undefined' ? customersData : []).find(c => c.name === name);
          // For customers, the day they were added to the system is their prospect date!
          startDateStr = (custItem && custItem.prospect && custItem.prospect !== 'N/A') ? custItem.prospect : node.getAttribute('data-prospect');
        } else if (type === 'employee') {
          const empItem = (typeof employeesData !== 'undefined' ? employeesData : []).find(e => e.name === name);
          startDateStr = (empItem && empItem.date) ? empItem.date : node.getAttribute('data-date');
        }

        let daysDiff = 0;
        let valid = false;
        if (startDateStr && startDateStr !== 'N/A' && startDateStr !== 'Yes' && startDateStr !== 'No' && !startDateStr.includes('/')) {
          const start = new Date(startDateStr);
          if (!isNaN(start.getTime())) {
            const todayDate = new Date();
            const diffTime = todayDate.getTime() - start.getTime();
            daysDiff = Math.max(0, Math.floor(diffTime / (1000 * 60 * 60 * 24)));
            valid = true;
          }
        }
        daysInSystemEl.textContent = valid ? `⏱️ ${daysDiff} Days` : `-`;
      }

      if (daysAsCustomerEl) {
        let convertedDateStr = null;
        if (type === 'customer') {
          const custItem = (typeof customersData !== 'undefined' ? customersData : []).find(c => c.name === name);
          convertedDateStr = (custItem && custItem.customer && custItem.customer !== 'N/A') ? custItem.customer : node.getAttribute('data-customer');
        }

        let daysDiff = 0;
        let valid = false;
        if (convertedDateStr && convertedDateStr !== 'N/A' && convertedDateStr !== 'Yes' && convertedDateStr !== 'No' && !convertedDateStr.includes('/')) {
          const start = new Date(convertedDateStr);
          if (!isNaN(start.getTime())) {
            const todayDate = new Date();
            const diffTime = todayDate.getTime() - start.getTime();
            daysDiff = Math.max(0, Math.floor(diffTime / (1000 * 60 * 60 * 24)));
            valid = true;
          }
        }
        daysAsCustomerEl.textContent = valid ? `⏱️ ${daysDiff} Days` : `-`;
      }















      if (detailCategory) {















        detailCategory.textContent = type.toUpperCase();















        detailCategory.className = 'banner-tag';















        if (type === 'employee') detailCategory.classList.add('info-tag');















        else if (type === 'prospect') detailCategory.classList.add('alert-tag');















      }















      















      const detailSectorBannerVal = document.getElementById('detail-sector-banner-val');















      if (detailSectorBannerVal) detailSectorBannerVal.textContent = sector;















      















      const detailContactTag = document.getElementById('detail-contact-tag');















      if (detailContactTag) detailContactTag.textContent = contact;















      















      if (detailAddress) detailAddress.textContent = address;















      if (detailPhone) detailPhone.textContent = phone;















      if (detailEmail) detailEmail.textContent = email;















      if (detailRep) detailRep.textContent = type === 'employee' ? `Primary Manager: ${rep}` : `Assigned Rep: ${rep}`;















      















      const repSelect = document.getElementById('detail-rep-select');















      const isOnBoard = window.recoveryBoardClients && window.recoveryBoardClients.includes(name);















      















      if (repSelect) {















        if (type === 'employee') {















          repSelect.style.display = 'none';















          if (detailRep) detailRep.style.display = 'inline-block';















        } else if (isOnBoard) {















          // ONLY show representative selection dropdown if relationship is on the Recovery Board















          repSelect.style.display = 'inline-block';















          if (detailRep) detailRep.style.display = 'none';















          repSelect.value = rep;















        } else {















          // Otherwise hide selection dropdown and show static rep label















          repSelect.style.display = 'none';















          if (detailRep) detailRep.style.display = 'inline-block';















        }















      }















      















      const ctaPanel = document.getElementById('detail-claim-cta-panel');















      const claimBtnTop = document.getElementById('btn-claim-relationship');















      















      if (ctaPanel) {















        if (isOnBoard && type !== 'employee' && (window.currentRole === 'owner' || window.activeUserRole === 'owner')) {















          ctaPanel.style.display = 'flex';















        } else {















          ctaPanel.style.display = 'none';















        }















      }















      if (claimBtnTop) {















        if (isOnBoard && type !== 'employee' && (window.currentRole === 'owner' || window.activeUserRole === 'owner')) {















          claimBtnTop.style.display = 'inline-block';















        } else {















          claimBtnTop.style.display = 'none';















        }















      }















      















      // 5 New metadata fields















      const detailProspectTag = document.getElementById('detail-prospect-tag');















      const detailCustomerTag = document.getElementById('detail-customer-tag');















      const detailCityTag = document.getElementById('detail-city-tag');















      const detailProvinceTag = document.getElementById('detail-province-tag');















      const detailPostalTag = document.getElementById('detail-postal-tag');















      















      if (detailProspectTag) detailProspectTag.textContent = prospect;















      if (detailCustomerTag) detailCustomerTag.textContent = customer;















      if (detailCityTag) detailCityTag.textContent = city;















      if (detailProvinceTag) detailProvinceTag.textContent = province;















      if (detailPostalTag) detailPostalTag.textContent = postal;















      















      const statusText = row ? row.querySelector('.status-days') : null;















      const statusDays = statusText ? statusText.textContent.trim() : '0 Days Inactive';















      const statusClass = row ? row.getAttribute('data-status') : 'green';















      















      if (detailGlowDot) {















        detailGlowDot.className = `detail-glow-dot-large dot-${statusClass}`;















      }















      















      const statusTextVal = document.getElementById('detail-status-text-val');















      if (statusTextVal) {















        statusTextVal.className = `kpi-value ${statusClass}-text`;















        statusTextVal.textContent = statusDays.replace(/Inactive/gi, 'Ago');















      }















      















      const healthScoreInt = parseInt(health) || 90;















      if (detailHealthScore) detailHealthScore.textContent = `${healthScoreInt}%`;















      if (detailHealthFill) {















        const strokeDashOffset = 251.2 * (1 - healthScoreInt / 100);















        detailHealthFill.style.strokeDashoffset = strokeDashOffset;















        if (healthScoreInt >= 80) detailHealthFill.style.stroke = '#10b981';















        else if (healthScoreInt >= 60) detailHealthFill.style.stroke = '#f59e0b';















        else detailHealthFill.style.stroke = '#ef4444';















      }















      















      let actualTouchesSecond = (type === 'employee') ? window.getEmployeeTouchpointsCount(name) : getClientHistory(name).length;
    if (detailCalls) detailCalls.textContent = actualTouchesSecond;
    const localCallsCountVal = document.getElementById('detail-calls-count-val');
    if (localCallsCountVal) localCallsCountVal.textContent = actualTouchesSecond;
    if (detailGifts) detailGifts.textContent = gifts;















      if (detailAiRec) {















        detailAiRec.textContent = ai;















        if (statusClass === 'red') detailAiRec.style.color = '#ef4444';















        else if (statusClass === 'orange') detailAiRec.style.color = '#f59e0b';















        else detailAiRec.style.color = '#3b82f6';















      }















      















      const touchesPerMonthVal = document.getElementById('detail-touches-per-month-val');















      if (touchesPerMonthVal) {















        const touchCount = parseInt(calls) || 0;















        touchesPerMonthVal.textContent = (touchCount / 3).toFixed(1) + ' / mo';















      }















      















      if (detailTimelineList) {















        // Render dynamic database-driven timeline and SVG graph















        renderTimeline(name);















        renderDashboardGraph(name);















      }















      















      // Reset calendar view variables when clicking a node details view to June 2026















      window.currentCalendarMonth = 5; // June















      window.currentCalendarYear = 2026;















      















      // Book a Meeting button click handler















      const bookBtn = document.getElementById('btn-book-employee-meeting');















      if (bookBtn) {















        if (type === 'employee') {















          bookBtn.style.display = 'inline-block';















          bookBtn.onclick = (event) => {















            event.preventDefault();















            event.stopPropagation();















            















            if (typeof window.openExecutiveSchedulerModal === 'function') {















              window.openExecutiveSchedulerModal();















            } else {















              const schedulerModal = document.getElementById('executive-scheduler-modal');















              if (schedulerModal) {















                schedulerModal.style.display = 'flex';















                schedulerModal.classList.add('active');















              }















            }















            















            const targetInput = document.getElementById('scheduler-event-target');















            if (targetInput) targetInput.value = name;















            















            const typeInput = document.getElementById('scheduler-event-type');















            if (typeInput) typeInput.value = "Performance Review";















          };















        } else {















          bookBtn.style.display = 'none';















        }















      }































      // Send a Gift button click handler















      const sendGiftBtn = document.getElementById('btn-send-client-gift');















      if (sendGiftBtn) {















        if (type === 'customer' || type === 'prospect') {















          sendGiftBtn.style.display = 'inline-block';















          sendGiftBtn.onclick = (event) => {















            event.preventDefault();















            event.stopPropagation();















            if (typeof window.openGiftingModalFor === 'function') {















              window.openGiftingModalFor(name);















            }















          };















        } else {















          sendGiftBtn.style.display = 'none';















        }















      }































      // Convert to Customer button click handler















      const convertBtn = document.getElementById('btn-convert-relationship');















      if (convertBtn) {















        if (type === 'prospect') {















          convertBtn.style.display = 'inline-block';















          convertBtn.onclick = (event) => {















            event.preventDefault();















            event.stopPropagation();















            if (typeof window.convertProspectToCustomer === 'function') {















              window.convertProspectToCustomer(name);















            }















          };















        } else {















          convertBtn.style.display = 'none';















        }















      }































      // Dynamic Gifting Calendar Trigger















      window.activeScheduleType = 'send';















      renderCalendarEvents(name, type, window.activeScheduleType);















      















      const calToggles = document.querySelectorAll('#calendar-schedule-toggle .cal-toggle-btn');















      calToggles.forEach(btn => {















        const newBtn = btn.cloneNode(true);















        btn.parentNode.replaceChild(newBtn, btn);















        















        newBtn.addEventListener('click', (e) => {















          e.preventDefault();















          e.stopPropagation();















          















          document.querySelectorAll('#calendar-schedule-toggle .cal-toggle-btn').forEach(b => b.classList.remove('active'));















          newBtn.classList.add('active');















          















          window.activeScheduleType = newBtn.getAttribute('data-schedule');















          renderCalendarEvents(name, type, window.activeScheduleType);















        });















      });















      document.querySelectorAll('#calendar-schedule-toggle .cal-toggle-btn').forEach(b => {















        if (b.getAttribute('data-schedule') === 'send') b.classList.add('active');















        else b.classList.remove('active');















      });































      















      // Keep sidebar visible as requested by the user















      document.body.classList.remove('sidebar-collapsed');















      if (backBtn) backBtn.style.display = 'inline-flex';















      















      if (typeof window.hydrateProfileGiftingAnalytics === 'function') {



        window.hydrateProfileGiftingAnalytics(name);



      }



      if (typeof window.hydrateProfileTeamDirectory === 'function') {



        window.hydrateProfileTeamDirectory(name, type);



      }







      wrappers.forEach(wrap => wrap.classList.remove('active'));















      if (detailWrapper) detailWrapper.classList.add('active');















      















      const canvasEl = document.querySelector('.dashboard-canvas');















      if (canvasEl) canvasEl.scrollTo({ top: 0, behavior: 'smooth' });















    });















  });















}































