window.recoveryBoardClients = ["Vanguard Health", "Nova Financial"];































window.sendRelationshipToRecoveryBoard = function(client) {















  if (!window.recoveryBoardClients) {















    window.recoveryBoardClients = [];















  }















  















  if (!window.recoveryBoardClients.includes(client)) {















    window.recoveryBoardClients.push(client);















  }















  















  // Find record















  let match = customersData.find(c => c.name.toLowerCase() === client.toLowerCase());















  let type = 'customer';















  if (!match) {















    match = prospectsData.find(p => p.name.toLowerCase() === client.toLowerCase());















    type = 'prospect';















  }















  















  const sector = match ? (match.sector || 'B2B Sector') : 'B2B Sector';















  const inactiveDays = match ? (match.inactiveDays || 30) : 30;















  const rep = match ? (match.rep || 'Tom Collins') : 'Tom Collins';















  const value = (type === 'customer') ? 'High-Tier B2B' : 'Lead Opportunity';















  















  const cardHtml = `















    <div class="recovery-opp-card" style="opacity: 0; transform: translateY(15px); transition: all 0.5s cubic-bezier(0.16, 1, 0.3, 1);">















      <div class="opp-card-header">















        <span class="opp-sector">${sector}</span>















        <span class="opp-days red-text">${inactiveDays} days ago</span>















      </div>















      <h4 class="opp-client-name">${match ? match.name : client}</h4>















      <div class="opp-previous-meta">















        <span class="opp-meta-item">Prev. Rep: ${rep}</span>















        <span class="opp-meta-item">Value: ${value}</span>















      </div>















      <p class="opp-copy">${type === 'customer' ? 'Last active touchpoint was logged over ' + inactiveDays + ' days ago. Owner transferred this account to the Board. Claim to rescue relationship.' : 'Lead is at severe risk of decay. Transfer justification and strategic outreach required. Claim to rescue relationship.'}</p>















      <div class="opp-actions">















        <button class="btn-opp-action claim-recovery-btn" data-client="${match ? match.name : client}">Claim Relationship</button>















      </div>















    </div>















  `;















  















  const container = document.getElementById('recovery-opportunities-board');















  if (container) {















    let existingCard = null;















    container.querySelectorAll('.opp-client-name').forEach(title => {















      if (title.textContent.trim().toLowerCase() === client.toLowerCase()) {















        existingCard = title.closest('.recovery-opp-card');















      }















    });















    















    if (!existingCard) {















      container.insertAdjacentHTML('afterbegin', cardHtml);















      setTimeout(() => {















        const firstCard = container.querySelector('.recovery-opp-card');















        if (firstCard) {















          firstCard.style.opacity = '1';















          firstCard.style.transform = 'translateY(0)';















        }















      }, 50);















    }















  }















  















  if (typeof initDashboardRecovery === 'function') {















    initDashboardRecovery();















  }















  















  const recoveryTab = document.querySelector('.sidebar-nav-item[data-tab="recovery"]');















  if (recoveryTab) {















    let badge = recoveryTab.querySelector('.nav-badge-alert');















    if (!badge) {















      badge = document.createElement('span');















      badge.className = 'nav-badge-alert';















      recoveryTab.appendChild(badge);















    }















    badge.textContent = window.recoveryBoardClients.length;















  }















  















  const recoveryQueueCard = document.querySelector('.kpi-card.card-alert-red .kpi-value');















  if (recoveryQueueCard) {















    recoveryQueueCard.textContent = window.recoveryBoardClients.length;















  }















};















let customersData = [];















let currentCustCategoryFilter = 'all';















let currentCustStatusFilter = 'all';















let currentCustSort = 'standard';































function renderCustomersList() {
  const tableBody = document.getElementById('customers-table-rows');
  if (!tableBody) return;

  if (window.supabaseLoading) {
    tableBody.innerHTML = `<tr><td colspan="7" class="loading-state" style="text-align: center; padding: 30px; color: #a855f7; font-family: 'Outfit', sans-serif;">● Loading customers from Supabase...</td></tr>`;
    updateCustomersScorecards([]);
    return;
  }

  if (window.supabaseError) {
    tableBody.innerHTML = `<tr><td colspan="7" class="error-state" style="text-align: center; padding: 30px; color: #ef4444; font-family: 'Outfit', sans-serif;">● Connection issue: Live customers data unavailable</td></tr>`;
    updateCustomersScorecards([]);
    return;
  }

  // 1. Filter dataset
  let filtered = customersData.filter(cust => {
    // Role based filtering
    if (window.currentRole === 'rep') {
      if (cust.rep !== (window.currentUsername || 'Tom Collins')) return false;
    } else if (window.currentRole === 'manager') {
      const managerName = window.currentUsername || 'Marcus Dupond';
      const liveEmps = getLiveEmployeesList();
      const allEmployees = (liveEmps && liveEmps.length > 0) ? liveEmps : (typeof employeesData !== 'undefined' ? employeesData : []);
      const directReps = allEmployees.filter(e => e.manager === managerName && e.roleType === 'reps').map(e => e.name);
      if (window.managerCustViewMode === 'mine') {
        if (cust.rep !== managerName) return false;
      } else {
        // managerCustViewMode === 'team'
        if (window.managerSelectedTeamMember) {
          // Security check: Must be one of the manager's direct reps
          if (cust.rep !== window.managerSelectedTeamMember || !directReps.includes(cust.rep)) return false;
        } else {
          // Show all direct reports' customers, excluding the manager's own
          if (!directReps.includes(cust.rep)) return false;
        }
      }
    } else if (window.currentRole === 'owner') {
      if (window.ownerCustViewMode === 'team') {
        if (window.ownerSelectedTeamMember) {
          if (cust.rep !== window.ownerSelectedTeamMember) return false;
        }
      }
    } else if (window.currentRole === 'hr') {
      if (window.execCustViewMode === 'team') {
        if (window.execSelectedTeamMember) {
          if (cust.rep !== window.execSelectedTeamMember) return false;
        }
      }
    }

    // Category filter















    if (currentCustCategoryFilter !== 'all' && cust.category !== currentCustCategoryFilter) {















      return false;















    }















    // Status filter















    if (currentCustStatusFilter !== 'all') {















      const status = getInactivityStatus(cust.inactiveDays);















      if (currentCustStatusFilter !== status) {















        return false;















      }















    }















    return true;















  });































  // 2. Sort dataset















  if (currentCustSort === 'standard') {















    filtered.sort((a, b) => b.inactiveDays - a.inactiveDays);















  } else {















    filtered.sort((a, b) => b.health - a.health);















  }































  // 3. Update top scorecards based on active subset















  updateCustomersScorecards(filtered);

  if (filtered.length === 0) {
    tableBody.innerHTML = `<tr><td colspan="7" class="empty-state" style="text-align: center; padding: 30px; color: #94a3b8; font-family: 'Outfit', sans-serif;">No customers found.</td></tr>`;
    return;
  }































  // 4. Render Table Rows















  tableBody.innerHTML = filtered.map((cust, index) => {















    let rowClass = 'registry-row';















    let rankCell = '';















    const inactivityStatus = getInactivityStatus(cust.inactiveDays);































    if (currentCustSort === 'standard') {















      rowClass += ` ${inactivityStatus}-row`;















    } else {















      const performanceStatus = getPerformanceStatus(cust.health);















      rowClass += ` ${performanceStatus}-row`;















      















      let medalClass = '';















      if (index === 0) medalClass = 'medal-gold';















      else if (index === 1) medalClass = 'medal-silver';















      else if (index === 2) medalClass = 'medal-bronze';















      















      rankCell = `<span class="rank-badge ${medalClass}">${index + 1}</span>`;















    }































    // TEMPORARY FRONTEND HANDLING RULE: If inactiveDays is 999, display "No activity yet" instead of "999 days ago".
    const daysText = cust.inactiveDays === 999 ? 'No activity yet' : `${cust.inactiveDays} days ago`;
    const dotColor = cust.inactiveDays === 999 ? 'dot-gray' : (inactivityStatus === 'red' ? 'dot-red' : (inactivityStatus === 'orange' ? 'dot-orange' : 'dot-green'));
    const statusTextClass = cust.inactiveDays === 999 ? 'gray-text' : (inactivityStatus === 'red' ? 'red-text' : (inactivityStatus === 'orange' ? 'orange-text' : 'green-text'));































    return `















      <tr class="${rowClass}" data-status="${inactivityStatus}">















        <td>















          <div class="leaderboard-profile-cell">















            ${rankCell}















            <div class="profile-avatar ${cust.colorClass}">${cust.initials}</div>















            <div class="profile-meta">















              <span class="client-name node-name" data-type="customer" data-address="${cust.streetAddress}" data-contact="${cust.contact}" data-city="${cust.city}" data-province="${cust.province}" data-postal="${cust.postal}" data-prospect="${cust.prospect}" data-customer="${cust.customer}" data-phone="${cust.phone}" data-email="${cust.email}" data-rep="${cust.rep}" data-health="${cust.health}%" data-calls="${cust.prospects} logged" data-gifts="${cust.gifts} sent" data-ai="${cust.aiRecommend}">${cust.name}</span>















              <span class="client-sector">${cust.sector}</span>















            </div>















          </div>















        </td>















        <td>B2B Customer</td>
        <td>${cust.rep}</td>
        <td>${cust.gifts} sent</td>















        <td>















          <div class="status-cell">















            <span class="aging-glow-dot ${dotColor}"></span>















            <span class="status-days ${statusTextClass}">${daysText}</span>















          </div>















        </td>















        <td>















          <div class="performance-score-badge ${cust.health >= 90 ? 'positive' : (cust.health >= 75 ? 'neutral' : 'negative')}">${cust.health}% Health</div>















        </td>















        <td>















          <div class="row-actions">















            <button class="row-btn action-gift send-gift-btn" data-name="${cust.name}">Send Gift</button>















            <button class="row-btn action-contact contact-btn" data-name="${cust.name}">Contact</button>















          </div>















        </td>















      </tr>















    `;















  }).join('');































  bindDynamicCustomerActions();















}































function updateCustomersScorecards(dataset) {















  const totalVal = document.getElementById('cust-card-total-val');















  const healthVal = document.getElementById('cust-card-health-val');















  const neglectedVal = document.getElementById('cust-card-neglected-val');















  const giftsVal = document.getElementById('cust-card-gifts-val');

  const isFiltered = (dataset.length !== (typeof customersData !== 'undefined' ? customersData.length : 0));
  if (!isFiltered) {
    if (window.supabaseLoading) {
      if (totalVal) totalVal.textContent = '...';
      if (healthVal) { healthVal.textContent = '...'; healthVal.className = 'kpi-value'; }
      if (neglectedVal) neglectedVal.textContent = '...';
      if (giftsVal) giftsVal.textContent = '...';
      return;
    } else if (window.supabaseError || !window.supabaseKPIs) {
      if (totalVal) totalVal.textContent = '—';
      if (healthVal) { healthVal.textContent = '—'; healthVal.className = 'kpi-value'; }
      if (neglectedVal) neglectedVal.textContent = '—';
      if (giftsVal) giftsVal.textContent = '—';
      return;
    } else if (window.supabaseKPIs) {
      if (totalVal) totalVal.textContent = window.supabaseKPIs.clients;
      if (healthVal) {
        healthVal.textContent = `${window.supabaseKPIs.avg_health}%`;
        healthVal.className = `kpi-value ${window.supabaseKPIs.avg_health >= 90 ? 'text-green' : (window.supabaseKPIs.avg_health >= 75 ? 'text-orange' : 'text-red')}`;
      }
      if (neglectedVal) neglectedVal.textContent = window.supabaseKPIs.neglected_count;
      if (giftsVal) giftsVal.textContent = window.supabaseKPIs.deliveredCount;
      return;
    }
  }































  if (!dataset.length) {















    if (totalVal) totalVal.textContent = '0';















    if (healthVal) healthVal.textContent = '0%';















    if (neglectedVal) neglectedVal.textContent = '0';















    if (giftsVal) giftsVal.textContent = '0';















    return;















  }































  const total = dataset.length;















  const avgHealth = Math.round(dataset.reduce((acc, cust) => acc + cust.health, 0) / total);















  const neglected = dataset.filter(cust => cust.inactiveDays >= 60).length;















  const gifts = dataset.reduce((acc, cust) => acc + cust.gifts, 0);































  if (totalVal) totalVal.textContent = total;















  if (healthVal) {















    healthVal.textContent = `${avgHealth}%`;















    healthVal.className = `kpi-value ${avgHealth >= 90 ? 'text-green' : (avgHealth >= 75 ? 'text-orange' : 'text-red')}`;















  }















  if (neglectedVal) {















    neglectedVal.textContent = neglected;















    neglectedVal.className = `kpi-value ${neglected > 0 ? 'value-red' : ''}`;















  }















  if (giftsVal) giftsVal.textContent = gifts;















}































function bindDynamicCustomerActions() {















  const giftBtns = document.querySelectorAll('#customers-table-rows .send-gift-btn');















  giftBtns.forEach(btn => {















    btn.addEventListener('click', () => {















      const name = btn.getAttribute('data-name');















      showDashboardToast(`Corporate appreciation gift box dispatched to ${name}!`, '✓');















    });















  });































  bindDynamicNodeClicks('#customers-table-rows .node-name');















}































function initCustomersDirectory() {















  const categoryTabs = document.querySelectorAll('#customers-category-tabs .role-tab-btn');















  const statusBadges = document.querySelectorAll('#customers-status-filters .status-badge-btn');















  const sortSegmentBtns = document.querySelectorAll('#customers-sort-toggle .sort-segment-btn');































  if (!categoryTabs.length) return;































  categoryTabs.forEach(btn => {















    btn.addEventListener('click', () => {















      categoryTabs.forEach(b => b.classList.remove('active'));















      btn.classList.add('active');















      currentCustCategoryFilter = btn.getAttribute('data-category');















      renderCustomersList();















    });















  });































  statusBadges.forEach(btn => {















    btn.addEventListener('click', () => {















      statusBadges.forEach(b => b.classList.remove('active'));















      btn.classList.add('active');















      currentCustStatusFilter = btn.getAttribute('data-status');















      renderCustomersList();















    });















  });































  sortSegmentBtns.forEach(btn => {















    btn.addEventListener('click', () => {















      sortSegmentBtns.forEach(b => b.classList.remove('active'));















      btn.classList.add('active');















      currentCustSort = btn.getAttribute('data-sort');















      















      const panelTag = document.getElementById('customers-panel-tag');















      if (panelTag) {















        panelTag.textContent = currentCustSort === 'standard' ? 'Touchpoint Sorted' : 'Health Ranked';















      }















      renderCustomersList();















    });















  });































  renderCustomersList();















  initCustomerIntake();















}































