function initAnalyticsHUD() {















  // Bind time filter buttons once















  initTimeFilterPills();















  















  // Bind activity ticker collapsible once















  initActivityTicker();















  















  // Initialize KPI card previews & tooltips















  initAnalyticsHUDClickablePreviews();















  















  // Load initial view















  renderAnalyticsDashboard();















}































function initTimeFilterPills() {















  const pills = document.querySelectorAll('.time-filter-pills:not(.rep-time-filter-pills) .filter-pill');















  pills.forEach(pill => {















    // Clone and replace to prevent double binding on subsequent tab clicks















    const newPill = pill.cloneNode(true);















    pill.parentNode.replaceChild(newPill, pill);















    















    newPill.addEventListener('click', (e) => {















      e.preventDefault();















      document.querySelectorAll('.time-filter-pills:not(.rep-time-filter-pills) .filter-pill').forEach(p => p.classList.remove('active'));















      newPill.classList.add('active');















      















      currentAnalyticsRange = newPill.getAttribute('data-range');















      showDashboardToast(`Analytics HUD filtered to: ${newPill.textContent.trim()} data`, '✓');















      















      renderAnalyticsDashboard();















    });















  });















}































function initActivityTicker() {















  const toggleBtn = document.getElementById('btn-toggle-activity-feed');















  const container = document.getElementById('analytics-activity-ticker');















  















  if (toggleBtn && container) {















    // Clone and replace to prevent double binding















    const newToggle = toggleBtn.cloneNode(true);















    toggleBtn.parentNode.replaceChild(newToggle, toggleBtn);















    















    newToggle.addEventListener('click', (e) => {















      e.preventDefault();















      container.classList.toggle('collapsed');















      newToggle.textContent = container.classList.contains('collapsed') ? '▶' : '◀';















      showDashboardToast(container.classList.contains('collapsed') ? "Activity feed collapsed" : "Activity feed expanded", 'ℹ');















    });















  }















}































