function animateCountUp(element, target, duration = 1000, suffix = '') {















  if (!element) return;















  















  let startTimestamp = null;















  const step = (timestamp) => {















    if (!startTimestamp) startTimestamp = timestamp;















    const progress = Math.min((timestamp - startTimestamp) / duration, 1);















    const currentValue = Math.floor(progress * target);















    element.textContent = currentValue + suffix;
    if (progress < 1) {
      window.requestAnimationFrame(step);
    } else {
      element.textContent = target + suffix;
    }
  };
  window.requestAnimationFrame(step);
}

function getACFPercentageData(tab, range, labels) {
  const len = labels.length;
  let data = [];
  const seed = range.charCodeAt(0) || 5;
  let base = 85;
  let variance = 10;
  if (tab === 'customers') {
    base = 65;
    variance = 15;
  } else if (tab === 'employees') {
    base = 35;
    variance = 12;
  }
  for (let i = 0; i < len; i++) {
    const val = base + Math.sin(seed + i * 1.5) * variance;
    data.push(Math.round(val));
  }
  return data;
}

function getTPVolumeDataForTab(tab, range, labels) {
  const len = labels.length;
  let data = [];
  const seed = range.charCodeAt(0) || 5;
  let scale = 1;
  if (range === 'live') scale = 48;
  else if (range === 'yesterday') scale = 192;
  else if (range === '7d') scale = 960;
  else if (range === '30d') scale = 4200;
  else if (range === '90d') scale = 13200;
  else if (range === 'ytd') scale = 38400;
  else if (range === 'all') scale = 90000;
  let factor = 0.2;
  if (tab === 'customers') factor = 0.35;
  else if (tab === 'employees') factor = 0.45;
  for (let i = 0; i < len; i++) {
    const val = Math.round(scale * factor * (0.5 + Math.abs(Math.sin(seed + i * 1.1)) * 0.5));
    data.push(val || 1);
  }
  return data;
}

function renderACFTrendChart(labels) {
  const svg = document.getElementById('svg-acf-trend');
  if (!svg) return;

  const width = 600;
  const height = 160;
  const paddingLeft = 48; // Fit percentage labels "100% (A)" cleanly
  const paddingRight = 15;
  const paddingTop = 20;
  const paddingBottom = 25;

  const activeLabels = labels || ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'];
  const graphWidth = width - paddingLeft - paddingRight;
  const graphHeight = height - paddingTop - paddingBottom;

  const range = currentAnalyticsRange || 'live';

  if (!window.activeACFSeries) {
    window.activeACFSeries = { prospects: true, customers: true, employees: true };
  }

  // Bind click/zoom to the card
  const card = document.getElementById('card-acf-trend-hud');
  if (card && !card.dataset.zoomListenerAttached) {
    card.dataset.zoomListenerAttached = 'true';
    card.style.cursor = 'pointer';
    card.addEventListener('click', (e) => {
      if (e.target.closest('.panel-tag')) return;
      showAnalyticsPreviewModal('acf-trend');
    });
  }

  // Bind click listeners and style legend pills
  const tags = document.querySelectorAll('#card-acf-trend-hud .analytics-legend-row .panel-tag');
  if (tags.length >= 3) {
    const tabsList = ['prospects', 'customers', 'employees'];
    tabsList.forEach((tab, index) => {
      const tag = tags[index];
      tag.style.cursor = 'pointer';
      tag.style.transition = 'all 0.2s cubic-bezier(0.16, 1, 0.3, 1)';
      
      if (!tag.dataset.listenerAttached) {
        tag.dataset.listenerAttached = 'true';
        tag.addEventListener('click', (e) => {
          e.stopPropagation();
          window.activeACFSeries[tab] = !window.activeACFSeries[tab];
          renderACFTrendChart(labels);
        });
      }

      if (window.activeACFSeries[tab]) {
        tag.style.opacity = '1';
        if (tab === 'prospects') {
          tag.style.background = 'rgba(59, 130, 246, 0.15)';
          tag.style.borderColor = 'rgba(59, 130, 246, 0.4)';
          tag.style.color = '#3b82f6';
        } else if (tab === 'customers') {
          tag.style.background = 'rgba(16, 185, 129, 0.15)';
          tag.style.borderColor = 'rgba(16, 185, 129, 0.4)';
          tag.style.color = '#10b981';
        } else {
          tag.style.background = 'rgba(129, 140, 248, 0.15)';
          tag.style.borderColor = 'rgba(129, 140, 248, 0.4)';
          tag.style.color = '#818cf8';
        }
      } else {
        tag.style.opacity = '0.3';
        tag.style.background = 'rgba(255, 255, 255, 0.02)';
        tag.style.borderColor = 'rgba(255, 255, 255, 0.05)';
        tag.style.color = '#64748b';
      }
    });
  }

  const getPoints = (dataArr) => {
    return dataArr.map((val, idx) => {
      const x = paddingLeft + (idx / (dataArr.length - 1)) * graphWidth;
      const y = paddingTop + graphHeight * (1 - val / 100);
      return { x, y, val };
    });
  };

  const getPathD = (points) => {
    if (points.length === 0) return '';
    let pathD = `M ${points[0].x} ${points[0].y}`;
    for (let i = 0; i < points.length - 1; i++) {
      const p0 = points[i];
      const p1 = points[i + 1];
      const cp1x = p0.x + (p1.x - p0.x) / 3;
      const cp1y = p0.y;
      const cp2x = p0.x + 2 * (p1.x - p0.x) / 3;
      const cp2y = p1.y;
      pathD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;
    }
    return pathD;
  };

  const getFillD = (points) => {
    if (points.length === 0) return '';
    let fillD = `M ${points[0].x} ${height - paddingBottom} L ${points[0].x} ${points[0].y}`;
    for (let i = 0; i < points.length - 1; i++) {
      const p0 = points[i];
      const p1 = points[i + 1];
      const cp1x = p0.x + (p1.x - p0.x) / 3;
      const cp1y = p0.y;
      const cp2x = p0.x + 2 * (p1.x - p0.x) / 3;
      const cp2y = p1.y;
      fillD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;
    }
    fillD += ` L ${points[points.length - 1].x} ${height - paddingBottom} Z`;
    return fillD;
  };

  let prospectsCurve = '';
  if (window.activeACFSeries.prospects) {
    const rawDataP = getACFPercentageData('prospects', range, activeLabels);
    const pts = getPoints(rawDataP);
    const path = getPathD(pts);
    const fill = getFillD(pts);
    prospectsCurve = `
      <path d="${fill}" fill="url(#acf-prospects-fill)" />
      <path d="${path}" fill="none" stroke="#3b82f6" stroke-width="2.5" stroke-linecap="round" />
      ${pts.map(p => `
        <circle cx="${p.x}" cy="${p.y}" r="3.2" fill="#3b82f6" stroke="#0a0b18" stroke-width="1.2" />
        <text x="${p.x}" y="${p.y - 8}" fill="#fff" font-size="7.5" font-family="'Outfit', sans-serif" font-weight="900" text-anchor="middle" style="text-shadow: 0 1px 2px rgba(0,0,0,0.9);">${p.val}%</text>
      `).join('')}
    `;
  }

  let customersCurve = '';
  if (window.activeACFSeries.customers) {
    const rawDataC = getACFPercentageData('customers', range, activeLabels);
    const pts = getPoints(rawDataC);
    const path = getPathD(pts);
    const fill = getFillD(pts);
    customersCurve = `
      <path d="${fill}" fill="url(#acf-customers-fill)" />
      <path d="${path}" fill="none" stroke="#10b981" stroke-width="2.5" stroke-linecap="round" />
      ${pts.map(p => `
        <circle cx="${p.x}" cy="${p.y}" r="3.2" fill="#10b981" stroke="#0a0b18" stroke-width="1.2" />
        <text x="${p.x}" y="${p.y - 8}" fill="#fff" font-size="7.5" font-family="'Outfit', sans-serif" font-weight="900" text-anchor="middle" style="text-shadow: 0 1px 2px rgba(0,0,0,0.9);">${p.val}%</text>
      `).join('')}
    `;
  }

  let employeesCurve = '';
  if (window.activeACFSeries.employees) {
    const rawDataE = getACFPercentageData('employees', range, activeLabels);
    const pts = getPoints(rawDataE);
    const path = getPathD(pts);
    const fill = getFillD(pts);
    employeesCurve = `
      <path d="${fill}" fill="url(#acf-employees-fill)" />
      <path d="${path}" fill="none" stroke="#818cf8" stroke-width="2.5" stroke-linecap="round" />
      ${pts.map(p => `
        <circle cx="${p.x}" cy="${p.y}" r="3.2" fill="#818cf8" stroke="#0a0b18" stroke-width="1.2" />
        <text x="${p.x}" y="${p.y - 8}" fill="#fff" font-size="7.5" font-family="'Outfit', sans-serif" font-weight="900" text-anchor="middle" style="text-shadow: 0 1px 2px rgba(0,0,0,0.9);">${p.val}%</text>
      `).join('')}
    `;
  }

  const labelsHtml = activeLabels.map((l, idx) => {
    const x = paddingLeft + (idx / (activeLabels.length - 1)) * graphWidth;
    return `<text x="${x}" y="${height - 10}" fill="#64748b" font-size="8.5" font-weight="700" text-anchor="middle">${l}</text>`;
  }).join('');

  svg.innerHTML = `
    <style>
    </style>
    <defs>
      <linearGradient id="acf-prospects-fill" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stop-color="rgba(59, 130, 246, 0.08)"/>
        <stop offset="100%" stop-color="rgba(59, 130, 246, 0)"/>
      </linearGradient>
      <linearGradient id="acf-customers-fill" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stop-color="rgba(16, 185, 129, 0.08)"/>
        <stop offset="100%" stop-color="rgba(16, 185, 129, 0)"/>
      </linearGradient>
      <linearGradient id="acf-employees-fill" x1="0" y1="0" x2="0" y2="1">
        <stop offset="0%" stop-color="rgba(129, 140, 248, 0.08)"/>
        <stop offset="100%" stop-color="rgba(129, 140, 248, 0)"/>
      </linearGradient>
    </defs>

    <line x1="${paddingLeft}" y1="${paddingTop}" x2="${width - paddingRight}" y2="${paddingTop}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
    <line x1="${paddingLeft}" y1="${paddingTop + graphHeight / 2}" x2="${width - paddingRight}" y2="${paddingTop + graphHeight / 2}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
    <line x1="${paddingLeft}" y1="${height - paddingBottom}" x2="${width - paddingRight}" y2="${height - paddingBottom}" stroke="rgba(255,255,255,0.06)" stroke-width="1.5"/>

    <text x="40" y="${paddingTop + 4}" fill="#64748b" font-size="8.5" font-weight="700" text-anchor="end">100% (A)</text>
    <text x="40" y="${paddingTop + graphHeight / 2 + 4}" fill="#475569" font-size="8.5" font-weight="700" text-anchor="end">50% (C)</text>
    <text x="40" y="${height - paddingBottom + 3}" fill="#ef4444" font-size="8.5" font-weight="800" text-anchor="end">0% (F)</text>

    ${prospectsCurve}
    ${customersCurve}
    ${employeesCurve}
    ${labelsHtml}
  `;
}

