function initAnalyticsHUDClickablePreviews() {















  // Bind click handlers to all 7 Hero KPI cards - REMOVED per user request to disable modals for KPI cards















  const kpiBinds = [















    { id: 'kpi-active-clients' },















    { id: 'kpi-avg-health' },















    { id: 'kpi-total-prospects' },















    { id: 'kpi-active-prospects' },















    { id: 'kpi-active-employees' },















    { id: 'kpi-touchpoints' },















    { id: 'kpi-gifts-sent' }















  ];































  kpiBinds.forEach(binding => {















    const cardEl = document.getElementById(binding.id);















    if (cardEl) {















      cardEl.style.cursor = 'default';















      cardEl.onclick = null;















    }















  });































  // Bind click handler to the new combined Conversion Performance HUD card















  const convHudCard = document.getElementById('card-conversion-performance-hud');















  if (convHudCard) {















    convHudCard.onclick = (e) => {















      e.preventDefault();















      showAnalyticsPreviewModal('conversion-hud');















    };















  }































  // Bind click handler to the Relationship Health Trend card















  const healthTrendCard = document.getElementById('card-health-trend-hud');















  if (healthTrendCard) {















    healthTrendCard.onclick = (e) => {















      e.preventDefault();















      showAnalyticsPreviewModal('health-trend');















    };















  }































  // Bind click handler to the Monthly Gifts Dispatched card















  const giftingTrendCard = document.getElementById('card-gifting-trend-hud');















  if (giftingTrendCard) {















    giftingTrendCard.onclick = (e) => {















      e.preventDefault();















      showAnalyticsPreviewModal('gifting-trend');















    };















  }































  // Bind click handler to the Rep Leaderboard panel card itself or its rows















  const repRows = document.querySelectorAll('.leaderboard-table-analytics tbody tr');















  repRows.forEach(row => {















    row.onclick = (e) => {















      e.preventDefault();















      showAnalyticsPreviewModal('rep-leaderboard');















    };















  });































  // Bind click handler to the Gifted vs. Non-Gifted Impact card















  const giftedImpactCard = document.getElementById('card-gifted-impact-hud');















  if (giftedImpactCard) {















    giftedImpactCard.onclick = (e) => {















      e.preventDefault();















      showAnalyticsPreviewModal('gifted-impact');















    };















  }































































  // Bind click handler to the Rep Performance Leaderboard card















  const repLboardCard = document.getElementById('card-rep-leaderboard-hud');















  if (repLboardCard) {















    repLboardCard.onclick = (e) => {















      e.preventDefault();















      showAnalyticsPreviewModal('rep-leaderboard');















    };















  }































  // Bind modal close buttons















  const modal = document.getElementById('analytics-preview-modal');















  const closeBtn = document.getElementById('btn-analytics-modal-close');















  if (closeBtn && modal) {















    closeBtn.onclick = (e) => {















      e.preventDefault();















      modal.classList.remove('show');















    };















    modal.onclick = (e) => {















      if (e.target === modal) {















        modal.classList.remove('show');















      }















    };















  }































  // Bind Leaderboard Perf Index info trigger tooltip hover















  const perfHelp = document.getElementById('leaderboard-perf-help');















  const generalTooltip = document.getElementById('analytics-general-tooltip');















  if (perfHelp && generalTooltip) {















    perfHelp.onmouseenter = (e) => {















      const rect = perfHelp.getBoundingClientRect();















      generalTooltip.innerHTML = `















        <div style="font-weight: 700; color: #fff; margin-bottom: 4px;">Perf Index Formula</div>















        <div style="color: #94a3b8; line-height: 1.4; white-space: normal; width: 190px;">















          Weighted scorecard reflecting:<br>















          • <strong>40%</strong> Touchpoint Consistency<br>















          • <strong>30%</strong> Prospect to Customer Conversion Time<br>















          • <strong>30%</strong> Avg Relationship Health















        </div>















      `;















      generalTooltip.style.display = 'block';















      generalTooltip.style.left = (rect.left + window.scrollX - 90) + 'px';















      generalTooltip.style.top = (rect.top + window.scrollY - 105) + 'px';















    };















    perfHelp.onmouseleave = () => {















      generalTooltip.style.display = 'none';















    };















  }































  // Global routing utility to view employee profile details modal programmatically















  window.viewEmployeeProfile = function(empName) {















    // 1. Close the modal















    const modal = document.getElementById('analytics-preview-modal');















    if (modal) modal.classList.remove('show');















    















    // 2. Switch tab to employees















    const tabBtn = document.querySelector('.sidebar-nav-item[data-tab="employees"]');















    if (tabBtn) tabBtn.click();















    















    // 3. Wait a brief instant for the DOM to update, then search for the row















    setTimeout(() => {















      const nodes = document.querySelectorAll('#employees-table-rows .node-name');















      let found = false;















      for (const node of nodes) {















        if (node.textContent.trim().toLowerCase().includes(empName.toLowerCase())) {















          node.click();















          found = true;















          break;















        }















      }















      // If not found in the currently filtered view, clear search/role filters and try again















      if (!found) {















        const searchInput = document.getElementById('employees-search-input');















        if (searchInput) {















          searchInput.value = '';















          searchInput.dispatchEvent(new Event('input'));















        }















        const allRoleBtn = document.querySelector('#employees-role-tabs .role-tab-btn[data-role="all"]');















        if (allRoleBtn) allRoleBtn.click();















        















        const allStatusBtn = document.querySelector('#employees-status-filters .status-badge-btn[data-status="all"]');















        if (allStatusBtn) allStatusBtn.click();















        















        setTimeout(() => {















          const renodes = document.querySelectorAll('#employees-table-rows .node-name');















          for (const renode of renodes) {















            if (renode.textContent.trim().toLowerCase().includes(empName.toLowerCase())) {















              renode.click();















              break;















            }















          }















        }, 50);















      }















    }, 100);















  };















}































function generateExpandedHealthTrendSVG(trendData, labels) {















  const width = 560;















  const height = 185;















  const paddingLeft = 45;















  const paddingRight = 20;















  const paddingTop = 25;















  const paddingBottom = 30;















  















  const graphWidth = width - paddingLeft - paddingRight;















  const graphHeight = height - paddingTop - paddingBottom;















  















  const points = trendData.map((val, idx) => {















    const x = paddingLeft + (idx / (trendData.length - 1)) * graphWidth;















    const y = paddingTop + graphHeight * (1 - val / 100);















    return { x, y, val };















  });















  















  let pathD = `M ${points[0].x} ${points[0].y}`;















  let fillD = `M ${points[0].x} ${height - paddingBottom} L ${points[0].x} ${points[0].y}`;















  















  for (let i = 0; i < points.length - 1; i++) {















    const p0 = points[i];















    const p1 = points[i + 1];















    const cp1x = p0.x + (p1.x - p0.x) / 3;















    const cp1y = p0.y;















    const cp2x = p0.x + 2 * (p1.x - p0.x) / 3;















    const cp2y = p1.y;















    















    pathD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;















    fillD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;















  }















  fillD += ` L ${points[points.length - 1].x} ${height - paddingBottom} Z`;















  















  return `















    <svg viewBox="0 0 ${width} ${height}" style="width: 100%; height: ${height}px; display: block; background: rgba(10, 11, 24, 0.45); border: 1px solid rgba(255, 255, 255, 0.05); border-radius: 12px; margin-bottom: 16px;">















      <defs>















        <linearGradient id="health-modal-line-grad" x1="0" y1="0" x2="1" y2="0">















          <stop offset="0%" stop-color="#a78bfa"/>















          <stop offset="100%" stop-color="#6366f1"/>















        </linearGradient>















        <linearGradient id="health-modal-fill-grad" x1="0" y1="0" x2="0" y2="1">















          <stop offset="0%" stop-color="rgba(139, 92, 246, 0.22)"/>















          <stop offset="100%" stop-color="rgba(139, 92, 246, 0)"/>















        </linearGradient>















      </defs>















      















      <!-- Grid Lines -->















      <line x1="${paddingLeft}" y1="${paddingTop}" x2="${width - paddingRight}" y2="${paddingTop}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>















      <line x1="${paddingLeft}" y1="${paddingTop + graphHeight / 2}" x2="${width - paddingRight}" y2="${paddingTop + graphHeight / 2}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>















      <line x1="${paddingLeft}" y1="${height - paddingBottom}" x2="${width - paddingRight}" y2="${height - paddingBottom}" stroke="rgba(255,255,255,0.06)" stroke-width="1.5"/>















      















      <!-- Y Axis Labels -->















      <text x="10" y="${paddingTop + 4}" fill="#64748b" font-size="9" font-weight="700">100%</text>















      <text x="15" y="${paddingTop + graphHeight / 2 + 4}" fill="#475569" font-size="9" font-weight="700">50%</text>















      <text x="20" y="${height - paddingBottom + 3}" fill="#ef4444" font-size="9" font-weight="800">0%</text>















      















      <!-- Fill Area -->















      <path d="${fillD}" fill="url(#health-modal-fill-grad)"/>















      















      <!-- Line Path -->















      <path d="${pathD}" fill="none" stroke="url(#health-modal-line-grad)" stroke-width="4" stroke-linecap="round"/>















      















      <!-- Nodes & Labels -->















      ${points.map((pt, idx) => `















        <circle cx="${pt.x}" cy="${pt.y}" r="5" fill="#818cf8" stroke="#0a0b18" stroke-width="2" style="filter: drop-shadow(0 0 5px #6366f1);"/>















        <text x="${pt.x}" y="${pt.y - 10}" fill="#fff" font-size="9.5" font-weight="800" text-anchor="middle">${pt.val}%</text>















        <text x="${pt.x}" y="${height - 10}" fill="#64748b" font-size="9.5" font-weight="700" text-anchor="middle">${labels[idx] || ''}</text>















      `).join('')}















    </svg>















  `;















}































function generateExpandedGiftingTrendSVG(trendData, labels) {















  const width = 560;















  const height = 185;















  const paddingLeft = 35;















  const paddingRight = 20;















  const paddingTop = 25;















  const paddingBottom = 30;















  















  const graphWidth = width - paddingLeft - paddingRight;















  const graphHeight = height - paddingTop - paddingBottom;















  















  const maxVal = Math.max(...trendData, 5);















  















  const barWidth = 32;















  const gap = (graphWidth - (trendData.length * barWidth)) / (trendData.length - 1);















  















  const bars = trendData.map((val, idx) => {















    const x = paddingLeft + idx * (barWidth + gap);















    const h = (val / maxVal) * graphHeight;















    const y = height - paddingBottom - h;















    return { x, y, h, val };















  });















  















  return `















    <svg viewBox="0 0 ${width} ${height}" style="width: 100%; height: ${height}px; display: block; background: rgba(10, 11, 24, 0.45); border: 1px solid rgba(255, 255, 255, 0.05); border-radius: 12px; margin-bottom: 16px;">















      <defs>















        <linearGradient id="gifting-modal-bar-grad" x1="0" y1="0" x2="0" y2="1">















          <stop offset="0%" stop-color="#34d399"/>















          <stop offset="100%" stop-color="#059669"/>















        </linearGradient>















      </defs>















      















      <!-- Grid Lines -->















      <line x1="${paddingLeft}" y1="${paddingTop}" x2="${width - paddingRight}" y2="${paddingTop}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>















      <line x1="${paddingLeft}" y1="${paddingTop + graphHeight / 2}" x2="${width - paddingRight}" y2="${paddingTop + graphHeight / 2}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>















      <line x1="${paddingLeft}" y1="${height - paddingBottom}" x2="${width - paddingRight}" y2="${height - paddingBottom}" stroke="rgba(255,255,255,0.06)" stroke-width="1.5"/>















      















      <!-- Y Axis Labels -->















      <text x="12" y="${paddingTop + 4}" fill="#64748b" font-size="9" font-weight="700">${maxVal}</text>















      <text x="12" y="${paddingTop + graphHeight / 2 + 4}" fill="#475569" font-size="9" font-weight="700">${Math.round(maxVal / 2)}</text>















      















      <!-- Bars -->















      ${bars.map((b, idx) => `
        <g class="gifting-bar-group" data-index="${idx}" style="cursor: pointer; pointer-events: all;">
          <!-- Highlight Outline -->
          <rect class="gifting-bar-highlight" x="${b.x - 3}" y="${b.y - 3}" width="${barWidth + 6}" height="${b.h + 6}" rx="7" ry="7" fill="none" stroke="#34d399" stroke-width="2" style="opacity: 0; transition: opacity 0.2s ease; filter: drop-shadow(0 0 4px rgba(52,211,153,0.5));" />
          
          <!-- Actual Bar -->
          <rect class="gifting-bar" x="${b.x}" y="${b.y}" width="${barWidth}" height="${b.h}" rx="5" ry="5" fill="url(#gifting-modal-bar-grad)" style="opacity: 0.85; transition: opacity 0.2s ease; filter: drop-shadow(0 0 6px rgba(52, 211, 153, 0.2));"/>
          
          <!-- Value Label -->
          <text class="gifting-bar-val" x="${b.x + barWidth / 2}" y="${b.y - 6}" fill="#10b981" font-size="9.5" font-weight="800" text-anchor="middle" style="opacity: 0.85; transition: all 0.2s ease;">${b.val}</text>
          
          <!-- X Axis Label -->
          <text x="${b.x + barWidth / 2}" y="${height - 10}" fill="#64748b" font-size="9.5" font-weight="700" text-anchor="middle">${labels[idx] || ''}</text>
          
          <!-- Invisible overlay rect for hover area -->
          <rect class="gifting-bar-overlay" x="${b.x - 2}" y="${paddingTop}" width="${barWidth + 4}" height="${graphHeight}" fill="#fff" fill-opacity="0" pointer-events="all" />
        </g>
      `).join('')}















    </svg>















  `;















}

function generateExpandedACFTrendSVG(labels) {
  const width = 800;
  const height = 240;
  const paddingLeft = 55;
  const paddingRight = 20;
  const paddingTop = 25;
  const paddingBottom = 30;

  const activeLabels = labels || ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'];
  const graphWidth = width - paddingLeft - paddingRight;
  const graphHeight = height - paddingTop - paddingBottom;
  const range = currentAnalyticsRange || 'live';

  if (!window.activeACFSeries) {
    window.activeACFSeries = { prospects: true, customers: true, employees: true };
  }

  const getPoints = (dataArr) => {
    return dataArr.map((val, idx) => {
      const x = paddingLeft + (idx / (dataArr.length - 1)) * graphWidth;
      const y = paddingTop + graphHeight * (1 - val / 100);
      return { x, y, val };
    });
  };

  const getPathD = (points) => {
    if (points.length === 0) return '';
    let pathD = `M ${points[0].x} ${points[0].y}`;
    for (let i = 0; i < points.length - 1; i++) {
      const p0 = points[i];
      const p1 = points[i + 1];
      const cp1x = p0.x + (p1.x - p0.x) / 3;
      const cp1y = p0.y;
      const cp2x = p0.x + 2 * (p1.x - p0.x) / 3;
      const cp2y = p1.y;
      pathD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;
    }
    return pathD;
  };

  const getFillD = (points) => {
    if (points.length === 0) return '';
    let fillD = `M ${points[0].x} ${height - paddingBottom} L ${points[0].x} ${points[0].y}`;
    for (let i = 0; i < points.length - 1; i++) {
      const p0 = points[i];
      const p1 = points[i + 1];
      const cp1x = p0.x + (p1.x - p0.x) / 3;
      const cp1y = p0.y;
      const cp2x = p0.x + 2 * (p1.x - p0.x) / 3;
      const cp2y = p1.y;
      fillD += ` C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${p1.x} ${p1.y}`;
    }
    fillD += ` L ${points[points.length - 1].x} ${height - paddingBottom} Z`;
    return fillD;
  };

  let curvesHtml = '';
  const series = [
    { key: 'prospects', color: '#3b82f6', grad: 'acf-prospects-fill-modal' },
    { key: 'customers', color: '#10b981', grad: 'acf-customers-fill-modal' },
    { key: 'employees', color: '#818cf8', grad: 'acf-employees-fill-modal' }
  ];

  series.forEach(s => {
    if (window.activeACFSeries[s.key]) {
      const rawData = getACFPercentageData(s.key, range, activeLabels);
      const pts = getPoints(rawData);
      const path = getPathD(pts);
      const fill = getFillD(pts);
      curvesHtml += `
        <!-- ${s.key} curve -->
        <path d="${fill}" fill="url(#${s.grad})" />
        <path d="${path}" fill="none" stroke="${s.color}" stroke-width="3" stroke-linecap="round" filter="drop-shadow(0 2px 4px rgba(0,0,0,0.3))" />
        ${pts.map((p, idx) => `
          <circle cx="${p.x}" cy="${p.y}" r="4" fill="${s.color}" stroke="#0a0b18" stroke-width="1.5" />
          <text x="${p.x}" y="${p.y - 10}" fill="#fff" font-family="'Outfit', sans-serif" font-size="8" font-weight="900" text-anchor="middle" style="text-shadow: 0 1px 3px rgba(0,0,0,0.9);">${p.val}%</text>
        `).join('')}
      `;
    }
  });

  const labelsHtml = activeLabels.map((l, idx) => {
    const x = paddingLeft + (idx / (activeLabels.length - 1)) * graphWidth;
    return `<text x="${x}" y="${height - 12}" fill="#94a3b8" font-family="'Outfit', sans-serif" font-size="9" font-weight="700" text-anchor="middle">${l}</text>`;
  }).join('');

  return `
    <svg viewBox="0 0 ${width} ${height}" style="width: 100%; height: auto; background: rgba(10, 11, 24, 0.6); border: 1px solid rgba(255,255,255,0.05); border-radius: 16px; overflow: visible;">
      <style>
      </style>
      <defs>
        <linearGradient id="acf-prospects-fill-modal" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="rgba(59, 130, 246, 0.12)"/>
          <stop offset="100%" stop-color="rgba(59, 130, 246, 0)"/>
        </linearGradient>
        <linearGradient id="acf-customers-fill-modal" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="rgba(16, 185, 129, 0.12)"/>
          <stop offset="100%" stop-color="rgba(16, 185, 129, 0)"/>
        </linearGradient>
        <linearGradient id="acf-employees-fill-modal" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="rgba(129, 140, 248, 0.12)"/>
          <stop offset="100%" stop-color="rgba(129, 140, 248, 0)"/>
        </linearGradient>
      </defs>

      <!-- Y Grid Lines & Labels -->
      <line x1="${paddingLeft}" y1="${paddingTop}" x2="${width - paddingRight}" y2="${paddingTop}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${paddingTop + graphHeight / 2}" x2="${width - paddingRight}" y2="${paddingTop + graphHeight / 2}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${height - paddingBottom}" x2="${width - paddingRight}" y2="${height - paddingBottom}" stroke="rgba(255,255,255,0.08)" stroke-width="1.5"/>

      <text x="${paddingLeft - 10}" y="${paddingTop + 4}" fill="#94a3b8" font-family="'Outfit', sans-serif" font-size="9" font-weight="800" text-anchor="end">100% (A)</text>
      <text x="${paddingLeft - 10}" y="${paddingTop + graphHeight / 2 + 4}" fill="#475569" font-family="'Outfit', sans-serif" font-size="9" font-weight="800" text-anchor="end">50% (C)</text>
      <text x="${paddingLeft - 10}" y="${height - paddingBottom + 3}" fill="#ef4444" font-family="'Outfit', sans-serif" font-size="9" font-weight="900" text-anchor="end">0% (F)</text>

      ${curvesHtml}
      ${labelsHtml}
    </svg>
  `;
}

function generateExpandedTPVolumeSVG(labels) {
  const width = 800;
  const height = 240;
  const paddingLeft = 45;
  const paddingRight = 20;
  const paddingTop = 25;
  const paddingBottom = 30;

  const activeLabels = labels || ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'];
  const graphWidth = width - paddingLeft - paddingRight;
  const graphHeight = height - paddingTop - paddingBottom;
  const range = currentAnalyticsRange || 'live';

  if (!window.activeTPVolumeSeries) {
    window.activeTPVolumeSeries = { prospects: true, customers: true, employees: true };
  }

  const dataP = getTPVolumeDataForTab('prospects', range, activeLabels);
  const dataC = getTPVolumeDataForTab('customers', range, activeLabels);
  const dataE = getTPVolumeDataForTab('employees', range, activeLabels);

  const len = activeLabels.length;
  let maxTotal = 1;
  for (let i = 0; i < len; i++) {
    const valP = window.activeTPVolumeSeries.prospects ? dataP[i] : 0;
    const valC = window.activeTPVolumeSeries.customers ? dataC[i] : 0;
    const valE = window.activeTPVolumeSeries.employees ? dataE[i] : 0;
    const itemMax = Math.max(valP, valC, valE);
    if (itemMax > maxTotal) maxTotal = itemMax;
  }

  const barWidth = 18; // Massive inside modal!
  const barGap = 4;
  const groupWidth = 3 * barWidth + 2 * barGap; // 62px
  const colGap = (graphWidth - (len * groupWidth)) / (len - 1);

  const columnsHtml = activeLabels.map((l, idx) => {
    const groupX = paddingLeft + idx * (groupWidth + colGap);
    
    let prospectsBar = '';
    if (window.activeTPVolumeSeries.prospects) {
      const val = dataP[idx];
      const h = (val / maxTotal) * graphHeight;
      const y = height - paddingBottom - h;
      prospectsBar = `
        <g class="tp-volume-bar-group" data-index="${idx}" data-category="prospects" data-value="${val}" style="cursor: pointer; pointer-events: all;">
          <rect class="tp-volume-bar-highlight" x="${groupX - 2}" y="${y - 2}" width="${barWidth + 4}" height="${h + 4}" rx="4" ry="4" fill="none" stroke="#3b82f6" stroke-width="1.5" style="opacity: 0; transition: opacity 0.2s ease; filter: drop-shadow(0 0 4px rgba(59,130,246,0.5));" />
          <rect class="tp-volume-bar" x="${groupX}" y="${y}" width="${barWidth}" height="${h}" rx="3" ry="3" fill="url(#tp-prospects-grad-modal)" style="opacity: 0.85; transition: opacity 0.2s ease;" />
          ${val > 0 ? `<text class="tp-volume-bar-val" x="${groupX + barWidth / 2}" y="${y - 5}" fill="#3b82f6" font-family="'Outfit', sans-serif" font-size="7.5" font-weight="800" text-anchor="middle" style="transition: opacity 0.2s ease;">${val}</text>` : ''}
          <rect x="${groupX - 1}" y="${paddingTop}" width="${barWidth + 2}" height="${graphHeight}" fill="#fff" fill-opacity="0" pointer-events="all" />
        </g>
      `;
    }

    let customersBar = '';
    if (window.activeTPVolumeSeries.customers) {
      const val = dataC[idx];
      const h = (val / maxTotal) * graphHeight;
      const y = height - paddingBottom - h;
      const xOffset = groupX + barWidth + barGap;
      customersBar = `
        <g class="tp-volume-bar-group" data-index="${idx}" data-category="customers" data-value="${val}" style="cursor: pointer; pointer-events: all;">
          <rect class="tp-volume-bar-highlight" x="${xOffset - 2}" y="${y - 2}" width="${barWidth + 4}" height="${h + 4}" rx="4" ry="4" fill="none" stroke="#10b981" stroke-width="1.5" style="opacity: 0; transition: opacity 0.2s ease; filter: drop-shadow(0 0 4px rgba(16,185,129,0.5));" />
          <rect class="tp-volume-bar" x="${xOffset}" y="${y}" width="${barWidth}" height="${h}" rx="3" ry="3" fill="url(#tp-customers-grad-modal)" style="opacity: 0.85; transition: opacity 0.2s ease;" />
          ${val > 0 ? `<text class="tp-volume-bar-val" x="${xOffset + barWidth / 2}" y="${y - 5}" fill="#10b981" font-family="'Outfit', sans-serif" font-size="7.5" font-weight="800" text-anchor="middle" style="transition: opacity 0.2s ease;">${val}</text>` : ''}
          <rect x="${xOffset - 1}" y="${paddingTop}" width="${barWidth + 2}" height="${graphHeight}" fill="#fff" fill-opacity="0" pointer-events="all" />
        </g>
      `;
    }

    let employeesBar = '';
    if (window.activeTPVolumeSeries.employees) {
      const val = dataE[idx];
      const h = (val / maxTotal) * graphHeight;
      const y = height - paddingBottom - h;
      const xOffset = groupX + 2 * (barWidth + barGap);
      employeesBar = `
        <g class="tp-volume-bar-group" data-index="${idx}" data-category="employees" data-value="${val}" style="cursor: pointer; pointer-events: all;">
          <rect class="tp-volume-bar-highlight" x="${xOffset - 2}" y="${y - 2}" width="${barWidth + 4}" height="${h + 4}" rx="4" ry="4" fill="none" stroke="#818cf8" stroke-width="1.5" style="opacity: 0; transition: opacity 0.2s ease; filter: drop-shadow(0 0 4px rgba(129,140,248,0.5));" />
          <rect class="tp-volume-bar" x="${xOffset}" y="${y}" width="${barWidth}" height="${h}" rx="3" ry="3" fill="url(#tp-employees-grad-modal)" style="opacity: 0.85; transition: opacity 0.2s ease;" />
          ${val > 0 ? `<text class="tp-volume-bar-val" x="${xOffset + barWidth / 2}" y="${y - 5}" fill="#818cf8" font-family="'Outfit', sans-serif" font-size="7.5" font-weight="800" text-anchor="middle" style="transition: opacity 0.2s ease;">${val}</text>` : ''}
          <rect x="${xOffset - 1}" y="${paddingTop}" width="${barWidth + 2}" height="${graphHeight}" fill="#fff" fill-opacity="0" pointer-events="all" />
        </g>
      `;
    }

    return `
      <g>
        ${prospectsBar}
        ${customersBar}
        ${employeesBar}
      </g>
    `;
  }).join('');

  const labelsHtml = activeLabels.map((l, idx) => {
    const x = paddingLeft + idx * (groupWidth + colGap) + groupWidth / 2;
    return `<text x="${x}" y="${height - 12}" fill="#94a3b8" font-family="'Outfit', sans-serif" font-size="9" font-weight="700" text-anchor="middle">${l}</text>`;
  }).join('');

  return `
    <svg viewBox="0 0 ${width} ${height}" style="width: 100%; height: auto; background: rgba(10, 11, 24, 0.6); border: 1px solid rgba(255,255,255,0.05); border-radius: 16px; overflow: visible;">
      <style>
        .tp-volume-bar {
          transition: transform 0.2s ease, opacity 0.2s ease, filter 0.2s ease;
        }
        .tp-volume-bar-group:hover .tp-volume-bar {
          filter: brightness(1.2);
          transform: translateY(-2px);
          opacity: 1 !important;
        }
      </style>
      <defs>
        <linearGradient id="tp-prospects-grad-modal" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="#3b82f6"/>
          <stop offset="100%" stop-color="#1d4ed8"/>
        </linearGradient>
        <linearGradient id="tp-customers-grad-modal" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="#10b981"/>
          <stop offset="100%" stop-color="#047857"/>
        </linearGradient>
        <linearGradient id="tp-employees-grad-modal" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stop-color="#818cf8"/>
          <stop offset="100%" stop-color="#4f46e5"/>
        </linearGradient>
      </defs>

      <!-- Y Grid Lines -->
      <line x1="${paddingLeft}" y1="${paddingTop}" x2="${width - paddingRight}" y2="${paddingTop}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${paddingTop + graphHeight / 2}" x2="${width - paddingRight}" y2="${paddingTop + graphHeight / 2}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${height - paddingBottom}" x2="${width - paddingRight}" y2="${height - paddingBottom}" stroke="rgba(255,255,255,0.08)" stroke-width="1.5"/>

      <!-- Y-Axis Labels -->
      <text x="${paddingLeft - 10}" y="${paddingTop + 4}" fill="#94a3b8" font-family="'Outfit', sans-serif" font-size="9" font-weight="800" text-anchor="end">${maxTotal}</text>
      <text x="${paddingLeft - 10}" y="${paddingTop + graphHeight / 2 + 4}" fill="#475569" font-family="'Outfit', sans-serif" font-size="9" font-weight="800" text-anchor="end">${Math.round(maxTotal / 2)}</text>
      <text x="${paddingLeft - 10}" y="${height - paddingBottom + 3}" fill="#94a3b8" font-family="'Outfit', sans-serif" font-size="9" font-weight="800" text-anchor="end">0</text>

      ${columnsHtml}
      ${labelsHtml}
    </svg>
  `;
}































