function initGiftingTrendInteractiveListeners() {
  const groups = document.querySelectorAll('#analytics-preview-modal .gifting-bar-group');
  const tbody = document.querySelector('#analytics-preview-modal .preview-details-table tbody');
  
  if (!tbody) return;
  
  // Clear the table initially and show a nice placeholder
  tbody.innerHTML = `
    <tr class="gifting-placeholder-row">
      <td colspan="5" style="text-align: center; padding: 28px; color: #64748b; font-family: 'Outfit'; font-size: 11.5px; background: rgba(255,255,255,0.01);">
        <span style="font-size: 14px; margin-right: 6px;">👈</span> Click on any bar in the graph above to view dispatched gifts for that time period.
      </td>
    </tr>
  `;
  
  groups.forEach(group => {
    // Keep track of the active clicked index on the SVG itself
    const svgParent = group.closest('svg');
    
    group.addEventListener('mouseenter', function() {
      const index = parseInt(this.getAttribute('data-index'));
      const activeIdx = svgParent.getAttribute('data-active-index');
      if (activeIdx !== null && parseInt(activeIdx) === index) return; // Keep full highlight on active
      
      const highlight = this.querySelector('.gifting-bar-highlight');
      const bar = this.querySelector('.gifting-bar');
      if (highlight) highlight.style.opacity = '0.5';
      if (bar) bar.style.opacity = '1';
    });
    
    group.addEventListener('mouseleave', function() {
      const index = parseInt(this.getAttribute('data-index'));
      const activeIdx = svgParent.getAttribute('data-active-index');
      if (activeIdx !== null && parseInt(activeIdx) === index) return; // Keep full highlight on active
      
      const highlight = this.querySelector('.gifting-bar-highlight');
      const bar = this.querySelector('.gifting-bar');
      if (highlight) highlight.style.opacity = '0';
      if (bar) bar.style.opacity = '0.85';
    });

    group.addEventListener('click', function() {
      const index = parseInt(this.getAttribute('data-index'));
      svgParent.setAttribute('data-active-index', index);
      
      // Highlight the clicked group, dim others
      groups.forEach((g, i) => {
        const highlight = g.querySelector('.gifting-bar-highlight');
        const bar = g.querySelector('.gifting-bar');
        const valText = g.querySelector('.gifting-bar-val');
        
        if (i === index) {
          // Highlight
          if (highlight) highlight.style.opacity = '1';
          if (bar) bar.style.opacity = '1';
          if (valText) {
            valText.style.opacity = '1';
            valText.style.fill = '#fff';
            valText.style.fontWeight = '900';
          }
        } else {
          // Dim
          if (highlight) highlight.style.opacity = '0';
          if (bar) bar.style.opacity = '0.35';
          if (valText) valText.style.opacity = '0.35';
        }
      });
      
      // Get label and value from current active range data
      const currentRange = currentAnalyticsRange || 'live';
      const rangeData = analyticsDataSets[currentRange];
      if (!rangeData) return;
      
      const label = rangeData.giftingLabels[index];
      const count = rangeData.giftingTrend[index];
      
      // Populate details table rows
      populateGiftingTrendDetails(label, count, tbody);
    });
  });
}

function populateGiftingTrendDetails(label, count, tbody) {
  if (count === 0) {
    tbody.innerHTML = `
      <tr>
        <td colspan="5" style="text-align: center; padding: 24px; color: #94a3b8; font-family: 'Outfit'; font-size: 11px;">
          📭 No gifts were dispatched during the "${label}" period.
        </td>
      </tr>
    `;
    return;
  }
  
  const mockSenders = ['Sarah Lansky', 'Tom Collins', 'Marcus Dupond', 'Jack R.', 'Anna L.', 'Gregory Sterling'];
  const mockRecipients = [
    { client: 'OmniCorp Tech', company: 'OmniCorp' },
    { client: 'Chevron Solutions', company: 'Chevron' },
    { client: 'Apex Global Retail', company: 'Apex' },
    { client: 'Nova Financial', company: 'Nova' },
    { client: 'Summit Financial', company: 'Summit' },
    { client: 'TechFlow Inc', company: 'TechFlow' },
    { client: 'BlueSky Ventures', company: 'BlueSky' },
    { client: 'Quantum Dynamics', company: 'Quantum' },
    { client: 'Alpha Crest', company: 'Alpha Crest' },
    { client: 'Apex Core', company: 'Apex Core' }
  ];
  const mockGifts = [
    'Pack Box (Birthday)',
    'Sweet Box (Retention)',
    'Premium Box (Anniversary)',
    'Milestone Sweet Box',
    'Quarterly Sync Box',
    'VIP Celebration Pack',
    'Signature Chocolate Medley',
    'Artisanal Cookie Sampler'
  ];
  
  // Base date calculation
  const currentRange = currentAnalyticsRange || 'live';
  let dateBase = 'May 26, 2026';
  if (currentRange === 'yesterday') {
    dateBase = 'May 25, 2026';
  }
  
  let html = '';
  
  for (let i = 0; i < count; i++) {
    // Pick deterministic but varied mock elements
    const sender = mockSenders[(label.charCodeAt(0) + i) % mockSenders.length];
    const rec = mockRecipients[(label.charCodeAt(0) + i * 2) % mockRecipients.length];
    const gift = mockGifts[(label.charCodeAt(0) + i * 3) % mockGifts.length];
    
    // Determine date & time
    let dateStr = '';
    let timeStr = '';
    
    // Random minute for natural variation
    const min = (10 + (i * 17)) % 60;
    const minStr = min < 10 ? '0' + min : min;
    
    if (label.includes('am') || label.includes('pm')) {
      // Hourly
      dateStr = dateBase;
      const hourStr = label.replace('am', '').replace('pm', '');
      const isPm = label.includes('pm');
      timeStr = `${hourStr}:${minStr} ${isPm ? 'PM' : 'AM'}`;
    } else if (['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'].includes(label)) {
      // 7D Daily
      const daysMap = {
        'Mon': 'May 25, 2026', 'Tue': 'May 26, 2026', 'Wed': 'May 27, 2026',
        'Thu': 'May 28, 2026', 'Fri': 'May 29, 2026', 'Sat': 'May 30, 2026',
        'Sun': 'May 31, 2026'
      };
      dateStr = daysMap[label] || dateBase;
      const hr = 9 + (i * 2) % 8;
      timeStr = `${hr < 10 ? '0' + hr : hr}:${minStr} ${hr >= 12 ? 'PM' : 'AM'}`;
    } else if (label.startsWith('Wk')) {
      // Weekly
      const wkNum = parseInt(label.replace('Wk', ''));
      const day = 1 + (wkNum - 1) * 7 + (i * 2) % 6;
      const dayStr = day < 10 ? '0' + day : day;
      dateStr = `May ${dayStr}, 2026`;
      const hr = 9 + (i * 2) % 8;
      timeStr = `${hr < 10 ? '0' + hr : hr}:${minStr} ${hr >= 12 ? 'PM' : 'AM'}`;
    } else {
      // Monthly/Quarterly (Jan, Feb, Month 1, etc.)
      const monthStr = label.replace('Month ', '');
      const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
      let targetMonth = months[Math.abs(label.charCodeAt(0)) % months.length];
      if (months.includes(label)) {
        targetMonth = label;
      }
      const day = 5 + (i * 4) % 20;
      const dayStr = day < 10 ? '0' + day : day;
      dateStr = `${targetMonth} ${dayStr}, 2026`;
      const hr = 9 + (i * 2) % 8;
      timeStr = `${hr < 10 ? '0' + hr : hr}:${minStr} ${hr >= 12 ? 'PM' : 'AM'}`;
    }
    
    html += `
      <tr style="transition: all 0.2s ease;">
        <td><strong>${sender}</strong></td>
        <td>${rec.client}</td>
        <td>${gift}</td>
        <td>${dateStr} at ${timeStr}</td>
        <td style="text-align: right; color:#10b981; font-weight:700;">✓ Dispatched</td>
      </tr>
    `;
  }
  
  tbody.innerHTML = html;
}

function initTPVolumeInteractiveListeners() {
  const groups = document.querySelectorAll('#analytics-preview-modal .tp-volume-bar-group');
  const tbody = document.querySelector('#analytics-preview-modal table tbody');
  
  if (!tbody) return;
  
  groups.forEach(group => {
    const svgParent = group.closest('svg');
    
    group.addEventListener('mouseenter', function() {
      const activeIdx = svgParent.getAttribute('data-active-index');
      const activeCat = svgParent.getAttribute('data-active-cat');
      const index = parseInt(this.getAttribute('data-index'));
      const category = this.getAttribute('data-category');
      
      if (activeIdx !== null && parseInt(activeIdx) === index && activeCat === category) return;
      
      const highlight = this.querySelector('.tp-volume-bar-highlight');
      const bar = this.querySelector('.tp-volume-bar');
      if (highlight) highlight.style.opacity = '0.5';
      if (bar) bar.style.opacity = '1';
    });
    
    group.addEventListener('mouseleave', function() {
      const activeIdx = svgParent.getAttribute('data-active-index');
      const activeCat = svgParent.getAttribute('data-active-cat');
      const index = parseInt(this.getAttribute('data-index'));
      const category = this.getAttribute('data-category');
      
      if (activeIdx !== null && parseInt(activeIdx) === index && activeCat === category) return;
      
      const highlight = this.querySelector('.tp-volume-bar-highlight');
      const bar = this.querySelector('.tp-volume-bar');
      if (highlight) highlight.style.opacity = '0';
      if (bar) bar.style.opacity = '0.85';
    });

    group.addEventListener('click', function() {
      const index = parseInt(this.getAttribute('data-index'));
      const category = this.getAttribute('data-category');
      const value = parseInt(this.getAttribute('data-value'));
      
      svgParent.setAttribute('data-active-index', index);
      svgParent.setAttribute('data-active-cat', category);
      
      // Highlight the clicked bar group, dim all others
      groups.forEach((g) => {
        const gIdx = parseInt(g.getAttribute('data-index'));
        const gCat = g.getAttribute('data-category');
        const highlight = g.querySelector('.tp-volume-bar-highlight');
        const bar = g.querySelector('.tp-volume-bar');
        const valText = g.querySelector('.tp-volume-bar-val');
        
        if (gIdx === index && gCat === category) {
          // Highlight active
          if (highlight) highlight.style.opacity = '1';
          if (bar) bar.style.opacity = '1';
          if (valText) {
            valText.style.opacity = '1';
            valText.style.fontWeight = '900';
          }
        } else {
          // Dim inactive
          if (highlight) highlight.style.opacity = '0';
          if (bar) bar.style.opacity = '0.25';
          if (valText) valText.style.opacity = '0.25';
        }
      });
      
      // Fetch label from range
      const currentRange = currentAnalyticsRange || 'live';
      const rangeData = analyticsDataSets[currentRange];
      const label = rangeData ? rangeData.healthLabels[index] : 'Period';
      
      populateTPVolumeDetails(label, category, value, tbody);
    });
  });
}

