function generateExpandedGradedSVG(key) {
  const range = currentAnalyticsRange || 'live';
  const { maxVal, days: activeDays } = getGradedDataForRange(key, range);

  const width = 800;
  const height = 240;
  const paddingLeft = 45;
  const paddingRight = 20;
  const paddingTop = 25;
  const paddingBottom = 30;
  
  const graphWidth = width - paddingLeft - paddingRight;
  const graphHeight = height - paddingTop - paddingBottom;
  
  let maxTotal = 1;
  activeDays.forEach(d => {
    const sum = d.green + d.yellow + d.red;
    if (sum > maxTotal) maxTotal = sum;
  });
  
  const barWidth = 36;
  const len = activeDays.length;
  const colGap = (graphWidth - (len * barWidth)) / (len - 1 || 1);
  
  const columnsHtml = activeDays.map((d, idx) => {
    const x = paddingLeft + idx * (barWidth + colGap);
    
    const greenH = (d.green / maxTotal) * graphHeight;
    const yellowH = (d.yellow / maxTotal) * graphHeight;
    const redH = (d.red / maxTotal) * graphHeight;
    
    const greenY = height - paddingBottom - greenH;
    const yellowY = greenY - yellowH;
    const redY = yellowY - redH;
    
    let greenBlock = '';
    if (d.green > 0) {
      greenBlock = `
        <g class="graded-segment-group" data-day="${d.day}" data-grade="A" data-count="${d.green}" style="cursor: pointer;">
          <rect class="graded-segment-highlight" x="${x - 2}" y="${greenY - 2}" width="${barWidth + 4}" height="${greenH + 4}" rx="4" fill="none" stroke="#10b981" stroke-width="1.5" style="opacity: 0; transition: opacity 0.2s;" />
          <rect class="graded-segment-bar" x="${x}" y="${greenY}" width="${barWidth}" height="${greenH}" rx="3" fill="#10b981" style="opacity: 0.85; transition: opacity 0.2s;" />
          <text class="graded-segment-val" x="${x + barWidth / 2}" y="${greenY + greenH / 2 + 3}" fill="#fff" font-family="'Outfit', sans-serif" font-size="8.5" font-weight="800" text-anchor="middle" style="pointer-events: none;">${d.green}</text>
        </g>
      `;
    }
    
    let yellowBlock = '';
    if (d.yellow > 0) {
      yellowBlock = `
        <g class="graded-segment-group" data-day="${d.day}" data-grade="C" data-count="${d.yellow}" style="cursor: pointer;">
          <rect class="graded-segment-highlight" x="${x - 2}" y="${yellowY - 2}" width="${barWidth + 4}" height="${yellowH + 4}" rx="4" fill="none" stroke="#f59e0b" stroke-width="1.5" style="opacity: 0; transition: opacity 0.2s;" />
          <rect class="graded-segment-bar" x="${x}" y="${yellowY}" width="${barWidth}" height="${yellowH}" rx="3" fill="#f59e0b" style="opacity: 0.85; transition: opacity 0.2s;" />
          <text class="graded-segment-val" x="${x + barWidth / 2}" y="${yellowY + yellowH / 2 + 3}" fill="#fff" font-family="'Outfit', sans-serif" font-size="8.5" font-weight="800" text-anchor="middle" style="pointer-events: none;">${d.yellow}</text>
        </g>
      `;
    }
    
    let redBlock = '';
    if (d.red > 0) {
      redBlock = `
        <g class="graded-segment-group" data-day="${d.day}" data-grade="F" data-count="${d.red}" style="cursor: pointer;">
          <rect class="graded-segment-highlight" x="${x - 2}" y="${redY - 2}" width="${barWidth + 4}" height="${redH + 4}" rx="4" fill="none" stroke="#ef4444" stroke-width="1.5" style="opacity: 0; transition: opacity 0.2s;" />
          <rect class="graded-segment-bar" x="${x}" y="${redY}" width="${barWidth}" height="${redH}" rx="3" fill="#ef4444" style="opacity: 0.85; transition: opacity 0.2s;" />
          <text class="graded-segment-val" x="${x + barWidth / 2}" y="${redY + redH / 2 + 3}" fill="#fff" font-family="'Outfit', sans-serif" font-size="8.5" font-weight="800" text-anchor="middle" style="pointer-events: none;">${d.red}</text>
        </g>
      `;
    }
    
    return `
      <g>
        ${greenBlock}
        ${yellowBlock}
        ${redBlock}
      </g>
    `;
  }).join('');
  
  const labelsHtml = activeDays.map((d, idx) => {
    const x = paddingLeft + idx * (barWidth + colGap) + barWidth / 2;
    return `<text x="${x}" y="${height - 10}" fill="#94a3b8" font-family="'Outfit', sans-serif" font-size="10" font-weight="700" text-anchor="middle">${d.day}</text>`;
  }).join('');
  
  return `
    <svg viewBox="0 0 ${width} ${height}" style="width: 100%; height: auto; background: rgba(10, 11, 24, 0.6); border: 1px solid rgba(255,255,255,0.05); border-radius: 16px; overflow: visible;">
      <style>
        .graded-segment-bar {
          transition: transform 0.2s ease, opacity 0.2s ease, filter 0.2s ease;
        }
        .graded-segment-group:hover .graded-segment-bar {
          filter: brightness(1.2);
          transform: translateY(-1px);
          opacity: 1 !important;
        }
      </style>
      
      <!-- Grid Lines -->
      <line x1="${paddingLeft}" y1="${paddingTop}" x2="${width - paddingRight}" y2="${paddingTop}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${paddingTop + graphHeight / 2}" x2="${width - paddingRight}" y2="${paddingTop + graphHeight / 2}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${height - paddingBottom}" x2="${width - paddingRight}" y2="${height - paddingBottom}" stroke="rgba(255,255,255,0.06)" stroke-width="1.5"/>
      
      <!-- Y Axis Labels -->
      <text x="12" y="${paddingTop + 4}" fill="#64748b" font-family="'Outfit', sans-serif" font-size="9" font-weight="600">${maxTotal}</text>
      <text x="12" y="${paddingTop + graphHeight / 2 + 4}" fill="#475569" font-family="'Outfit', sans-serif" font-size="9" font-weight="600">${Math.round(maxTotal / 2)}</text>
      <text x="12" y="${height - paddingBottom + 4}" fill="#475569" font-family="'Outfit', sans-serif" font-size="9" font-weight="600">0</text>
      
      ${columnsHtml}
      ${labelsHtml}
    </svg>
  `;
}


function initGradedInteractiveListeners(metric) {
  const groups = document.querySelectorAll('#analytics-preview-modal .graded-segment-group');
  const tbody = document.querySelector('#analytics-preview-modal table tbody');
  if (!tbody) return;
  
  groups.forEach(group => {
    const svgParent = group.closest('svg');
    
    group.addEventListener('mouseenter', function() {
      const activeDay = svgParent.getAttribute('data-active-day');
      const activeGrade = svgParent.getAttribute('data-active-grade');
      const day = this.getAttribute('data-day');
      const grade = this.getAttribute('data-grade');
      
      if (activeDay === day && activeGrade === grade) return;
      
      const highlight = this.querySelector('.graded-segment-highlight');
      const bar = this.querySelector('.graded-segment-bar');
      if (highlight) highlight.style.opacity = '0.5';
      if (bar) bar.style.opacity = '1';
    });
    
    group.addEventListener('mouseleave', function() {
      const activeDay = svgParent.getAttribute('data-active-day');
      const activeGrade = svgParent.getAttribute('data-active-grade');
      const day = this.getAttribute('data-day');
      const grade = this.getAttribute('data-grade');
      
      if (activeDay === day && activeGrade === grade) return;
      
      const highlight = this.querySelector('.graded-segment-highlight');
      const bar = this.querySelector('.graded-segment-bar');
      if (highlight) highlight.style.opacity = '0';
      if (bar) bar.style.opacity = '0.85';
    });
    
    group.addEventListener('click', function() {
      const day = this.getAttribute('data-day');
      const grade = this.getAttribute('data-grade');
      const count = parseInt(this.getAttribute('data-count'));
      
      svgParent.setAttribute('data-active-day', day);
      svgParent.setAttribute('data-active-grade', grade);
      
      groups.forEach(g => {
        const gDay = g.getAttribute('data-day');
        const gGrade = g.getAttribute('data-grade');
        const highlight = g.querySelector('.graded-segment-highlight');
        const bar = g.querySelector('.graded-segment-bar');
        const valText = g.querySelector('.graded-segment-val');
        
        if (gDay === day && gGrade === grade) {
          if (highlight) highlight.style.opacity = '1';
          if (bar) bar.style.opacity = '1';
          if (valText) valText.style.fontWeight = '900';
        } else {
          if (highlight) highlight.style.opacity = '0';
          if (bar) bar.style.opacity = '0.25';
          if (valText) valText.style.opacity = '0.25';
        }
      });
      
      populateGradedNotesDetails(metric, day, grade, count, tbody);
    });
  });
}


