function getGradedPeriodLabel(range) {
  switch (range) {
    case 'live': return 'Live Graded Distribution';
    case 'yesterday': return 'Yesterday Graded Distribution';
    case '7d': return 'Weekly Graded Distribution';
    case '30d': return '30-Day Graded Distribution';
    case '90d': return '90-Day Graded Distribution';
    case 'ytd': return 'Year-to-Date Graded Distribution';
    case 'all': return 'All-Time Graded Distribution';
    default: return 'Graded Distribution';
  }
}

function getGradedDataForRange(key, range) {
  let baseMax = 15;
  let labels = [];
  
  switch (range) {
    case 'live':
      baseMax = 15;
      labels = ['8am', '10am', '12pm', '2pm', '4pm', '6pm'];
      break;
    case 'yesterday':
      baseMax = 25;
      labels = ['8am', '10am', '12pm', '2pm', '4pm', '6pm'];
      break;
    case '7d':
      baseMax = 35;
      labels = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];
      break;
    case '30d':
      baseMax = 140;
      labels = ['Wk 1', 'Wk 2', 'Wk 3', 'Wk 4', 'Active'];
      break;
    case '90d':
      baseMax = 400;
      labels = ['Wk 1-2', 'Wk 3-4', 'Wk 5-6', 'Wk 7-8', 'Wk 9-10', 'Active'];
      break;
    case 'ytd':
      baseMax = 1200;
      labels = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'];
      break;
    case 'all':
      baseMax = 3000;
      labels = ['2025 Q3', '2025 Q4', '2026 Q1', '2026 Q2'];
      break;
    default:
      baseMax = 15;
      labels = ['8am', '10am', '12pm', '2pm', '4pm', '6pm'];
  }
  
  const multiplier = (key === 'prospects') ? 1.0 : ((key === 'customers') ? 1.6 : 2.2);
  const maxVal = Math.round(baseMax * multiplier);
  
  let pcts = [];
  if (labels.length === 3) {
    pcts = [0.75, 0.85, 0.65];
  } else if (labels.length === 4) {
    pcts = [0.70, 0.80, 0.75, 0.85];
  } else if (labels.length === 5) {
    pcts = [0.75, 0.82, 0.88, 0.70, 0.60];
  } else if (labels.length === 6) {
    pcts = [0.45, 0.70, 0.85, 0.90, 0.75, 0.50];
  } else if (labels.length === 7) {
    pcts = [0.70, 0.85, 0.75, 0.90, 0.80, 0.30, 0.15];
  } else {
    pcts = new Array(labels.length).fill(0.75);
  }
  
  const days = labels.map((label, idx) => {
    const pct = pcts[idx] || 0.75;
    const total = Math.round(maxVal * pct);
    
    let green = Math.round(total * 0.75);
    let yellow = Math.round(total * 0.20);
    let red = Math.max(0, total - green - yellow);
    
    if (total > 0 && green === 0 && yellow === 0 && red === 0) {
      green = 1;
    }
    
    return {
      day: label,
      green: green,
      yellow: yellow,
      red: red
    };
  });
  
  return { maxVal, days };
}

function renderGradedTouchpointsCharts() {
  const range = currentAnalyticsRange || 'live';
  
  const badgeLabels = {
    'live': 'Live Segments',
    'yesterday': 'Yesterday Segments',
    '7d': '7-Day Segments',
    '30d': '30-Day Segments',
    '90d': '90-Day Segments',
    'ytd': 'Year-to-Date Segments',
    'all': 'All Segments'
  };
  const currentBadgeText = badgeLabels[range] || 'Daily Segments';

  const categories = [
    { id: 'svg-prospect-stacked', key: 'prospects', title: 'Prospect Touches' },
    { id: 'svg-customer-stacked', key: 'customers', title: 'Customer Touches' },
    { id: 'svg-employee-stacked', key: 'employees', title: 'Employee Touches' }
  ];

  const width = 400;
  const height = 200;
  const paddingLeft = 30;
  const paddingRight = 15;
  const paddingTop = 20;
  const paddingBottom = 30;
  const graphWidth = width - paddingLeft - paddingRight;
  const graphHeight = height - paddingTop - paddingBottom;
  const barWidth = 22;

  categories.forEach(cat => {
    const svg = document.getElementById(cat.id);
    if (!svg) return;

    try {
      const card = svg.closest('.analytics-panel-card');
      if (card) {
        const badge = card.querySelector('.panel-tag');
        if (badge) {
          badge.textContent = currentBadgeText;
        }
      }
    } catch (e) {
      console.warn("Failed to update panel tag badge text", e);
    }

    const { maxVal, days } = getGradedDataForRange(cat.key, range);
    const gap = (graphWidth - (days.length * barWidth)) / (days.length - 1 || 1);

    const barsHtml = days.map((dayData, idx) => {
      const total = dayData.green + dayData.yellow + dayData.red;
      const x = paddingLeft + idx * (barWidth + gap);

      const redH = (dayData.red / maxVal) * graphHeight;
      const yellowH = (dayData.yellow / maxVal) * graphHeight;
      const greenH = (dayData.green / maxVal) * graphHeight;

      const greenY = height - paddingBottom - greenH;
      const yellowY = greenY - yellowH;
      const redY = yellowY - redH;

      const tooltipText = `Total: ${total} touches — ${dayData.green} Good (A), ${dayData.yellow} Okay (C), ${dayData.red} Critical (F)`;

      return `
        <!-- Stack Group for ${dayData.day} -->
        <g class="stacked-bar-analytics" data-tooltip="${tooltipText}">
          <!-- Green Block (A) -->
          ${dayData.green > 0 ? `
            <rect class="stacked-bar-segment" x="${x}" y="${greenY}" width="${barWidth}" height="${greenH}" rx="3" ry="3" fill="#10b981" style="opacity: 0.9; filter: drop-shadow(0 0 2px rgba(16, 185, 129, 0.1));" />
          ` : ''}

          <!-- Yellow Block (C) -->
          ${dayData.yellow > 0 ? `
            <rect class="stacked-bar-segment" x="${x}" y="${yellowY}" width="${barWidth}" height="${yellowH}" rx="3" ry="3" fill="#f59e0b" style="opacity: 0.85; filter: drop-shadow(0 0 2px rgba(245, 158, 11, 0.1));" />
          ` : ''}

          <!-- Red Block (F) -->
          ${dayData.red > 0 ? `
            <rect class="stacked-bar-segment" x="${x}" y="${redY}" width="${barWidth}" height="${redH}" rx="3" ry="3" fill="#ef4444" style="opacity: 0.85; filter: drop-shadow(0 0 2px rgba(239, 68, 68, 0.1));" />
          ` : ''}

          <!-- Invisible overlay rect for hovering convenience -->
          <rect class="stacked-bar-overlay" x="${x}" y="${redY}" width="${barWidth}" height="${redH + yellowH + greenH}" fill="transparent" style="cursor: pointer;" />

          <!-- X Axis Label -->
          <text x="${x + barWidth / 2}" y="${height - 10}" fill="#64748b" font-size="9.5" font-weight="700" text-anchor="middle">${dayData.day}</text>
        </g>
      `;
    }).join('');

    svg.innerHTML = `
      <!-- Grid Lines -->
      <line x1="${paddingLeft}" y1="${paddingTop}" x2="${width - paddingRight}" y2="${paddingTop}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${paddingTop + graphHeight / 2}" x2="${width - paddingRight}" y2="${paddingTop + graphHeight / 2}" stroke="rgba(255,255,255,0.03)" stroke-width="1"/>
      <line x1="${paddingLeft}" y1="${height - paddingBottom}" x2="${width - paddingRight}" y2="${height - paddingBottom}" stroke="rgba(255,255,255,0.06)" stroke-width="1.5"/>

      <!-- Y Axis Labels -->
      <text x="10" y="${paddingTop + 4}" fill="#64748b" font-size="8.5" font-weight="600">${maxVal}</text>
      <text x="10" y="${paddingTop + graphHeight / 2 + 4}" fill="#475569" font-size="8.5" font-weight="600">${Math.round(maxVal / 2)}</text>
      <text x="10" y="${height - paddingBottom + 4}" fill="#475569" font-size="8.5" font-weight="600">0</text>

      <!-- Bars -->
      ${barsHtml}
    `;

    // Bind tooltip behavior
    const tooltip = document.getElementById('analytics-general-tooltip');
    const groups = svg.querySelectorAll('.stacked-bar-analytics');

    groups.forEach(group => {
      group.onmouseenter = (e) => {
        if (!tooltip) return;
        const text = group.getAttribute('data-tooltip');
        tooltip.innerHTML = `
          <div style="font-weight: 700; color: #fff; margin-bottom: 2px;">${cat.title}</div>
          <div style="color: #e2e8f0; white-space: normal; width: 160px; line-height: 1.3;">${text}</div>
        `;
        tooltip.style.display = 'block';

        const overlay = group.querySelector('.stacked-bar-overlay');
        const rect = overlay.getBoundingClientRect();
        tooltip.style.left = (rect.left + window.scrollX - 70) + 'px';
        tooltip.style.top = (rect.top + window.scrollY - 65) + 'px';
      };

      group.onmouseleave = () => {
        if (tooltip) tooltip.style.display = 'none';
      };

      group.onclick = (e) => {
        e.preventDefault();
        showAnalyticsPreviewModal(cat.key === 'prospects' ? 'prospects-graded' : (cat.key === 'customers' ? 'customers-graded' : 'employees-graded'));
      };
    });
  });
}
