    const cardLeftBorder = isYellow ? '4px solid #eab308' : '4px solid #ef4444';















    















    const hoverBg = isYellow ? 'rgba(234,179,8,0.08)' : 'rgba(239,68,68,0.08)';















    const hoverBorder = isYellow ? 'rgba(234,179,8,0.3)' : 'rgba(239,68,68,0.3)';















    















