    const btnBg = isYellow ? 'rgba(234, 179, 8, 0.12)' : 'rgba(239, 68, 68, 0.12)';















    const btnBorder = isYellow ? '1px solid rgba(234, 179, 8, 0.35)' : '1px solid rgba(239, 68, 68, 0.35)';















    















