// Modal Toggle Functions















function openExecutiveSchedulerModal() {















  const modal = document.getElementById('executive-scheduler-modal');















  if (!modal) return;































  if (modal.parentElement !== document.documentElement) {















    document.documentElement.appendChild(modal);















  }































  modal.style.display = 'flex';















  modal.getBoundingClientRect();















  modal.classList.add('show');















}















window.openExecutiveSchedulerModal = openExecutiveSchedulerModal;































function closeExecutiveSchedulerModal() {















  const modal = document.getElementById('executive-scheduler-modal');















  if (!modal) return;































  modal.classList.remove('show');















  setTimeout(() => {















    modal.style.display = 'none';















  }, 300);















}















window.closeExecutiveSchedulerModal = closeExecutiveSchedulerModal;































function openExecutiveSchedulerModalWithDate(date) {















  openExecutiveSchedulerModal();















  const dateEl = document.getElementById('scheduler-event-date');















  if (dateEl) dateEl.value = date;















}















window.openExecutiveSchedulerModalWithDate = openExecutiveSchedulerModalWithDate;































// Override/enhance routeToOwnerCalendar to trigger the slide-over scheduler modal















function routeToOwnerCalendar(eventType, targetName) {















  console.log(`[RMOS Calendar Router] Routing event type "${eventType}" for "${targetName}" to Executive Calendar Modal.`);















  















  // 1. Switch sidebar active view to "profile"















  const profileSidebarBtn = document.querySelector('.sidebar-nav-item[data-tab="profile"]');















  if (profileSidebarBtn) {















    profileSidebarBtn.click();















  }















  















  // 2. Open B2B Scheduler Modal with premium fade animation















  openExecutiveSchedulerModal();















  















  // 3. Pre-fill scheduler modal fields















  const categorySelect = document.getElementById('scheduler-event-type');















  const targetInput = document.getElementById('scheduler-event-target');















  const dateInput = document.getElementById('scheduler-event-date');















  















  if (categorySelect) {















    if (eventType.includes("Performance") || eventType.includes("Review") || eventType.includes("Sync")) {















      categorySelect.value = "Performance Review";















    } else if (eventType.includes("Strategic") || eventType.includes("Meeting") || eventType.includes("Sync")) {















      categorySelect.value = "Client Strategic Meeting";















    } else if (eventType.includes("Gift") || eventType.includes("Delivery")) {















      categorySelect.value = "Milestone Gift Delivery";















    } else {















      categorySelect.value = "Internal Operations Review";















    }















    categorySelect.dispatchEvent(new Event('change', { bubbles: true }));















  }















  















  if (targetInput) {















    targetInput.value = targetName;















    targetInput.dispatchEvent(new Event('input', { bubbles: true }));















  }















  















  if (dateInput) {















    dateInput.value = '2026-05-27';















    dateInput.dispatchEvent(new Event('input', { bubbles: true }));















    setTimeout(() => {















      dateInput.focus();















    }, 250);















  }















  















  showDashboardToast(`📅 Calendar Scheduler loaded for ${targetName}!`, '✓');















}















window.routeToOwnerCalendar = routeToOwnerCalendar;































