window.initConstellationEvents = function() {



  console.log("[Constellation Engine] initConstellationEvents called!");



  const openBtn = document.getElementById('btn-open-constellation');



  const screen = document.getElementById('constellation-screen');



  const closeBtn = document.getElementById('btn-close-constellation');



  



  if (!screen) {



    console.warn("[Constellation Engine] constellation-screen element not found!");



    return;



  }



  



  if (screen.dataset.boundConstellation) {



    console.log("[Constellation Engine] Events already bound, skipping duplicate binding.");



    return;



  }



  screen.dataset.boundConstellation = "true";



  



  if (openBtn) {



    openBtn.addEventListener('click', (e) => {



      e.preventDefault();



      e.stopPropagation();



      screen.style.display = 'flex';



      document.body.style.overflow = 'hidden';



      window.updateConstellationPills();



      window.drawConstellationConnections();



      



      // Set default initial details to Gregory Sterling when opening



      const ceoNode = document.getElementById('node-gregory-sterling');



      if (ceoNode) {



        window.hydrateConstellationDetail(ceoNode);



      }



    });



  }



  



  const closeFn = (e) => {



    if (e) { e.preventDefault(); e.stopPropagation(); }



    screen.style.display = 'none';



    document.body.style.overflow = '';



  };



  



  if (closeBtn) {



    closeBtn.addEventListener('click', closeFn);



  }



  



  window.addEventListener('keydown', (e) => {



    if (e.key === 'Escape' && screen.style.display === 'flex') {



      closeFn();



    }



  });



  



  window.addEventListener('resize', () => {



    if (screen.style.display === 'flex') {



      window.drawConstellationConnections();



    }



  });



  



  // Wire node clicks for all nodes inside the constellation overlay and the tab view



  document.querySelectorAll('#constellation-screen .constellation-node, #constellation-screen .constellation-team-pill, #view-constellation .constellation-node, #view-constellation .constellation-team-pill').forEach(el => {



    el.addEventListener('click', (e) => {



      e.preventDefault();



      e.stopPropagation();



      window.hydrateConstellationDetail(el);



    });



  });



  



  // Wire team card clicks to automatically trigger the grouped stats panel!



  document.querySelectorAll('#constellation-screen .constellation-team-card, #view-constellation .constellation-team-card').forEach(card => {



    card.addEventListener('click', (e) => {



      e.preventDefault();



      e.stopPropagation();



      const pill = card.querySelector('.constellation-team-pill');



      if (pill) {



        window.hydrateConstellationDetail(pill);



      }



    });



  });



  



  // Initialize zoom and pan controls



  if (typeof window.initConstellationZoom === 'function') {



    window.initConstellationZoom();



  }



  



  // Update the team pills initially on load



  window.updateConstellationPills();



};







window.initConstellationZoom = function() {



  console.log("[Constellation Engine] Initializing premium zoom and pan controls...");



  



  const canvases = document.querySelectorAll('#view-constellation, #constellation-screen');



  



  canvases.forEach(container => {



    const canvasArea = container.querySelector('#constellation-canvas-area');



    const zoomWrapper = container.querySelector('#constellation-zoom-wrapper');



    const btnIn = container.querySelector('#btn-const-zoom-in');



    const btnOut = container.querySelector('#btn-const-zoom-out');



    const btnReset = container.querySelector('#btn-const-zoom-reset');



    



    if (!canvasArea || !zoomWrapper) return;



    



    let scale = 1.0;



    let panX = 0;



    let panY = 0;



    



    let isDragging = false;



    let startX = 0;



    let startY = 0;



    



    const applyTransform = () => {



      zoomWrapper.style.transform = `scale(${scale}) translate(${panX}px, ${panY}px)`;



    };



    



    // Zoom In



    if (btnIn) {



      btnIn.addEventListener('click', (e) => {



        e.preventDefault(); e.stopPropagation();



        scale = Math.min(2.0, scale + 0.15);



        applyTransform();



      });



    }



    



    // Zoom Out



    if (btnOut) {



      btnOut.addEventListener('click', (e) => {



        e.preventDefault(); e.stopPropagation();



        scale = Math.max(0.4, scale - 0.15);



        applyTransform();



      });



    }



    



    // Zoom Reset



    if (btnReset) {



      btnReset.addEventListener('click', (e) => {



        e.preventDefault(); e.stopPropagation();



        scale = 1.0;



        panX = 0;



        panY = 0;



        applyTransform();



      });



    }



    



    // Mouse drag panning



    canvasArea.addEventListener('mousedown', (e) => {
      if (e.button !== 0) return;
      if (e.target.closest('.constellation-node') || e.target.closest('.constellation-team-card') || e.target.closest('.constellation-team-pill') || e.target.closest('button')) return;
      isDragging = true;
      canvasArea.style.cursor = 'grabbing';
      zoomWrapper.style.transition = 'none';
      startX = e.clientX - panX;
      startY = e.clientY - panY;
      e.preventDefault();
    });

    window.addEventListener('mousemove', (e) => {
      if (!isDragging) return;
      panX = e.clientX - startX;
      panY = e.clientY - startY;
      applyTransform();
    });

    window.addEventListener('mouseup', () => {
      if (isDragging) {
        isDragging = false;
        canvasArea.style.cursor = 'grab';
        zoomWrapper.style.transition = 'transform 0.15s cubic-bezier(0.25, 0.46, 0.45, 0.94)';
      }
    })



    



    canvasArea.style.cursor = 'grab';



  });



};



window.updateConstellationPills = function() {



  console.log("[Constellation Engine] Calculating dynamic card KPIs...");



  



  // Find current managers dynamically based on sector or default fallback



  let scrantonMgr = employeesData.find(e => e.roleType === 'managers' && e.sector === 'B2B Sales') || employeesData.find(e => e.name === 'Jane Smith');



  let enterpriseMgr = employeesData.find(e => e.roleType === 'managers' && e.sector === 'Enterprise Sales') || employeesData.find(e => e.name === 'Marcus Dupond');



  let financialMgr = employeesData.find(e => e.roleType === 'managers' && e.sector === 'Accounting & Operations') || employeesData.find(e => e.name === 'Angela Martin');



  



  const scrantonMgrName = scrantonMgr ? scrantonMgr.name : "None";



  const enterpriseMgrName = enterpriseMgr ? enterpriseMgr.name : "None";



  const financialMgrName = financialMgr ? financialMgr.name : "None";







  const updateCardMetrics = (managerName, teamKey, pillId) => {



    const pillEl = document.getElementById(pillId);



    if (!pillEl) return;



    



    // Dynamically update card's manager data attribute



    const cardEl = document.getElementById(`card-${teamKey}-sales`) || 



                   document.getElementById(`card-${teamKey}-ops`) || 



                   document.getElementById(`card-${teamKey}`);



    if (cardEl) {



      cardEl.setAttribute('data-manager', managerName);



      



      // Dynamically render/update the Manager Node in the card



      const mgrNode = cardEl.querySelector('.node-mgr');



      if (mgrNode) {



        const mgr = employeesData.find(e => e.name.trim().toLowerCase() === managerName.trim().toLowerCase());



        if (mgr) {



          mgrNode.id = `node-${mgr.name.toLowerCase().replace(/[^a-z0-9]/g, '-')}`;



          mgrNode.setAttribute('data-name', mgr.name);



          



          const avatarEl = mgrNode.querySelector('div:first-child');



          if (avatarEl) {



            avatarEl.textContent = mgr.initials;



            avatarEl.className = `profile-avatar ${mgr.colorClass || 'bg-purple'}`;



            avatarEl.style.cssText = "width: 32px; height: 32px; border-radius: 50%; display: flex; align-items: center; justify-content: center; color: #fff; font-weight: 800; font-size: 11px; border: 1.5px solid rgba(255,255,255,0.15);";



          }



          



          const strongEl = mgrNode.querySelector('strong');



          if (strongEl) strongEl.textContent = mgr.name;



          



          const spanEl = mgrNode.querySelector('span');



          if (spanEl) spanEl.textContent = mgr.role;



          



          const healthRing = mgrNode.querySelector('.node-health-ring');



          if (healthRing) {



            healthRing.textContent = mgr.health;



            const healthClass = mgr.health >= 90 ? 'health-green' : (mgr.health >= 80 ? 'health-yellow' : 'health-red');



            healthRing.className = `node-health-ring ${healthClass}`;



          }



          mgrNode.style.display = 'flex';



        } else {



          // No manager



          mgrNode.style.display = 'none';



        }



      }



    }



    



    const metrics = window.compileTeamConstellationMetrics(managerName);



    



    // Update compiled score pill



    pillEl.textContent = `${metrics.compiledScore}%`;



    



    // Update dynamic 4-KPI scoreboard deck



    const convEl = document.getElementById(`${teamKey}-avg-conversion`);



    const volEl = document.getElementById(`${teamKey}-avg-volume`);



    const custH = document.getElementById(`${teamKey}-avg-client-health`);



    const prospH = document.getElementById(`${teamKey}-avg-prosp-health`);



    



    if (convEl) convEl.textContent = `${metrics.conversionRate}%`;



    if (volEl) volEl.textContent = (metrics.totalAccounts / Math.max(1, metrics.teamSize)).toFixed(1);



    if (custH) custH.textContent = `${metrics.avgCustHealth}%`;



    if (prospH) prospH.textContent = `${metrics.avgProspHealth}%`;



    



    // Update bottom Live Portfolio cards



    const liveCust = document.getElementById(`${teamKey}-live-customers`);



    const liveProsp = document.getElementById(`${teamKey}-live-prospects`);



    



    if (liveCust) liveCust.textContent = metrics.totalCustomers;



    if (liveProsp) liveProsp.textContent = metrics.totalProspects;



    



    // Color team score pill



    if (metrics.compiledScore >= 90) {



      pillEl.style.backgroundColor = 'rgba(16, 185, 129, 0.15)';



      pillEl.style.color = '#10b981';



      pillEl.style.borderColor = 'rgba(16, 185, 129, 0.45)';



    } else if (metrics.compiledScore >= 80) {



      pillEl.style.backgroundColor = 'rgba(245, 158, 11, 0.15)';



      pillEl.style.color = '#f59e0b';



      pillEl.style.borderColor = 'rgba(245, 158, 11, 0.45)';



    } else {



      pillEl.style.backgroundColor = 'rgba(239, 68, 68, 0.15)';



      pillEl.style.color = '#ef4444';



      pillEl.style.borderColor = 'rgba(239, 68, 68, 0.45)';



    }







    // Dynamic direct representatives rendering



    const repsContainer = document.getElementById(`${teamKey}-reps-container`);



    if (repsContainer) {



      const teamReps = (typeof employeesData !== 'undefined') ? employeesData.filter(e => e.manager && e.manager.trim().toLowerCase() === managerName.trim().toLowerCase() && (e.roleType === 'reps' || e.roleType === 'employee')) : [];



      if (teamReps.length === 0) {



        repsContainer.innerHTML = `<div style="font-size:9px; color:#64748b; font-style:italic; text-align:center; padding:10px 0; width:100%;">No representatives mapped.</div>`;



      } else {



        repsContainer.innerHTML = teamReps.map(rep => {



          const healthClass = rep.health >= 90 ? 'health-green' : (rep.health >= 80 ? 'health-yellow' : 'health-red');



          const nodeId = `node-${rep.name.toLowerCase().replace(/[^a-z0-9]/g, '-')}`;



          return `



            <div class="constellation-node node-rep" id="${nodeId}" data-name="${rep.name}" style="cursor: pointer; position: relative; display: flex; flex-direction: column; align-items: center; padding: 6px 8px; border-radius: 10px; background: rgba(255,255,255,0.015); border: 1px solid rgba(255,255,255,0.06); flex: 1 1 70px; max-width: 80px; min-width: 65px; transition: all 0.2s;">



              <div style="width: 22px; height: 22px; border-radius: 50%; background: rgba(255,255,255,0.05); display: flex; align-items: center; justify-content: center; color: #fff; font-weight: 700; font-size: 9px;">${rep.initials}</div>



              <strong style="display: block; font-size: 9px; color: #ccc; margin-top: 4px; text-align: center; white-space: nowrap;">${rep.name}</strong>



              <div class="node-health-ring ${healthClass}" style="position: absolute; top: -3px; right: -3px; width: 13px; height: 13px; border-radius: 50%; display: flex; align-items: center; justify-content: center; font-size: 6.5px; font-weight: 800; color: #000; border: 1px solid #0a0a0f;">${rep.health}</div>



            </div>



          `;



        }).join('');







        // Wire click handler for dynamic representative nodes



        repsContainer.querySelectorAll('.node-rep').forEach(node => {



          node.addEventListener('click', (e) => {
      if (typeof window.cancelContactEdit === 'function') {
        window.cancelContactEdit();
      }



            e.preventDefault();



            e.stopPropagation();



            window.hydrateConstellationDetail(node);



          });



        });



      }



    }



  };



  



  updateCardMetrics(scrantonMgrName, "scranton", "pill-scranton-sales");



  updateCardMetrics(enterpriseMgrName, "enterprise", "pill-enterprise-sales");



  updateCardMetrics(financialMgrName, "financial", "pill-financial-ops");



};



window.drawConstellationConnections = function() {



  console.log("[Constellation Engine] Connection lines completely disabled per user command.");



  const svg = document.getElementById('constellation-svg-canvas');



  if (svg) {



    svg.innerHTML = '';



  }



};



window.compileTeamConstellationMetrics = function(managerName) {



  const liveEmps = getLiveEmployeesList();
  const allEmployees = (liveEmps && liveEmps.length > 0) ? liveEmps : ((typeof employeesData !== 'undefined') ? employeesData : []);
  const repRecords = allEmployees.filter(e => e.manager && e.manager.trim().toLowerCase() === managerName.trim().toLowerCase() && (e.roleType === 'reps' || e.roleType === 'employee'));



  const avgRepHealth = repRecords.length > 0 ? Math.round(repRecords.reduce((sum, r) => sum + r.health, 0) / repRecords.length) : 0;



  



  const mgrRecord = allEmployees.find(e => e.name && e.name.trim().toLowerCase() === managerName.trim().toLowerCase());



  const mgrHealth = mgrRecord ? mgrRecord.health : 0;



  



  const reps = repRecords.map(r => r.name);



  const teamCustomers = (typeof customersData !== 'undefined') ? customersData.filter(c => reps.includes(c.rep)) : [];



  const avgCustHealth = teamCustomers.length > 0 ? Math.round(teamCustomers.reduce((sum, c) => sum + c.health, 0) / teamCustomers.length) : 0;



  



  const teamProspects = (typeof prospectsData !== 'undefined') ? prospectsData.filter(p => reps.includes(p.rep)) : [];



  const avgProspHealth = teamProspects.length > 0 ? Math.round(teamProspects.reduce((sum, p) => sum + p.health, 0) / teamProspects.length) : 0;



  



  const totalCustomers = repRecords.reduce((sum, r) => sum + (r.customers || 0), 0);



  const totalProspects = repRecords.reduce((sum, r) => sum + (r.prospects || 0), 0);



  const conversionRate = (totalCustomers + totalProspects) > 0 ? Math.round((totalCustomers / (totalCustomers + totalProspects)) * 100) : 0;



  



  const totalGifts = repRecords.reduce((sum, r) => sum + (r.gifts || 0), 0);



  const totalSpend = totalGifts * 45;



  



  const compiledScore = Math.round((conversionRate + avgCustHealth + avgProspHealth + avgRepHealth + mgrHealth) / 5);



  



  return {



    avgRepHealth,



    mgrHealth,



    avgCustHealth,



    avgProspHealth,



    conversionRate,



    totalCustomers,



    totalProspects,



    totalAccounts: totalCustomers + totalProspects,



    teamSize: repRecords.length,



    totalGifts,



    totalSpend,



    compiledScore



  };



};



window.hydrateConstellationDetail = function(el) {



  const container = el.closest('#constellation-screen') || el.closest('#view-constellation') || document;



  const placeholder = container.querySelector('#constellation-panel-placeholder');



  const content = container.querySelector('#constellation-panel-content');



  if (!placeholder || !content) return;



  



  placeholder.style.display = 'none';



  content.style.display = 'flex';



  



  // Determine click target type



  const isTeam = el.classList.contains('constellation-team-pill') || el.classList.contains('constellation-team-card');



  



  const tagEl = container.querySelector('#constellation-panel-tag');



  const titleEl = container.querySelector('#constellation-panel-title');



  const subEl = container.querySelector('#constellation-panel-sub');



  



  // High-fidelity dynamic KPI selectors



  const healthEl = container.querySelector('#constellation-metric-health');



  const lbl2El = container.querySelector('#constellation-metric-lbl2');



  const val2El = container.querySelector('#constellation-metric-val2');



  



  const detLbl1 = container.querySelector('#constellation-lbl-det1');



  const detVal1 = container.querySelector('#constellation-val-det1');



  const detLbl2 = container.querySelector('#constellation-lbl-det2');



  const detVal2 = container.querySelector('#constellation-val-det2');



  const detLbl3 = container.querySelector('#constellation-lbl-det3');



  const detVal3 = container.querySelector('#constellation-val-det3');



  



  const ledgerTitle = container.querySelector('#constellation-gifting-ledger-visual-wrap span');



  const giftsSumEl = container.querySelector('#constellation-val-gifts-sum');



  const spendSumEl = container.querySelector('#constellation-val-spend-sum');



  



  const barReach = container.querySelector('#const-bar-reach');



  const barRetain = container.querySelector('#const-bar-retain');



  const barReward = container.querySelector('#const-bar-reward');



  const barRemember = container.querySelector('#const-bar-remember');



  



  const formattedSpend = (val) => '$' + val.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });



  



  if (isTeam) {



    const teamName = el.getAttribute('data-team') || "Branch Sales Team";



    const managerName = el.getAttribute('data-manager') || "Jane Smith";



    const metrics = window.compileTeamConstellationMetrics(managerName);



    



    tagEl.textContent = "Grouped Team Workspace";



    tagEl.style.backgroundColor = "rgba(16, 185, 129, 0.15)";



    tagEl.style.color = "#10b981";



    



    titleEl.textContent = teamName;



    subEl.textContent = `Team Leader & Manager: ${managerName}`;



    



    // Large prominent compiled score circle



    healthEl.textContent = metrics.compiledScore + '%';



    lbl2El.textContent = "Total Team size";



    val2El.textContent = `${metrics.teamSize + 1} members`;



    val2El.style.color = '#c084fc';



    



    // Exact 5 KPIs in details list



    detLbl1.textContent = "Conversion Rate Avg";



    detVal1.textContent = metrics.conversionRate + '%';



    detLbl2.textContent = "Total B2B Prospects";



    detVal2.textContent = metrics.totalProspects;



    detLbl3.textContent = "Total B2B Customers";



    detVal3.textContent = metrics.totalCustomers;



    



    // Insert dynamic client/prospect health averages in detailed slots



    const statsList = container.querySelector('#constellation-panel-content');



    let extraWrap = container.querySelector('#constellation-team-extra-stats');



    if (!extraWrap) {



      extraWrap = document.createElement('div');



      extraWrap.id = 'constellation-team-extra-stats';



      extraWrap.style.display = 'flex';



      extraWrap.style.flexDirection = 'column';



      extraWrap.style.gap = '10px';



      extraWrap.style.paddingTop = '10px';



      extraWrap.style.borderTop = '1px solid rgba(255,255,255,0.06)';



      



      const ledgerWrap = container.querySelector('#constellation-gifting-ledger-visual-wrap');



      if (ledgerWrap) {



        statsList.insertBefore(extraWrap, ledgerWrap);



      } else {



        statsList.appendChild(extraWrap);



      }



    }



    



    extraWrap.innerHTML = `



      <div style="display: flex; align-items: center; justify-content: space-between; font-size: 11px;">



        <span style="color: #64748b; font-weight: 500;">Avg Customer Health Score</span>



        <strong style="color: #10b981; font-weight: 700;">${metrics.avgCustHealth}%</strong>



      </div>



      <div style="display: flex; align-items: center; justify-content: space-between; font-size: 11px;">



        <span style="color: #64748b; font-weight: 500;">Avg Prospect Health Score</span>



        <strong style="color: #f59e0b; font-weight: 700;">${metrics.avgProspHealth}%</strong>



      </div>



      <div style="display: flex; align-items: center; justify-content: space-between; font-size: 11px;">



        <span style="color: #64748b; font-weight: 500;">Manager Health Score</span>



        <strong style="color: #c084fc; font-weight: 700;">${metrics.mgrHealth}%</strong>



      </div>



    `;



    extraWrap.style.display = 'flex';



    



    // Gifting stats



    if (ledgerTitle) ledgerTitle.textContent = "Grouped Team Gifting ROI Ledger";



    giftsSumEl.textContent = metrics.totalGifts + " Boxes";



    spendSumEl.textContent = formattedSpend(metrics.totalSpend);



    



    // Update bars



    const reachGifts = Math.round(metrics.totalGifts * 0.25);



    const retainGifts = Math.round(metrics.totalGifts * 0.45);



    const rewardGifts = Math.round(metrics.totalGifts * 0.10);



    const rememberGifts = Math.max(0, metrics.totalGifts - (reachGifts + retainGifts + rewardGifts));



    



    const maxVal = Math.max(1, reachGifts, retainGifts, rewardGifts, rememberGifts);



    barReach.style.height = `${(reachGifts / maxVal) * 85 + 15}px`;



    barRetain.style.height = `${(retainGifts / maxVal) * 85 + 15}px`;



    barReward.style.height = `${(rewardGifts / maxVal) * 85 + 15}px`;



    barRemember.style.height = `${(rememberGifts / maxVal) * 85 + 15}px`;



    



  } else {



    // Individual Team Member Node Click



    const empName = el.getAttribute('data-name');



    const emp = (typeof employeesData !== 'undefined') ? employeesData.find(e => e.name === empName) : null;



    if (!emp) return;



    



    tagEl.textContent = emp.roleType.toUpperCase();



    if (emp.roleType === 'executives') {



      tagEl.textContent = "Executive";



      tagEl.style.backgroundColor = "rgba(16, 185, 129, 0.15)";



      tagEl.style.color = "#10b981";



    } else if (emp.roleType === 'managers') {



      tagEl.textContent = "Team Leader / Manager";



      tagEl.style.backgroundColor = "rgba(59, 130, 246, 0.15)";



      tagEl.style.color = "#3b82f6";



    } else {



      tagEl.textContent = "Field Representative";



      tagEl.style.backgroundColor = "rgba(255, 255, 255, 0.05)";



      tagEl.style.color = "#94a3b8";



    }



    



    titleEl.textContent = emp.name;



    subEl.textContent = emp.role;



    



    // Dynamic individual client / prospect lists health calculations



    const indivCustomers = (typeof customersData !== 'undefined') ? customersData.filter(c => c.rep === emp.name) : [];



    const avgCustHealth = indivCustomers.length > 0 ? Math.round(indivCustomers.reduce((sum, c) => sum + c.health, 0) / indivCustomers.length) : 0;



    



    const indivProspects = (typeof prospectsData !== 'undefined') ? prospectsData.filter(p => p.rep === emp.name) : [];



    const avgProspHealth = indivProspects.length > 0 ? Math.round(indivProspects.reduce((sum, p) => sum + p.health, 0) / indivProspects.length) : 0;



    



    const conversionRate = (emp.customers + emp.prospects) > 0 ? Math.round((emp.customers / (emp.customers + emp.prospects)) * 100) : 0;



    



    // Highlight their representative health score



    healthEl.textContent = emp.health + '%';



    lbl2El.textContent = "Account Volume";



    val2El.textContent = `${emp.customers + emp.prospects} accounts`;



    val2El.style.color = '#3b82f6';



    



    // Exact 5 KPIs requested inside the side menu



    detLbl1.textContent = "Conversion Rate Avg";



    detVal1.textContent = conversionRate + '%';



    detLbl2.textContent = "Total B2B Prospects";



    detVal2.textContent = emp.prospects || 0;



    detLbl3.textContent = "Total B2B Customers";



    detVal3.textContent = emp.customers || 0;



    



    // Remove extra team stats block if visible



    const statsList = container.querySelector('#constellation-panel-content');



    let extraWrap = container.querySelector('#constellation-team-extra-stats');



    if (!extraWrap) {



      extraWrap = document.createElement('div');



      extraWrap.id = 'constellation-team-extra-stats';



      extraWrap.style.display = 'flex';



      extraWrap.style.flexDirection = 'column';



      extraWrap.style.gap = '10px';



      extraWrap.style.paddingTop = '10px';



      extraWrap.style.borderTop = '1px solid rgba(255,255,255,0.06)';



      



      const ledgerWrap = container.querySelector('#constellation-gifting-ledger-visual-wrap');



      if (ledgerWrap) {



        statsList.insertBefore(extraWrap, ledgerWrap);



      } else {



        statsList.appendChild(extraWrap);



      }



    }



    



    extraWrap.innerHTML = `



      <div style="display: flex; align-items: center; justify-content: space-between; font-size: 11px;">



        <span style="color: #64748b; font-weight: 500;">Avg Customer Health Score</span>



        <strong style="color: #10b981; font-weight: 700;">${avgCustHealth}%</strong>



      </div>



      <div style="display: flex; align-items: center; justify-content: space-between; font-size: 11px;">



        <span style="color: #64748b; font-weight: 500;">Avg Prospect Health Score</span>



        <strong style="color: #f59e0b; font-weight: 700;">${avgProspHealth}%</strong>



      </div>



      <div style="display: flex; align-items: center; justify-content: space-between; font-size: 11px;">



        <span style="color: #64748b; font-weight: 500;">Direct Supervisor</span>



        <strong style="color: #94a3b8; font-weight: 700;">${emp.manager || "N/A"}</strong>



      </div>



    `;



    extraWrap.style.display = 'flex';



    



    // Gifting stats



    if (ledgerTitle) ledgerTitle.textContent = "Individual Gifting ROI Ledger";



    const valGifts = emp.gifts || 0;



    giftsSumEl.textContent = valGifts + " Boxes";



    spendSumEl.textContent = formattedSpend(valGifts * 45);



    



    // Update bars



    const reachGifts = Math.round(valGifts * 0.25);



    const retainGifts = Math.round(valGifts * 0.45);



    const rewardGifts = 0;



    const rememberGifts = Math.max(0, valGifts - (reachGifts + retainGifts + rewardGifts));



    



    const maxVal = Math.max(1, reachGifts, retainGifts, rewardGifts, rememberGifts);



    barReach.style.height = `${(reachGifts / maxVal) * 85 + 15}px`;



    barRetain.style.height = `${(retainGifts / maxVal) * 85 + 15}px`;



    barReward.style.height = `${(rewardGifts / maxVal) * 85 + 15}px`;



    barRemember.style.height = `${(rememberGifts / maxVal) * 85 + 15}px`;



  }



};











