document.addEventListener('DOMContentLoaded', () => {



  // Initialize employee timeline tab state
  window.employeeTimelineTab = 'activity';

  // Global helper to switch active profiles dynamically
  window.switchToProfile = function(name, type) {
    if (!name || !type) return;
    
    // Find the registry list element with matching name and click it to change the active profile!
    let found = false;
    document.querySelectorAll('[data-name]').forEach(el => {
      const elType = el.getAttribute('data-type') || '';
      if (el.getAttribute('data-name').trim() === name.trim() && elType.toLowerCase() === type.toLowerCase()) {
        el.click();
        found = true;
      }
    });
    
    if (!found) {
      document.querySelectorAll('.registry-row, .list-item, .employee-item').forEach(el => {
        const elName = (el.getAttribute('data-name') || el.getAttribute('data-contact') || el.textContent.trim()).trim();
        const elType = el.getAttribute('data-type') || '';
        if (elName === name && elType.toLowerCase() === type.toLowerCase()) {
          el.click();
          found = true;
        }
      });
    }

    if (!found) {
      // Fallback
      window.activeProfileName = name;
      window.activeProfileType = type.toLowerCase();
      window.refreshActiveDetailPanel();
    }
  };

  // Add click handlers for employee timeline tab toggle buttons dynamically when clicking
  document.addEventListener('click', (e) => {
    const activityBtn = e.target.closest('#btn-employee-tab-activity') || e.target.closest('#timeline-toggle-activity');
    const reportBtn = e.target.closest('#btn-employee-tab-report') || e.target.closest('#timeline-toggle-report');
    const exportBtn = e.target.closest('#btn-employee-tab-export');
    const printBtn = e.target.closest('#btn-employee-tab-print');

    if (activityBtn) {
      window.employeeTimelineTab = 'activity';
      const btns = [
        document.getElementById('btn-employee-tab-activity'),
        document.getElementById('timeline-toggle-activity')
      ];
      btns.forEach(b => {
        if (b) {
          b.classList.add('active');
          if (b.id === 'timeline-toggle-activity') {
            b.style.background = 'rgba(59, 130, 246, 0.15)';
            b.style.color = '#3b82f6';
          }
        }
      });
      const rBtns = [
        document.getElementById('btn-employee-tab-report'),
        document.getElementById('timeline-toggle-report')
      ];
      rBtns.forEach(r => {
        if (r) {
          r.classList.remove('active');
          if (r.id === 'timeline-toggle-report') {
            r.style.background = 'transparent';
            r.style.color = '#64748b';
          }
        }
      });
      if (typeof renderTimeline === 'function') {
        renderTimeline(window.activeProfileName);
      }
    } else if (reportBtn) {
      window.employeeTimelineTab = 'report';
      const btns = [
        document.getElementById('btn-employee-tab-report'),
        document.getElementById('timeline-toggle-report')
      ];
      btns.forEach(b => {
        if (b) {
          b.classList.add('active');
          if (b.id === 'timeline-toggle-report') {
            b.style.background = 'rgba(59, 130, 246, 0.15)';
            b.style.color = '#3b82f6';
          }
        }
      });
      const aBtns = [
        document.getElementById('btn-employee-tab-activity'),
        document.getElementById('timeline-toggle-activity')
      ];
      aBtns.forEach(a => {
        if (a) {
          a.classList.remove('active');
          if (a.id === 'timeline-toggle-activity') {
            a.style.background = 'transparent';
            a.style.color = '#64748b';
          }
        }
      });
      if (typeof renderTimeline === 'function') {
        renderTimeline(window.activeProfileName);
      }
    } else if (exportBtn) {
      // Premium Export Feature! Show confirmation toast or alert with data
      const name = window.activeProfileName;
      const myClients = (typeof customersData !== 'undefined' ? customersData : []).filter(c => c.rep === name);
      const myProspects = (typeof prospectsData !== 'undefined' ? prospectsData : []).filter(p => p.rep === name);
      
      const csvLines = [
        ['Type', 'Name', 'Rep', 'Health', 'Inactive Days', 'Calls Logged', 'Gifts Dispatched'],
        ...myClients.map(c => ['Client', c.name, c.rep, c.health, c.inactiveDays || 0, c.calls || 0, c.gifts || 0]),
        ...myProspects.map(p => ['Prospect', p.name, p.rep, p.health, p.inactiveDays || 0, p.calls || 0, p.gifts || 0])
      ];
      
      const csvContent = "data:text/csv;charset=utf-8," + csvLines.map(e => e.map(val => `"${val}"`).join(",")).join("\n");
      const encodedUri = encodeURI(csvContent);
      const link = document.createElement("a");
      link.setAttribute("href", encodedUri);
      link.setAttribute("download", `${name.replace(/\s+/g, '_')}_Report_Card.csv`);
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);

      // Toast notification if helper exists
      if (typeof showToast === 'function') {
        showToast('Export Successful', `Exported Report Card for ${name} to CSV.`);
      } else {
        alert(`Exported Report Card for ${name} to CSV.`);
      }
    } else if (printBtn) {
      // Print report card! Focus on the detail-timeline-list container and print it!
      const timelineEl = document.getElementById('detail-timeline-list');
      if (timelineEl) {
        const printWindow = window.open('', '_blank');
        printWindow.document.write(`
          <html>
            <head>
              <title>Employee Performance Report - ${window.activeProfileName}</title>
              <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;500;700&display=swap" rel="stylesheet">
              <style>
                body {
                  background: #0b0f19;
                  color: #f8fafc;
                  font-family: 'Outfit', sans-serif;
                  padding: 40px;
                }
                .report-card-container {
                  max-width: 800px;
                  margin: 0 auto;
                  border: 1px solid rgba(255, 255, 255, 0.1);
                  border-radius: 16px;
                  padding: 24px;
                  background: #111827;
                }
                .metric-card {
                  background: rgba(255, 255, 255, 0.05) !important;
                  border: 1px solid rgba(255, 255, 255, 0.1) !important;
                  padding: 16px;
                  border-radius: 12px;
                }
                .report-grid {
                  display: grid;
                  grid-template-columns: repeat(2, 1fr);
                  gap: 16px;
                }
                h5 {
                  font-size: 16px;
                  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
                  padding-bottom: 8px;
                  margin-top: 24px;
                }
                button { display: none !important; }
              </style>
            </head>
            <body onload="window.print(); window.close();">
              <h2 style="text-align: center; margin-bottom: 20px;">WhiteBox RMOS Performance Report</h2>
              <h3 style="text-align: center; color: #3b82f6; margin-bottom: 40px;">Employee: ${window.activeProfileName}</h3>
              ${timelineEl.innerHTML}
            </body>
          </html>
        `);
        printWindow.document.close();
      }
    }
  });

  // 1. Initialize settings structure



  window.rmosSettings = {



    decayWarning: 30,



    decayCritical: 60,



    targetConversion: 48,



    hoursStart: '09:00',



    hoursEnd: '17:00',



    nudgeCap: 5,



    autoNeglect: true,



    managerOverride: true,



    alertRouting: true,



    budgetMilestone: 45.00,



    budgetMonthly: 500.00,



    approvalGate: true,



    approvalThreshold: 100.00,



    autoGifting: true,



    webhooks: {



      slack: '',



      teams: ''



    },



    integrations: {



      salesforce: false,



      hubspot: false,



      twilio: false,



      ringcentral: false,



      gmail: false,



      outlook: false



    }



  };







  // Pre-load saved settings if present in LocalStorage



  const savedSettings = localStorage.getItem('rmos_system_settings');



  if (savedSettings) {



    try {



      const parsed = JSON.parse(savedSettings);



      window.rmosSettings = { ...window.rmosSettings, ...parsed };



    } catch (e) {



      console.error("Error loading system settings:", e);



    }



  }







  // Intercept the default getInactivityStatus function



  if (typeof window.getInactivityStatus === 'function') {



    const originalGetStatus = window.getInactivityStatus;



    window.getInactivityStatus = function(days) {



      if (!window.rmosSettings) return originalGetStatus(days);



      if (days >= window.rmosSettings.decayCritical) return 'red';



      if (days >= window.rmosSettings.decayWarning) return 'orange';



      return 'green';



    };



  }







  // Intercept neglected filter checks by rewriting or overriding neglected count calculations



  if (typeof window.updateCustomersScorecards === 'function') {



    const originalUpdate = window.updateCustomersScorecards;



    window.updateCustomersScorecards = function(dataset) {



      const totalVal = document.getElementById('cust-card-total-val');



      const avgHealthVal = document.getElementById('cust-card-avg-health-val');



      const neglectedVal = document.getElementById('cust-card-neglected-val');



      const giftsVal = document.getElementById('cust-card-gifts-val');







      if (dataset && dataset.length) {



        const total = dataset.length;



        const avgHealth = Math.round(dataset.reduce((acc, cust) => acc + cust.health, 0) / total);



        const neglected = dataset.filter(cust => cust.inactiveDays >= window.rmosSettings.decayCritical).length;



        const gifts = dataset.reduce((acc, cust) => acc + cust.gifts, 0);







        if (totalVal) totalVal.textContent = total;



        if (avgHealthVal) avgHealthVal.textContent = avgHealth + '%';



        if (neglectedVal) {



          neglectedVal.textContent = neglected;



          neglectedVal.className = `kpi-value ${neglected > 0 ? 'value-red' : ''}`;



        }



        if (giftsVal) giftsVal.textContent = gifts;



      } else {



        if (totalVal) totalVal.textContent = '0';



        if (avgHealthVal) avgHealthVal.textContent = '0%';



        if (neglectedVal) {



          neglectedVal.textContent = '0';



          neglectedVal.className = 'kpi-value';



        }



        if (giftsVal) giftsVal.textContent = '0';



      }



    };



  }







  if (typeof window.updateProspectsScorecards === 'function') {



    const originalUpdate = window.updateProspectsScorecards;



    window.updateProspectsScorecards = function(dataset) {



      const totalVal = document.getElementById('prosp-card-total-val');



      const avgHealthVal = document.getElementById('prosp-card-avg-health-val');



      const neglectedVal = document.getElementById('prosp-card-neglected-val');



      const giftsVal = document.getElementById('prosp-card-gifts-val');







      if (dataset && dataset.length) {



        const total = dataset.length;



        const avgHealth = Math.round(dataset.reduce((acc, prosp) => acc + prosp.health, 0) / total);



        const neglected = dataset.filter(prosp => prosp.inactiveDays >= window.rmosSettings.decayCritical).length;



        const gifts = dataset.reduce((acc, prosp) => acc + prosp.gifts, 0);







        if (totalVal) totalVal.textContent = total;



        if (avgHealthVal) avgHealthVal.textContent = avgHealth + '%';



        if (neglectedVal) {



          neglectedVal.textContent = neglected;



          neglectedVal.className = `kpi-value ${neglected > 0 ? 'value-red' : ''}`;



        }



        if (giftsVal) giftsVal.textContent = gifts;



      } else {



        if (totalVal) totalVal.textContent = '0';



        if (avgHealthVal) avgHealthVal.textContent = '0%';



        if (neglectedVal) {



          neglectedVal.textContent = '0';



          neglectedVal.className = 'kpi-value';



        }



        if (giftsVal) giftsVal.textContent = '0';



      }



    };



  }







  // 2. Settings Tab Navigation Switching



  const settingsTabWrapper = document.getElementById('view-settings');



  if (settingsTabWrapper) {



    const navItems = settingsTabWrapper.querySelectorAll('.settings-nav-item');



    const panelCards = settingsTabWrapper.querySelectorAll('.settings-panel-card');







    navItems.forEach(btn => {



      btn.addEventListener('click', () => {



        // Clear active



        navItems.forEach(i => i.classList.remove('active'));



        panelCards.forEach(c => c.classList.remove('active'));







        // Set active



        btn.classList.add('active');



        const targetId = btn.getAttribute('data-target');



        const targetCard = document.getElementById(targetId);



        if (targetCard) {



          targetCard.classList.add('active');



        }



      });



    });



  }







  // Helper function to show notifications/toasts



  function triggerNotification(message, type = 'success') {



    if (typeof window.showToast === 'function') {



      window.showToast(message, type);



    } else if (typeof window.showNotification === 'function') {



      window.showNotification(message, type);



    } else {



      // Fallback custom alert toast



      let toast = document.getElementById('rmos-custom-toast');



      if (!toast) {



        toast = document.createElement('div');



        toast.id = 'rmos-custom-toast';



        toast.style.cssText = 'position: fixed; bottom: 30px; right: 30px; z-index: 999999; padding: 14px 24px; border-radius: 8px; background: rgba(10,11,18,0.95); border: 1px solid rgba(168,85,247,0.4); color: #fff; font-family: Outfit, sans-serif; font-size: 13px; font-weight: 600; box-shadow: 0 10px 30px rgba(0,0,0,0.5); backdrop-filter: blur(10px); transition: all 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275); transform: translateY(100px); opacity: 0;';



        document.body.appendChild(toast);



      }



      toast.textContent = message;



      toast.style.borderColor = type === 'success' ? 'rgba(16,185,129,0.5)' : 'rgba(239,68,68,0.5)';



      toast.style.transform = 'translateY(0)';



      toast.style.opacity = '1';



      setTimeout(() => {



        toast.style.transform = 'translateY(100px)';



        toast.style.opacity = '0';



      }, 3500);



    }



  }







  // 3. Range Sliders Live Updates



  const setupSlider = (inputId, valId, unit = '') => {



    const input = document.getElementById(inputId);



    const badge = document.getElementById(valId);



    if (input && badge) {



      // Initialize val



      input.value = window.rmosSettings[inputId.replace('input-', '').replace('-', '')] || input.value;



      badge.textContent = `${input.value}${unit}`;







      input.addEventListener('input', (e) => {



        badge.textContent = `${e.target.value}${unit}`;



      });



    }



  };







  setupSlider('input-decay-warning', 'val-decay-warning', ' Days');



  setupSlider('input-decay-critical', 'val-decay-critical', ' Days');



  setupSlider('input-target-conversion', 'val-target-conversion', '%');



  setupSlider('input-nudge-cap', 'val-nudge-cap', ' Nudges');







  // Populate inputs with current settings values



  const hoursStart = document.getElementById('input-hours-start');



  const hoursEnd = document.getElementById('input-hours-end');



  if (hoursStart) hoursStart.value = window.rmosSettings.hoursStart;



  if (hoursEnd) hoursEnd.value = window.rmosSettings.hoursEnd;







  const autoNeglect = document.getElementById('input-auto-neglect');



  if (autoNeglect) autoNeglect.checked = window.rmosSettings.autoNeglect;







  const managerOverride = document.getElementById('input-manager-override');



  if (managerOverride) managerOverride.checked = window.rmosSettings.managerOverride;







  const alertRouting = document.getElementById('input-alert-routing');



  if (alertRouting) alertRouting.checked = window.rmosSettings.alertRouting;







  const budgetMilestone = document.getElementById('input-budget-milestone');



  const budgetMonthly = document.getElementById('input-budget-monthly');



  if (budgetMilestone) budgetMilestone.value = window.rmosSettings.budgetMilestone;



  if (budgetMonthly) budgetMonthly.value = window.rmosSettings.budgetMonthly;







  const approvalGate = document.getElementById('input-approval-gate');



  const approvalThreshold = document.getElementById('input-approval-threshold');



  if (approvalGate) approvalGate.checked = window.rmosSettings.approvalGate;



  if (approvalThreshold) approvalThreshold.value = window.rmosSettings.approvalThreshold;







  const autoGifting = document.getElementById('input-auto-gifting');



  if (autoGifting) autoGifting.checked = window.rmosSettings.autoGifting;







  const webhookSlack = document.getElementById('input-webhook-slack');



  const webhookTeams = document.getElementById('input-webhook-teams');



  if (webhookSlack) webhookSlack.value = window.rmosSettings.webhooks.slack;



  if (webhookTeams) webhookTeams.value = window.rmosSettings.webhooks.teams;







  // 4. Save General Settings Form



  const formGeneral = document.getElementById('settings-form-general');



  if (formGeneral) {



    formGeneral.addEventListener('submit', (e) => {



      e.preventDefault();



      



      const valWarning = parseInt(document.getElementById('input-decay-warning').value);



      const valCritical = parseInt(document.getElementById('input-decay-critical').value);







      if (valWarning >= valCritical) {



        triggerNotification("Warning: Inactivity Warning Threshold must be smaller than Critical Neglect Threshold.", "error");



        return;



      }







      window.rmosSettings.decayWarning = valWarning;



      window.rmosSettings.decayCritical = valCritical;



      window.rmosSettings.targetConversion = parseInt(document.getElementById('input-target-conversion').value);



      window.rmosSettings.hoursStart = document.getElementById('input-hours-start').value;



      window.rmosSettings.hoursEnd = document.getElementById('input-hours-end').value;



      window.rmosSettings.nudgeCap = parseInt(document.getElementById('input-nudge-cap').value);



      window.rmosSettings.autoNeglect = document.getElementById('input-auto-neglect').checked;







      // Save to local storage



      localStorage.setItem('rmos_system_settings', JSON.stringify(window.rmosSettings));







      // Trigger recalculation across all panels



      try {



        if (typeof window.renderOverviewRegistry === 'function') window.renderOverviewRegistry();



        if (typeof window.renderCustomersList === 'function') window.renderCustomersList();



        if (typeof window.renderProspectsList === 'function') window.renderProspectsList();



        if (typeof window.renderEmployeesList === 'function') window.renderEmployeesList();



      } catch (err) {



        console.error("Error refreshing dashboard stats:", err);



      }







      triggerNotification("General operating parameters saved successfully. Dashboard KPIs updated!");



    });



  }







  // 5. Save Gifting Settings Form



  const formGifting = document.getElementById('settings-form-gifting');



  if (formGifting) {



    formGifting.addEventListener('submit', (e) => {



      e.preventDefault();







      window.rmosSettings.budgetMilestone = parseFloat(document.getElementById('input-budget-milestone').value);



      window.rmosSettings.budgetMonthly = parseFloat(document.getElementById('input-budget-monthly').value);



      window.rmosSettings.approvalGate = document.getElementById('input-approval-gate').checked;



      window.rmosSettings.approvalThreshold = parseFloat(document.getElementById('input-approval-threshold').value);



      window.rmosSettings.autoGifting = document.getElementById('input-auto-gifting').checked;







      localStorage.setItem('rmos_system_settings', JSON.stringify(window.rmosSettings));



      triggerNotification("Financial policies and gifting budget thresholds saved successfully.");



    });



  }







  // 6. Save Webhooks



  const btnWebhooks = document.getElementById('btn-save-webhooks');



  if (btnWebhooks) {



    btnWebhooks.addEventListener('click', (e) => {



      e.preventDefault();



      



      const slackUrl = document.getElementById('input-webhook-slack').value;



      const teamsUrl = document.getElementById('input-webhook-teams').value;







      if (slackUrl && !slackUrl.startsWith('https://hooks.slack.com/')) {



        triggerNotification("Invalid Slack Webhook URL structure.", "error");



        return;



      }



      if (teamsUrl && !teamsUrl.startsWith('https://')) {



        triggerNotification("Invalid Microsoft Teams Connector URL.", "error");



        return;



      }







      window.rmosSettings.webhooks.slack = slackUrl;



      window.rmosSettings.webhooks.teams = teamsUrl;







      localStorage.setItem('rmos_system_settings', JSON.stringify(window.rmosSettings));



      triggerNotification("Operational alert webhooks stored successfully. Twoway webhook handshakes activated!");



    });



  }







  // 7. Integrations Hub Configuration Forms & Setup Controllers

  // Load integration configs from LocalStorage
  const getIntegrationConfigs = () => {
    try {
      const configs = localStorage.getItem('rmos_integration_configs');
      return configs ? JSON.parse(configs) : {};
    } catch (e) {
      console.error("Error reading integration configs:", e);
      return {};
    }
  };

  const saveIntegrationConfigs = (configs) => {
    try {
      localStorage.setItem('rmos_integration_configs', JSON.stringify(configs));
    } catch (e) {
      console.error("Error saving integration configs:", e);
    }
  };

  const initIntegrationsHub = () => {
    const pane = document.getElementById('settings-pane-integrations');
    if (!pane) return;

    const platforms = ['salesforce', 'hubspot', 'twilio', 'ringcentral', 'gmail', 'outlook'];
    const configs = getIntegrationConfigs();

    platforms.forEach(platform => {
      const card = document.getElementById(`card-integration-${platform}`);
      if (!card) return;

      const viewState = card.querySelector('.connection-view-state');
      const setupState = card.querySelector('.connection-setup-state');
      const btnConnect = card.querySelector('.btn-connect');
      const btnConfigure = card.querySelector('.btn-configure');
      const btnCancel = card.querySelector('.btn-setup-cancel');
      const btnSave = card.querySelector('.btn-setup-save');
      const btnTest = card.querySelector('.btn-test-connection');
      const badge = document.getElementById(`badge-${platform}`);
      const statusDiv = document.getElementById(`status-${platform}`);

      // 1. Pre-populate form inputs if we have saved configs
      const platformConfig = configs[platform] || {};
      
      // Populate Salesforce inputs
      if (platform === 'salesforce') {
        if (platformConfig.url) document.getElementById('salesforce-url').value = platformConfig.url;
        if (platformConfig.clientId) document.getElementById('salesforce-client-id').value = platformConfig.clientId;
        if (platformConfig.clientSecret) document.getElementById('salesforce-client-secret').value = platformConfig.clientSecret;
        document.getElementById('salesforce-sync-contacts').checked = platformConfig.syncContacts !== false;
        document.getElementById('salesforce-sync-deals').checked = platformConfig.syncDeals !== false;
      }
      // Populate HubSpot inputs
      if (platform === 'hubspot') {
        if (platformConfig.portalId) document.getElementById('hubspot-portal-id').value = platformConfig.portalId;
        if (platformConfig.token) document.getElementById('hubspot-token').value = platformConfig.token;
        document.getElementById('hubspot-sync-contacts').checked = platformConfig.syncContacts !== false;
        document.getElementById('hubspot-sync-deals').checked = platformConfig.syncDeals !== false;
      }
      // Populate Twilio inputs
      if (platform === 'twilio') {
        if (platformConfig.sid) document.getElementById('twilio-sid').value = platformConfig.sid;
        if (platformConfig.token) document.getElementById('twilio-token').value = platformConfig.token;
        if (platformConfig.phone) document.getElementById('twilio-phone').value = platformConfig.phone;
        document.getElementById('twilio-sync-sms').checked = platformConfig.syncSms !== false;
        document.getElementById('twilio-sync-voice').checked = platformConfig.syncVoice !== false;
      }
      // Populate RingCentral inputs
      if (platform === 'ringcentral') {
        if (platformConfig.url) document.getElementById('ringcentral-url').value = platformConfig.url;
        if (platformConfig.clientId) document.getElementById('ringcentral-client-id').value = platformConfig.clientId;
        if (platformConfig.clientSecret) document.getElementById('ringcentral-client-secret').value = platformConfig.clientSecret;
        document.getElementById('ringcentral-sync-recordings').checked = platformConfig.syncRecordings !== false;
        document.getElementById('ringcentral-sync-history').checked = platformConfig.syncHistory !== false;
      }
      // Populate Gmail inputs
      if (platform === 'gmail') {
        if (platformConfig.clientId) document.getElementById('gmail-client-id').value = platformConfig.clientId;
        if (platformConfig.serviceAccount) document.getElementById('gmail-service-account').value = platformConfig.serviceAccount;
        document.getElementById('gmail-meta-only').checked = platformConfig.metaOnly !== false;
      }
      // Populate Outlook inputs
      if (platform === 'outlook') {
        if (platformConfig.tenantId) document.getElementById('outlook-tenant-id').value = platformConfig.tenantId;
        if (platformConfig.clientId) document.getElementById('outlook-client-id').value = platformConfig.clientId;
        if (platformConfig.clientSecret) document.getElementById('outlook-client-secret').value = platformConfig.clientSecret;
      }

      // 2. Set initial connection UI state based on window.rmosSettings
      const isConnected = window.rmosSettings.integrations[platform];
      if (isConnected) {
        if (btnConnect) {
          btnConnect.textContent = "Disconnect";
          btnConnect.className = "btn-connection-action btn-disconnect";
        }
        if (btnConfigure) btnConfigure.style.display = 'block';
        if (badge) {
          badge.textContent = "Connected";
          badge.className = "connection-status-badge connected";
        }
      } else {
        if (btnConnect) {
          btnConnect.textContent = "Connect";
          btnConnect.className = "btn-connection-action btn-connect";
        }
        if (btnConfigure) btnConfigure.style.display = 'none';
        if (badge) {
          badge.textContent = "Disconnected";
          badge.className = "connection-status-badge disconnected";
        }
      }

      // 3. Connect/Disconnect Toggle Button Handler
      if (btnConnect) {
        btnConnect.addEventListener('click', (e) => {
          e.preventDefault();
          const activeState = window.rmosSettings.integrations[platform];
          if (activeState) {
            // Disconnect flow
            if (confirm(`Are you sure you want to disconnect ${platform.charAt(0).toUpperCase() + platform.slice(1)} and revoke credentials?`)) {
              window.rmosSettings.integrations[platform] = false;
              localStorage.setItem('rmos_system_settings', JSON.stringify(window.rmosSettings));
              
              // Remove configs
              const currentConfigs = getIntegrationConfigs();
              delete currentConfigs[platform];
              saveIntegrationConfigs(currentConfigs);

              // Reset inputs
              if (platform === 'salesforce') {
                document.getElementById('salesforce-client-id').value = '';
                document.getElementById('salesforce-client-secret').value = '';
              } else if (platform === 'hubspot') {
                document.getElementById('hubspot-portal-id').value = '';
                document.getElementById('hubspot-token').value = '';
              } else if (platform === 'twilio') {
                document.getElementById('twilio-sid').value = '';
                document.getElementById('twilio-token').value = '';
                document.getElementById('twilio-phone').value = '';
              } else if (platform === 'ringcentral') {
                document.getElementById('ringcentral-client-id').value = '';
                document.getElementById('ringcentral-client-secret').value = '';
              } else if (platform === 'gmail') {
                document.getElementById('gmail-client-id').value = '';
                document.getElementById('gmail-service-account').value = '';
              } else if (platform === 'outlook') {
                document.getElementById('outlook-tenant-id').value = '';
                document.getElementById('outlook-client-id').value = '';
                document.getElementById('outlook-client-secret').value = '';
              }

              // Update UI
              btnConnect.textContent = "Connect";
              btnConnect.className = "btn-connection-action btn-connect";
              if (btnConfigure) btnConfigure.style.display = 'none';
              if (badge) {
                badge.textContent = "Disconnected";
                badge.className = "connection-status-badge disconnected";
              }
              if (statusDiv) statusDiv.style.display = 'none';
              triggerNotification(`Severed credential sync with ${platform.toUpperCase()}.`);
            }
          } else {
            // Show setup form state
            viewState.style.display = 'none';
            setupState.style.display = 'block';
          }
        });
      }

      // 4. Configure Button Handler
      if (btnConfigure) {
        btnConfigure.addEventListener('click', (e) => {
          e.preventDefault();
          viewState.style.display = 'none';
          setupState.style.display = 'block';
        });
      }

      // 5. Cancel Button Handler
      if (btnCancel) {
        btnCancel.addEventListener('click', (e) => {
          e.preventDefault();
          setupState.style.display = 'none';
          viewState.style.display = 'block';
          if (statusDiv) statusDiv.style.display = 'none';
        });
      }

      // 6. Test Connection Button Handler (Simulated server auth)
      if (btnTest) {
        btnTest.addEventListener('click', (e) => {
          e.preventDefault();
          
          // Verify we have fields
          let validated = true;
          if (platform === 'salesforce' && (!document.getElementById('salesforce-client-id').value || !document.getElementById('salesforce-client-secret').value)) validated = false;
          if (platform === 'hubspot' && (!document.getElementById('hubspot-portal-id').value || !document.getElementById('hubspot-token').value)) validated = false;
          if (platform === 'twilio' && (!document.getElementById('twilio-sid').value || !document.getElementById('twilio-token').value || !document.getElementById('twilio-phone').value)) validated = false;
          if (platform === 'ringcentral' && (!document.getElementById('ringcentral-client-id').value || !document.getElementById('ringcentral-client-secret').value)) validated = false;
          if (platform === 'gmail' && (!document.getElementById('gmail-client-id').value || !document.getElementById('gmail-service-account').value)) validated = false;
          if (platform === 'outlook' && (!document.getElementById('outlook-tenant-id').value || !document.getElementById('outlook-client-id').value || !document.getElementById('outlook-client-secret').value)) validated = false;

          if (statusDiv) {
            statusDiv.style.display = 'block';
            if (!validated) {
              statusDiv.textContent = "✗ Connection failed: Required credential fields cannot be blank.";
              statusDiv.style.color = "#ef4444";
              return;
            }

            btnTest.textContent = "Testing API connection...";
            btnTest.style.pointerEvents = 'none';
            btnTest.style.opacity = '0.6';
            statusDiv.textContent = "Connecting to remote gateway handshake endpoint...";
            statusDiv.style.color = "#94a3b8";

            setTimeout(() => {
              statusDiv.textContent = `✓ Handshake verified with ${platform.toUpperCase()} API Server. Client authentication active.`;
              statusDiv.style.color = "#10b981";
              btnTest.textContent = "Test Connection";
              btnTest.style.pointerEvents = 'auto';
              btnTest.style.opacity = '1';
            }, 1200);
          }
        });
      }

      // 7. Save Setup Button Handler
      if (btnSave) {
        btnSave.addEventListener('click', (e) => {
          e.preventDefault();
          
          let validated = true;
          const currentConfigs = getIntegrationConfigs();
          const info = {};

          if (platform === 'salesforce') {
            info.url = document.getElementById('salesforce-url').value;
            info.clientId = document.getElementById('salesforce-client-id').value;
            info.clientSecret = document.getElementById('salesforce-client-secret').value;
            info.syncContacts = document.getElementById('salesforce-sync-contacts').checked;
            info.syncDeals = document.getElementById('salesforce-sync-deals').checked;
            if (!info.clientId || !info.clientSecret) validated = false;
          } else if (platform === 'hubspot') {
            info.portalId = document.getElementById('hubspot-portal-id').value;
            info.token = document.getElementById('hubspot-token').value;
            info.syncContacts = document.getElementById('hubspot-sync-contacts').checked;
            info.syncDeals = document.getElementById('hubspot-sync-deals').checked;
            if (!info.portalId || !info.token) validated = false;
          } else if (platform === 'twilio') {
            info.sid = document.getElementById('twilio-sid').value;
            info.token = document.getElementById('twilio-token').value;
            info.phone = document.getElementById('twilio-phone').value;
            info.syncSms = document.getElementById('twilio-sync-sms').checked;
            info.syncVoice = document.getElementById('twilio-sync-voice').checked;
            if (!info.sid || !info.token || !info.phone) validated = false;
          } else if (platform === 'ringcentral') {
            info.url = document.getElementById('ringcentral-url').value;
            info.clientId = document.getElementById('ringcentral-client-id').value;
            info.clientSecret = document.getElementById('ringcentral-client-secret').value;
            info.syncRecordings = document.getElementById('ringcentral-sync-recordings').checked;
            info.syncHistory = document.getElementById('ringcentral-sync-history').checked;
            if (!info.clientId || !info.clientSecret) validated = false;
          } else if (platform === 'gmail') {
            info.clientId = document.getElementById('gmail-client-id').value;
            info.serviceAccount = document.getElementById('gmail-service-account').value;
            info.metaOnly = document.getElementById('gmail-meta-only').checked;
            if (!info.clientId || !info.serviceAccount) validated = false;
          } else if (platform === 'outlook') {
            info.tenantId = document.getElementById('outlook-tenant-id').value;
            info.clientId = document.getElementById('outlook-client-id').value;
            info.clientSecret = document.getElementById('outlook-client-secret').value;
            if (!info.tenantId || !info.clientId || !info.clientSecret) validated = false;
          }

          if (!validated) {
            triggerNotification("Error: Please fill in all required connection fields.", "error");
            return;
          }

          // Save integration config details
          currentConfigs[platform] = info;
          saveIntegrationConfigs(currentConfigs);

          // Update settings global object
          window.rmosSettings.integrations[platform] = true;
          localStorage.setItem('rmos_system_settings', JSON.stringify(window.rmosSettings));

          // Toggle UI state back to view
          setupState.style.display = 'none';
          viewState.style.display = 'block';

          // Update main connect actions
          if (btnConnect) {
            btnConnect.textContent = "Disconnect";
            btnConnect.className = "btn-connection-action btn-disconnect";
          }
          if (btnConfigure) btnConfigure.style.display = 'block';
          if (badge) {
            badge.textContent = "Connected";
            badge.className = "connection-status-badge connected";
          }
          if (statusDiv) statusDiv.style.display = 'none';

          triggerNotification(`${platform.charAt(0).toUpperCase() + platform.slice(1)} connection configuration saved successfully!`);
        });
      }
    });
  };

  initIntegrationsHub();


  // ==========================================================================
  // BRANDING & THEME CUSTOMIZER ENGINE
  // ==========================================================================

  // Hex to RGB Helper
  function hexToRgb(hex) {
    var shorthandRegex = /^#?([a-f\d])([a-f\d])([a-f\d])$/i;
    hex = hex.replace(shorthandRegex, function(m, r, g, b) {
      return r + r + g + g + b + b;
    });
    var result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
    return result ? {
      r: parseInt(result[1], 16),
      g: parseInt(result[2], 16),
      b: parseInt(result[3], 16)
    } : { r: 59, g: 130, b: 246 }; // fallback blue
  }

  // Inject or update theme styles in head
  window.applyDynamicTheme = (config) => {
    let theme = config;
    if (!theme) {
      try {
        const saved = localStorage.getItem('rmos_custom_theme');
        theme = saved ? JSON.parse(saved) : { mode: 'dual', primary: '#3b82f6', secondary: '#a855f7' };
      } catch (e) {
        theme = { mode: 'dual', primary: '#3b82f6', secondary: '#a855f7' };
      }
    }

    const priRgb = hexToRgb(theme.primary);
    const secColor = theme.mode === 'single' ? theme.primary : theme.secondary;
    const secRgb = hexToRgb(secColor);

    // Create or locate style block
    let styleBlock = document.getElementById('rmos-dynamic-theme-style');
    if (!styleBlock) {
      styleBlock = document.createElement('style');
      styleBlock.id = 'rmos-dynamic-theme-style';
      document.head.appendChild(styleBlock);
    }

    styleBlock.innerHTML = `
      :root {
        --theme-primary: ${theme.primary};
        --theme-secondary: ${secColor};
        --theme-primary-rgb: ${priRgb.r}, ${priRgb.g}, ${priRgb.b};
        --theme-secondary-rgb: ${secRgb.r}, ${secRgb.g}, ${secRgb.b};
      }

      /* Sidebar Navigation Highlight overrides */
      .sidebar-nav-item.active {
        background: rgba(var(--theme-primary-rgb), 0.1) !important;
        border: 1px solid rgba(var(--theme-primary-rgb), 0.2) !important;
        color: var(--theme-primary) !important;
        text-shadow: 0 0 10px rgba(var(--theme-primary-rgb), 0.25) !important;
      }
      .sidebar-nav-item.active .nav-icon {
        color: var(--theme-primary) !important;
        opacity: 1 !important;
      }

      /* Settings Navigation Tab overrides */
      .settings-nav-item.active {
        background: linear-gradient(135deg, rgba(var(--theme-secondary-rgb), 0.15) 0%, rgba(var(--theme-primary-rgb), 0.15) 100%) !important;
        border-color: rgba(var(--theme-secondary-rgb), 0.3) !important;
        color: #fff !important;
      }
      .settings-nav-item.active i {
        color: var(--theme-secondary) !important;
        text-shadow: 0 0 8px rgba(var(--theme-secondary-rgb), 0.5) !important;
      }

      /* General Buttons overrides */
      .btn-settings-save,
      .btn-blue-action,
      .btn-connection-action.btn-connect,
      .logo-upload-wrapper .btn-blue-action {
        background: linear-gradient(135deg, var(--theme-secondary) 0%, var(--theme-primary) 100%) !important;
        color: #fff !important;
        border: none !important;
        box-shadow: 0 4px 15px rgba(var(--theme-secondary-rgb), 0.3) !important;
      }
      .btn-settings-save:hover,
      .btn-blue-action:hover,
      .btn-connection-action.btn-connect:hover {
        box-shadow: 0 6px 20px rgba(var(--theme-secondary-rgb), 0.45) !important;
        transform: translateY(-1px) !important;
      }

      /* Panel glow dot indicators */
      .panel-glow-dot-blue,
      .panel-glow-dot {
        background: var(--theme-primary) !important;
        box-shadow: 0 0 10px var(--theme-primary) !important;
      }

      /* Progress Bar fill gauge */
      .seat-progress-bar-fill {
        background: linear-gradient(90deg, var(--theme-primary), var(--theme-secondary)) !important;
        box-shadow: 0 0 8px rgba(var(--theme-secondary-rgb), 0.4) !important;
      }

      /* Background spotlights */
      .dashboard-bg-spotlight {
        background: radial-gradient(circle at 10% 20%, rgba(var(--theme-primary-rgb), 0.08) 0%, transparent 40%),
                    radial-gradient(circle at 90% 80%, rgba(var(--theme-secondary-rgb), 0.06) 0%, transparent 40%) !important;
      }

      /* Checked Custom Toggles */
      .custom-switch input:checked + .slider-switch {
        background-color: rgba(var(--theme-secondary-rgb), 0.2) !important;
        border-color: rgba(var(--theme-secondary-rgb), 0.4) !important;
      }
      .custom-switch input:checked + .slider-switch:before {
        background-color: var(--theme-secondary) !important;
        box-shadow: 0 0 8px var(--theme-secondary) !important;
      }

      /* Active filters, overview tabs and badges */
      .leaderboard-tab.active,
      .role-tab.active,
      .overview-tab.active,
      .sub-tab.active {
        border-bottom-color: var(--theme-primary) !important;
        color: var(--theme-primary) !important;
      }
      .active-workspace-border {
        border-color: var(--theme-primary) !important;
      }
      .seat-user-avatar {
        background: linear-gradient(135deg, var(--theme-secondary) 0%, var(--theme-primary) 100%) !important;
      }
    `;

    // Apply custom logo if stored in localStorage
    const savedLogo = localStorage.getItem('rmos_custom_logo');
    const brandLogoImg = document.querySelector('.sidebar-logo img');
    const themeLogoPreview = document.getElementById('theme-logo-preview');

    if (savedLogo && typeof savedLogo === 'string' && savedLogo.startsWith('data:image/')) {
      if (brandLogoImg) brandLogoImg.src = savedLogo;
      if (themeLogoPreview) themeLogoPreview.src = savedLogo;
    } else {
      if (brandLogoImg) brandLogoImg.src = "./assets/crm-logo.png";
      if (themeLogoPreview) themeLogoPreview.src = "./assets/crm-logo.png";
    }
  };

  // Bind Custom Branding controls
  const initBrandingHub = () => {
    const form = document.getElementById('settings-form-branding');
    if (!form) return;

    const inputMode = document.getElementById('input-theme-mode');
    const inputPrimary = document.getElementById('input-primary-color');
    const inputSecondary = document.getElementById('input-secondary-color');
    const txtPrimary = document.getElementById('txt-primary-color');
    const txtSecondary = document.getElementById('txt-secondary-color');
    const wrapperSecondary = document.getElementById('wrapper-secondary-color');
    const uploader = document.getElementById('input-theme-logo');
    const btnResetLogo = document.getElementById('btn-reset-logo');
    const btnResetTheme = document.getElementById('btn-reset-theme');
    
    // Loaded logo base64 buffer
    let logoDataUrl = localStorage.getItem('rmos_custom_logo');
    if (logoDataUrl && (!logoDataUrl.startsWith('data:image/') || logoDataUrl === 'null' || logoDataUrl === 'undefined')) {
      logoDataUrl = null;
    }

    // Load saved settings values into inputs
    let themeConfig = { mode: 'dual', primary: '#3b82f6', secondary: '#a855f7' };
    try {
      const saved = localStorage.getItem('rmos_custom_theme');
      if (saved) themeConfig = JSON.parse(saved);
    } catch(e) {}

    inputMode.value = themeConfig.mode || 'dual';
    inputPrimary.value = themeConfig.primary || '#3b82f6';
    inputSecondary.value = themeConfig.secondary || '#a855f7';
    txtPrimary.value = (themeConfig.primary || '#3b82f6').toUpperCase();
    txtSecondary.value = (themeConfig.secondary || '#a855f7').toUpperCase();

    // Toggle secondary accent wrapper display depending on mode
    const checkModeDisplay = () => {
      if (inputMode.value === 'single') {
        if (wrapperSecondary) wrapperSecondary.style.opacity = '0.4';
        if (inputSecondary) inputSecondary.disabled = true;
      } else {
        if (wrapperSecondary) wrapperSecondary.style.opacity = '1';
        if (inputSecondary) inputSecondary.disabled = false;
      }
    };
    checkModeDisplay();

    inputMode.addEventListener('change', checkModeDisplay);

    // Sync input text labels on picker changes
    inputPrimary.addEventListener('input', (e) => {
      txtPrimary.value = e.target.value.toUpperCase();
    });
    inputSecondary.addEventListener('input', (e) => {
      txtSecondary.value = e.target.value.toUpperCase();
    });

    // Handle logo file uploads
    uploader.addEventListener('change', (e) => {
      const file = e.target.files[0];
      if (!file) return;

      if (file.size > 2000000) { // Limit size to 2MB to keep it safe for LocalStorage
        triggerNotification("Error: Uploaded image size must not exceed 2MB.", "error");
        uploader.value = '';
        return;
      }

      const reader = new FileReader();
      reader.onload = (event) => {
        logoDataUrl = event.target.result;
        const preview = document.getElementById('theme-logo-preview');
        if (preview) preview.src = logoDataUrl;
        triggerNotification("Logo loaded. Apply changes to save.");
      };
      reader.readAsDataURL(file);
    });

    // Handle form submit to save custom styles
    form.addEventListener('submit', (e) => {
      e.preventDefault();

      const config = {
        mode: inputMode.value,
        primary: inputPrimary.value,
        secondary: inputSecondary.value
      };

      localStorage.setItem('rmos_custom_theme', JSON.stringify(config));
      
      if (logoDataUrl) {
        localStorage.setItem('rmos_custom_logo', logoDataUrl);
      } else {
        localStorage.removeItem('rmos_custom_logo');
      }

      window.applyDynamicTheme(config);
      triggerNotification("Workspace custom theme parameters applied successfully!");
    });

    // Reset Logo Button
    btnResetLogo.addEventListener('click', (e) => {
      e.preventDefault();
      localStorage.removeItem('rmos_custom_logo');
      logoDataUrl = null;
      uploader.value = '';
      
      const preview = document.getElementById('theme-logo-preview');
      if (preview) preview.src = "./assets/crm-logo.png";
      const brandLogoImg = document.querySelector('.sidebar-logo img');
      if (brandLogoImg) brandLogoImg.src = "./assets/crm-logo.png";

      triggerNotification("Logo restored to default WhiteBox branding.");
    });

    // Reset Theme Button
    btnResetTheme.addEventListener('click', (e) => {
      e.preventDefault();
      localStorage.removeItem('rmos_custom_theme');
      
      inputMode.value = 'dual';
      inputPrimary.value = '#3b82f6';
      inputSecondary.value = '#a855f7';
      txtPrimary.value = '#3B82F6';
      txtSecondary.value = '#A855F7';
      checkModeDisplay();

      // Clear dynamic style element
      const styleBlock = document.getElementById('rmos-dynamic-theme-style');
      if (styleBlock) styleBlock.remove();

      triggerNotification("UI theme reverted back to RMOS classic gradients.");
    });
  };

  initBrandingHub();
  // Apply dynamic theme right away at startup
  window.applyDynamicTheme();
// 8. User Provisioning & Seat Registry List Engine



  let activeSeatsList = [



    { name: "Gregory Sterling", email: "g.sterling@whitebox.com", role: "Executive" },



    { name: "Sarah Lansky", email: "s.lansky@whitebox.com", role: "Executive" },



    { name: "Marcus Dupond", email: "m.dupond@whitebox.com", role: "Manager" },



    { name: "Jane Smith", email: "j.smith@whitebox.com", role: "Manager" },



    { name: "Dwight Schrute", email: "d.schrute@whitebox.com", role: "Rep" },



    { name: "Emily Davis", email: "e.davis@whitebox.com", role: "Executive" }



  ];







  // Try to load custom registry from local storage



  const savedSeats = localStorage.getItem('rmos_provisioned_seats');



  if (savedSeats) {



    try {



      activeSeatsList = JSON.parse(savedSeats);



    } catch(err) {}



  }







  const seatsContainer = document.getElementById('active-seats-container');



  const txtSeatCounter = document.getElementById('txt-seat-counter');



  const barSeatFill = document.getElementById('bar-seat-fill');







  function renderSeatsRegistry() {



    if (!seatsContainer) return;



    seatsContainer.innerHTML = '';



    



    // Update counter text & progress bar



    const countUsed = activeSeatsList.length;



    const countMax = 10;



    if (txtSeatCounter) {



      txtSeatCounter.textContent = `${countUsed} of ${countMax} Seats Used`;



    }



    if (barSeatFill) {



      barSeatFill.style.width = `${(countUsed / countMax) * 100}%`;



    }







    activeSeatsList.forEach((user, idx) => {



      const initials = user.name.split(' ').map(n => n[0]).join('').toUpperCase();



      const roleClass = user.role.toLowerCase();







      const row = document.createElement('div');



      row.className = 'seat-registry-row';



      row.innerHTML = `



        <div class="seat-user-info">



          <div class="seat-user-avatar">${initials}</div>



          <div class="seat-user-details">



            <span class="seat-user-name">${user.name}</span>



            <span class="seat-user-email">${user.email}</span>



          </div>



        </div>



        <div class="seat-badge-group">



          <span class="seat-role-tag ${roleClass}">${user.role}</span>



          ${user.name !== "Gregory Sterling" ? `



            <button class="btn-revoke-seat" data-idx="${idx}" title="Revoke Login Token">



              <i class="fas fa-user-slash"></i>



            </button>



          ` : ''}



        </div>



      `;



      seatsContainer.appendChild(row);



    });







    // Bind revoke buttons



    seatsContainer.querySelectorAll('.btn-revoke-seat').forEach(btn => {



      btn.addEventListener('click', (e) => {



        const index = parseInt(btn.getAttribute('data-idx'));



        const user = activeSeatsList[index];



        if (confirm(`Are you sure you want to revoke platform login access for ${user.name}? This will instantly invalidate their corporate credentials.`)) {



          activeSeatsList.splice(index, 1);



          localStorage.setItem('rmos_provisioned_seats', JSON.stringify(activeSeatsList));



          renderSeatsRegistry();



          triggerNotification(`Access revoked for ${user.name}. Allocated seat released.`);



        }



      });



    });



  }







  // Bind Provision New User Submit



  const formProvision = document.getElementById('form-provision-user');



  if (formProvision) {



    formProvision.addEventListener('submit', (e) => {



      e.preventDefault();







      if (activeSeatsList.length >= 10) {



        triggerNotification("Warning: Seat allocation limit reached! Please release an active seat or upgrade to a high-capacity tier.", "error");



        return;



      }







      const inputName = document.getElementById('input-provision-name');



      const inputEmail = document.getElementById('input-provision-email');



      const inputRole = document.getElementById('input-provision-role');



      const inputPass = document.getElementById('input-provision-password');







      if (!inputName || !inputEmail || !inputRole) return;







      const newName = inputName.value.trim();



      const newEmail = inputEmail.value.trim();



      const newRole = inputRole.value;







      // Duplicate check



      if (activeSeatsList.some(user => user.email.toLowerCase() === newEmail.toLowerCase())) {



        triggerNotification(`Error: Corporate email ${newEmail} is already provisioned in another active seat.`, "error");



        return;



      }







      activeSeatsList.push({



        name: newName,



        email: newEmail,



        role: newRole



      });







      // Save registry to local storage



      localStorage.setItem('rmos_provisioned_seats', JSON.stringify(activeSeatsList));



      



      // Re-render



      renderSeatsRegistry();







      // If this newly provisioned user corresponds to an existing employee, we can sync it



      try {



        if (window.employeesData && Array.isArray(window.employeesData)) {



          const initials = newName.split(' ').map(n => n[0]).join('').toUpperCase();



          



          const hasEmployee = window.employeesData.some(emp => emp.name.toLowerCase() === newName.toLowerCase());



          if (!hasEmployee) {



            window.employeesData.push({



              name: newName,



              initials: initials,



              role: newRole === 'Rep' ? 'Senior Sales Representative' : (newRole === 'Manager' ? 'Sales Manager' : 'Executive Director'),



              roleType: newRole === 'Rep' ? 'reps' : (newRole === 'Manager' ? 'managers' : 'executives'),



              manager: "Gregory Sterling",



              prospects: 0,



              customers: 0,



              gifts: 0,



              giftsReceived: 0,



              inactiveDays: 0,



              date: new Date().toLocaleDateString('en-US', { month: 'short', day: '2-digit', year: 'numeric' }),



              health: 100,



              colorClass: newRole === 'Rep' ? 'bg-teal' : (newRole === 'Manager' ? 'bg-purple' : 'bg-blue'),



              sector: "New Territory",



              streetAddress: "1725 Slough Avenue",



              contact: newName,



              city: "Scranton",



              province: "PA",



              postal: "18505",



              phone: "(570) 555-0" + Math.floor(100 + Math.random() * 900),



              email: newEmail,



              aiRecommend: "Onboarded fresh today. Schedule initial team standup.",



              isWorking: true,



              activeTask: "Reviewing Relationship OS Workspace onboarding guides",



              activeSince: "09:00 AM",



              sessionDuration: "00:05:00",



              todayTouches: "0 touches logged"



            });



            if (typeof window.renderEmployeesList === 'function') window.renderEmployeesList();



          }



        }



      } catch (err) {



        console.error("Error syncing new provisioned user to employees list:", err);



      }







      formProvision.reset();



      triggerNotification(`New credentials provisioned successfully! login token active for ${newName} [Active - ${newRole}].`);



    });



  }







  // Initialize



  renderSeatsRegistry();

  // Initialize the dashboard page
  initDashboardPage();



});






window.checkProfileRestriction = function(targetName, targetType) {
  const container = document.getElementById('detail-restricted-container');
  const overlay = document.getElementById('restricted-lock-overlay');
  if (!container || !overlay) return;
  
  let isRestricted = false;
  if (targetType === 'employee') {
    if (window.currentRole === 'rep') {
      isRestricted = true;
    } else if (window.currentRole === 'hr') {
      const activeEmployees = (typeof window.employeesData !== 'undefined' ? window.employeesData : (typeof employeesData !== 'undefined' ? employeesData : []));
      const targetEmp = activeEmployees.find(e => e.name === targetName);
      const username = window.currentUsername || localStorage.getItem('whitebox_username') || 'Sarah Lansky';
      if (targetEmp && targetEmp.roleType === 'executives' && targetEmp.name !== username) {
        isRestricted = true;
      }
    } else if (window.currentRole === 'manager') {
      if (targetName === 'Paul K.') {
        isRestricted = true;
      } else {
        const activeEmployees = (typeof window.employeesData !== 'undefined' ? window.employeesData : (typeof employeesData !== 'undefined' ? employeesData : []));
        const targetEmp = activeEmployees.find(e => e.name === targetName);
        if (targetEmp) {
          const username = window.currentUsername || localStorage.getItem('whitebox_username') || 'Marcus Dupond';
          if (targetEmp.name !== username && (targetEmp.roleType === 'managers' || targetEmp.roleType === 'executives')) {
            isRestricted = true;
          }
        }
      }
    }
  }
  
  if (isRestricted) {
    container.classList.add('restricted-locked');
    overlay.style.display = 'flex';
  } else {
    container.classList.remove('restricted-locked');
    overlay.style.display = 'none';
  }
};

