window.showTeamProfileDetail = function(teamName) {
  // 1. Close any open modals
  const modal = document.getElementById('analytics-preview-modal');
  if (modal) modal.classList.remove('show');

  // Extract manager's name
  let managerName = teamName;
  if (managerName.endsWith("'s Team")) {
    managerName = managerName.substring(0, managerName.length - 7);
  }

  // Compute metrics
  const metrics = window.compileTeamConstellationMetrics(managerName);

  // Update banner fields
  const titleEl = document.getElementById('team-detail-name');
  if (titleEl) titleEl.textContent = teamName;

  const mgrValEl = document.getElementById('team-detail-manager-val');
  if (mgrValEl) mgrValEl.textContent = managerName;

  // Metadata Grid
  const sizeEl = document.getElementById('team-meta-size');
  if (sizeEl) sizeEl.textContent = `${metrics.teamSize + 1} members`;

  const convEl = document.getElementById('team-meta-conversion');
  if (convEl) convEl.textContent = `${metrics.conversionRate}%`;

  const spendEl = document.getElementById('team-meta-spend');
  if (spendEl) spendEl.textContent = '$' + metrics.totalSpend.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  const prospEl = document.getElementById('team-meta-prospects');
  if (prospEl) prospEl.textContent = metrics.totalProspects;

  const custEl = document.getElementById('team-meta-customers');
  if (custEl) custEl.textContent = metrics.totalCustomers;

  // KPI Scorecard Cards
  const kpiHealthEl = document.getElementById('team-kpi-health');
  if (kpiHealthEl) kpiHealthEl.textContent = `${metrics.compiledScore}%`;

  const kpiMgrHealthEl = document.getElementById('team-kpi-mgr-health');
  if (kpiMgrHealthEl) kpiMgrHealthEl.textContent = `${metrics.mgrHealth}%`;

  const kpiCustHealthEl = document.getElementById('team-kpi-cust-health');
  if (kpiCustHealthEl) kpiCustHealthEl.textContent = `${metrics.avgCustHealth}%`;

  const kpiProspHealthEl = document.getElementById('team-kpi-prosp-health');
  if (kpiProspHealthEl) kpiProspHealthEl.textContent = `${metrics.avgProspHealth}%`;

  // Roster Rows
  const rosterTbody = document.getElementById('team-roster-rows');
  if (rosterTbody) {
    const allEmployees = (typeof employeesData !== 'undefined') ? employeesData : [];
    // Get team members
    const teamMembers = allEmployees.filter(e => e.manager && e.manager.trim().toLowerCase() === managerName.trim().toLowerCase() && (e.roleType === 'reps' || e.roleType === 'employee'));
    
    if (teamMembers.length === 0) {
      rosterTbody.innerHTML = `<tr><td colspan="6" style="padding: 15px; text-align: center; color: #64748b;">No members found on this team.</td></tr>`;
    } else {
      rosterTbody.innerHTML = teamMembers.map(m => {
        const initials = m.initials || m.name.split(' ').map(x => x[0]).join('');
        return `
          <tr style="border-bottom: 1px solid rgba(255,255,255,0.03); transition: background 0.2s;">
            <td style="padding: 8px;">
              <div style="display: flex; align-items: center; gap: 8px;">
                <div class="profile-avatar ${m.colorClass || 'bg-blue'}" style="width: 24px; height: 24px; font-size: 9px; line-height: 24px;">${initials}</div>
                <span style="font-weight: 600; color: #fff;">${m.name}</span>
              </div>
            </td>
            <td style="padding: 8px; color: #94a3b8;">${m.role || 'Sales Rep'}</td>
            <td style="padding: 8px; text-align: right; font-weight: 700; color: #10b981;">${m.health}%</td>
            <td style="padding: 8px; text-align: right;">${m.prospects || 0}</td>
            <td style="padding: 8px; text-align: right;">${m.customers || 0}</td>
            <td style="padding: 8px; text-align: center;">
              <button onclick="window.viewEmployeeProfile('${m.name}')" style="background: rgba(59,130,246,0.1); border: 1px solid rgba(59,130,246,0.2); color: #3b82f6; padding: 4px 8px; border-radius: 4px; font-size: 9px; font-family: 'Outfit'; font-weight: 600; cursor: pointer; transition: all 0.2s;">View</button>
            </td>
          </tr>
        `;
      }).join('');
    }
  }

  // Gifting ROI Ledger Chart
  const reachGifts = Math.round(metrics.totalGifts * 0.25);
  const retainGifts = Math.round(metrics.totalGifts * 0.45);
  const rewardGifts = Math.round(metrics.totalGifts * 0.10);
  const rememberGifts = Math.max(0, metrics.totalGifts - (reachGifts + retainGifts + rewardGifts));
  
  const maxVal = Math.max(1, reachGifts, retainGifts, rewardGifts, rememberGifts);

  const barReach = document.getElementById('team-bar-reach');
  if (barReach) barReach.style.height = `${(reachGifts / maxVal) * 85 + 15}px`;

  const barRetain = document.getElementById('team-bar-retain');
  if (barRetain) barRetain.style.height = `${(retainGifts / maxVal) * 85 + 15}px`;

  const barReward = document.getElementById('team-bar-reward');
  if (barReward) barReward.style.height = `${(rewardGifts / maxVal) * 85 + 15}px`;

  const barRemember = document.getElementById('team-bar-remember');
  if (barRemember) barRemember.style.height = `${(rememberGifts / maxVal) * 85 + 15}px`;

  const giftsBoxes = document.getElementById('team-gifting-boxes');
  if (giftsBoxes) giftsBoxes.textContent = `${metrics.totalGifts} Boxes`;

  const spendVal = document.getElementById('team-gifting-spend');
  if (spendVal) spendVal.textContent = '$' + metrics.totalSpend.toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  // Navigation: Show view-team-profile-detail, hide others
  document.body.classList.remove('sidebar-collapsed');
  
  const backBtn = document.getElementById('btn-back-to-workspace');
  if (backBtn) backBtn.style.display = 'inline-flex';

  const wrappers = document.querySelectorAll('.dashboard-canvas .dashboard-view-wrapper');
  wrappers.forEach(wrap => wrap.classList.remove('active'));

  const detailWrapper = document.getElementById('view-team-profile-detail');
  if (detailWrapper) detailWrapper.classList.add('active');
};

