// Global State Variables for Manager Prospects View
window.managerProspectViewMode = 'mine'; // 'mine' or 'team'
window.managerSelectedProspectMember = null; // String name of the selected employee

window.initManagerProspectsControls = function(role) {
  const container = document.getElementById('manager-prospects-controls');
  if (!container) return;

  if (role !== 'manager') {
    container.style.display = 'none';
    return;
  }

  // Show the controls container for Manager
  container.style.display = 'flex';

  // Grab child elements
  const toggleBtnMine = container.querySelector('#manager-prospect-toggle [data-view="mine"]');
  const toggleBtnTeam = container.querySelector('#manager-prospect-toggle [data-view="team"]');
  const searchContainer = document.getElementById('manager-prospect-team-search-container');
  const searchInput = document.getElementById('manager-prospect-team-search-input');
  const suggestionsBox = document.getElementById('manager-prospect-team-search-suggestions');
  const clearBtn = document.getElementById('manager-prospect-team-search-clear');
  const badgeEl = document.getElementById('manager-selected-prospect-member-badge');

  // Setup click handler for toggle My Prospects
  if (toggleBtnMine) {
    toggleBtnMine.onclick = function() {
      toggleBtnMine.classList.add('active');
      if (toggleBtnTeam) toggleBtnTeam.classList.remove('active');
      window.managerProspectViewMode = 'mine';
      if (searchContainer) searchContainer.style.display = 'none';
      if (badgeEl) badgeEl.style.display = 'none';
      // Reset selected team member
      window.managerSelectedProspectMember = null;
      if (searchInput) searchInput.value = '';
      if (clearBtn) clearBtn.style.display = 'none';
      if (typeof renderProspectsList === 'function') renderProspectsList();
    };
  }

  // Setup click handler for toggle Team Prospects
  if (toggleBtnTeam) {
    toggleBtnTeam.onclick = function() {
      toggleBtnTeam.classList.add('active');
      if (toggleBtnMine) toggleBtnMine.classList.remove('active');
      window.managerProspectViewMode = 'team';
      if (searchContainer) searchContainer.style.display = 'block';
      if (window.managerSelectedProspectMember) {
        if (badgeEl) badgeEl.style.display = 'flex';
      } else {
        if (badgeEl) badgeEl.style.display = 'none';
      }
      if (typeof renderProspectsList === 'function') renderProspectsList();
    };
  }

  // Populate dynamic suggestions for search input based on Manager's direct team reports (reps only)
  const mgrName = window.currentUsername || 'Marcus Dupond';
  const allEmployees = typeof employeesData !== 'undefined' ? employeesData : [];
  const teamReps = allEmployees.filter(e => e.manager === mgrName && e.roleType === 'reps');

  if (searchInput) {
    searchInput.oninput = function() {
      const val = searchInput.value.trim().toLowerCase();
      if (!val) {
        if (suggestionsBox) suggestionsBox.style.display = 'none';
        if (clearBtn) clearBtn.style.display = 'none';
        return;
      }
      if (clearBtn) clearBtn.style.display = 'block';

      // Filter matches
      const matches = teamReps.filter(rep => rep.name.toLowerCase().includes(val));
      
      if (suggestionsBox) {
        if (matches.length > 0) {
          suggestionsBox.style.display = 'block';
          suggestionsBox.style.background = '#0f0f1c';
          suggestionsBox.innerHTML = matches.map(rep => {
            return `
              <div class="team-prospect-suggest-item" data-name="${rep.name}" style="padding: 8px 12px; font-size: 11px; color: #fff; cursor: pointer; border-bottom: 1px solid rgba(255,255,255,0.03); transition: background 0.2s ease;">
                <div style="font-weight: 600;">${rep.name}</div>
                <div style="font-size: 9px; color: #94a3b8;">${rep.role}</div>
              </div>
            `;
          }).join('');

          // Bind click handlers to suggestion items
          const items = suggestionsBox.querySelectorAll('.team-prospect-suggest-item');
          items.forEach(item => {
            item.onmouseover = function() { item.style.background = 'rgba(168,85,247,0.15)'; };
            item.onmouseout = function() { item.style.background = 'transparent'; };
            item.onclick = function(e) {
              const name = item.getAttribute('data-name');
              selectTeamMember(name);
            };
          });
        } else {
          suggestionsBox.style.display = 'block';
          suggestionsBox.innerHTML = `<div style="padding: 8px 12px; font-size: 11px; color: #94a3b8; text-align: center;">No matching team member</div>`;
        }
      }
    };
  }

  // Clear button inside search input
  if (clearBtn) {
    clearBtn.onclick = function() {
      if (searchInput) searchInput.value = '';
      clearBtn.style.display = 'none';
      if (suggestionsBox) suggestionsBox.style.display = 'none';
      window.managerSelectedProspectMember = null;
      if (badgeEl) badgeEl.style.display = 'none';
      if (typeof renderProspectsList === 'function') renderProspectsList();
    };
  }

  // Clear button/close icon inside badge
  if (badgeEl) {
    const badgeClose = badgeEl.querySelector('.badge-close');
    if (badgeClose) {
      badgeClose.onclick = function() {
        window.managerSelectedProspectMember = null;
        badgeEl.style.display = 'none';
        if (searchInput) searchInput.value = '';
        if (clearBtn) clearBtn.style.display = 'none';
        if (typeof renderProspectsList === 'function') renderProspectsList();
      };
    }
  }

  function selectTeamMember(name) {
    window.managerSelectedProspectMember = name;
    if (searchInput) searchInput.value = name;
    if (suggestionsBox) suggestionsBox.style.display = 'none';
    if (clearBtn) clearBtn.style.display = 'block';
    
    if (badgeEl) {
      const textEl = badgeEl.querySelector('.badge-text');
      if (textEl) textEl.textContent = name;
      badgeEl.style.display = 'flex';
    }

    if (typeof renderProspectsList === 'function') renderProspectsList();
  }
};

